			windOffsetX %= base.CloudTileSize;
			mainThreadState.WindTileOffsetZ += (int)(windOffsetZ / (double)base.CloudTileSize);
			windOffsetZ %= base.CloudTileSize;
			offThreadState.Set(mainThreadState);
