		private void FindPath(BlockPos startBlockPos, BlockPos targetBlockPos, int searchDepth, int mhdistanceTolerance = 0)
		{
			waypointToReachIndex = 0;
			float stepHeight = entity.GetBehavior<EntityBehaviorControlledPhysics>()?.StepHeight ?? 0.6f;
			int maxFallHeight = (entity.Properties.FallDamage ? (Math.Min(8, (int)Math.Round(3.51 / Math.Max(0.01, entity.Properties.FallDamageMultiplier))) - (int)(movingSpeed * 30f)) : 8);
			newWaypoints = psys.FindPathAsWaypoints(startBlockPos, targetBlockPos, maxFallHeight, stepHeight, entity.CollisionBox, searchDepth, mhdistanceTolerance, creatureType);
		}

		public PathfinderTask PreparePathfinderTask(BlockPos startBlockPos, BlockPos targetBlockPos, int searchDepth = 999, int mhdistanceTolerance = 0, EnumAICreatureType? creatureType = null)
		{
			float stepHeight = entity.GetBehavior<EntityBehaviorControlledPhysics>()?.StepHeight ?? 0.6f;
			int num;
			if (entity.Properties.FallDamage)
			{
				JsonObject attributes = entity.Properties.Attributes;
				if (attributes == null || !attributes["reckless"].AsBool())
				{
					num = 4 - (int)(movingSpeed * 30f);
					goto IL_0071;
				}
			}
			num = 12;
			goto IL_0071;
			IL_0071:
			int maxFallHeight = num;
			return new PathfinderTask(startBlockPos, targetBlockPos, maxFallHeight, stepHeight, entity.CollisionBox, searchDepth, mhdistanceTolerance, creatureType ?? this.creatureType);
		}

		private void FindPath_Async(BlockPos startBlockPos, BlockPos targetBlockPos, int searchDepth, int mhdistanceTolerance = 0)
		{
			waypointToReachIndex = 0;
			asyncSearchObject = PreparePathfinderTask(startBlockPos, targetBlockPos, searchDepth, mhdistanceTolerance, creatureType);
			asyncPathfinder.EnqueuePathfinderTask(asyncSearchObject);
		}

		public bool AfterFoundPath()
		{
			if (asyncSearchObject != null)
			{
				newWaypoints = asyncSearchObject.waypoints;
				asyncSearchObject = null;
			}
			if (newWaypoints == null)
			{
				HandleNoPath();
				return false;
			}
			waypoints = newWaypoints;
			if (PathFindDebug)
			{
				List<BlockPos> list = new List<BlockPos>();
				List<int> list2 = new List<int>();
				int num = 0;
				foreach (Vec3d waypoint in waypoints)
				{
					list.Add(waypoint.AsBlockPos);
					list2.Add(ColorUtil.ColorFromRgba(128, 128, Math.Min(255, 128 + num * 8), 150));
					num++;
				}
				list.Add(desiredTarget.AsBlockPos);
				list2.Add(ColorUtil.ColorFromRgba(128, 0, 255, 255));
				IPlayer player = entity.World.AllOnlinePlayers[0];
				entity.World.HighlightBlocks(player, 2, list, list2);
			}
			waypoints.Add(desiredTarget);
			base.WalkTowards(desiredTarget, movingSpeed_New, targetDistance_New, OnGoalReached_New, OnStuck_New);
			OnFoundPath?.Invoke();
			return true;
		}

		public void HandleNoPath()
		{
			waypoints = new List<Vec3d>();
			if (PathFindDebug)
			{
				List<BlockPos> list = new List<BlockPos>();
				List<int> list2 = new List<int>();
				int num = 0;
				foreach (PathNode item in entity.World.Api.ModLoader.GetModSystem<PathfindSystem>().astar.closedSet)
				{
					list.Add(item);
					list2.Add(ColorUtil.ColorFromRgba(Math.Min(255, num * 4), 0, 0, 150));
					num++;
				}
				IPlayer player = entity.World.AllOnlinePlayers[0];
				entity.World.HighlightBlocks(player, 2, list, list2);
			}
			waypoints.Add(desiredTarget);
			base.WalkTowards(desiredTarget, movingSpeed_New, targetDistance_New, OnGoalReached_New, OnStuck_New);
			if (OnNoPath != null)
			{
				Active = false;
				OnNoPath();
			}
		}

		public override bool WalkTowards(Vec3d target, float movingSpeed, float targetDistance, Action OnGoalReached, Action OnStuck, EnumAICreatureType creatureType = EnumAICreatureType.Default)
		{
			waypoints = new List<Vec3d>();
			waypoints.Add(target);
			return base.WalkTowards(target, movingSpeed, targetDistance, OnGoalReached, OnStuck, creatureType);
		}

		protected override bool BeginGo()
		{
			entity.Controls.Forward = true;
			entity.ServerControls.Forward = true;
			curTurnRadPerSec = minTurnAnglePerSec + (float)entity.World.Rand.NextDouble() * (maxTurnAnglePerSec - minTurnAnglePerSec);
			curTurnRadPerSec *= 0.87266463f;
			stuckCounter = 0;
			waypointToReachIndex = 0;
			lastWaypointIncTotalMs = entity.World.ElapsedMilliseconds;
			distCheckAccum = 0f;
			prevPosAccum = 0f;
			return true;
		}

		public override void OnGameTick(float dt)
		{
			if (asyncSearchObject != null)
			{
				if (!asyncSearchObject.Finished)
				{
					return;
				}
				AfterFoundPath();
			}
			if (!Active)
			{
				return;
			}
			bool nearHorizontally = false;
			int num = 0;
			bool flag = IsNearTarget(num++, ref nearHorizontally) || IsNearTarget(num++, ref nearHorizontally) || IsNearTarget(num++, ref nearHorizontally);
			if (flag)
			{
				waypointToReachIndex += num;
				lastWaypointIncTotalMs = entity.World.ElapsedMilliseconds;
			}
			target = waypoints[Math.Min(waypoints.Count - 1, waypointToReachIndex)];
			_ = waypointToReachIndex;
			_ = waypoints.Count;
			if (waypointToReachIndex >= waypoints.Count)
			{
				Stop();
				OnGoalReached?.Invoke();
				return;
			}
			bool flag2 = nearHorizontally && !flag && entity.Properties.Habitat == EnumHabitat.Land;
			bool flag3 = (entity.CollidedVertically && entity.Controls.IsClimbing) || (entity.CollidedHorizontally && entity.ServerPos.Motion.Y <= 0.0) || flag2 || (entity.CollidedHorizontally && waypoints.Count > 1 && waypointToReachIndex < waypoints.Count && entity.World.ElapsedMilliseconds - lastWaypointIncTotalMs > 2000);
			double num2 = prevPrevPos.SquareDistanceTo(prevPos);
			flag3 |= num2 < 0.0001 && entity.World.Rand.NextDouble() < GameMath.Clamp(1.0 - num2 * 1.2, 0.1, 0.9);
			prevPosAccum += dt;
			if ((double)prevPosAccum > 0.2)
			{
				prevPosAccum = 0f;
				prevPrevPos.Set(prevPos);
				prevPos.Set(entity.ServerPos.X, entity.ServerPos.InternalY, entity.ServerPos.Z);
			}
			distCheckAccum += dt;
			if (distCheckAccum > 2f)
			{
				distCheckAccum = 0f;
				if ((double)Math.Abs(sqDistToTarget - lastDistToTarget) < 0.1)
				{
					flag3 = true;
					stuckCounter += 30;
				}
				else if (!flag3)
				{
					stuckCounter = 0;
				}
				lastDistToTarget = sqDistToTarget;
			}
			if (flag3)
			{
				stuckCounter++;
			}
			if (GlobalConstants.OverallSpeedMultiplier > 0f && (float)stuckCounter > 60f / GlobalConstants.OverallSpeedMultiplier)
			{
				Stop();
				OnStuck?.Invoke();
				return;
			}
			EntityControls entityControls = ((entity.MountedOn == null) ? entity.Controls : entity.MountedOn.Controls);
			if (entityControls == null)
			{
				return;
			}
			targetVec.Set((float)(target.X - entity.ServerPos.X), (float)(target.Y - entity.ServerPos.InternalY), (float)(target.Z - entity.ServerPos.Z));
			targetVec.Normalize();
			float end = 0f;
			if ((double)sqDistToTarget >= 0.01)
			{
				end = (float)Math.Atan2(targetVec.X, targetVec.Z);
			}
			float num3 = movingSpeed;
			if (sqDistToTarget < 1f)
			{
				num3 = Math.Max(0.005f, movingSpeed * Math.Max(sqDistToTarget, 0.2f));
			}
			float num4 = GameMath.AngleRadDistance(entity.ServerPos.Yaw, end);
			float num5 = curTurnRadPerSec * dt * GlobalConstants.OverallSpeedMultiplier * movingSpeed;
			entity.ServerPos.Yaw += GameMath.Clamp(num4, 0f - num5, num5);
			entity.ServerPos.Yaw = entity.ServerPos.Yaw % ((float)Math.PI * 2f);
			double z = Math.Cos(entity.ServerPos.Yaw);
			double x = Math.Sin(entity.ServerPos.Yaw);
			entityControls.WalkVector.Set(x, GameMath.Clamp(targetVec.Y, -1f, 1f), z);
			entityControls.WalkVector.Mul(num3 * GlobalConstants.OverallSpeedMultiplier / Math.Max(1f, Math.Abs(num4) * 3f));
			if (entity.Properties.RotateModelOnClimb && entity.Controls.IsClimbing && entity.ClimbingIntoFace != null && entity.Alive)
			{
				BlockFacing climbingIntoFace = entity.ClimbingIntoFace;
				if (Math.Sign(climbingIntoFace.Normali.X) == Math.Sign(entityControls.WalkVector.X))
				{
					entityControls.WalkVector.X = 0.0;
				}
				if (Math.Sign(climbingIntoFace.Normali.Y) == Math.Sign(entityControls.WalkVector.Y))
				{
					entityControls.WalkVector.Y = 0.0 - entityControls.WalkVector.Y;
				}
				if (Math.Sign(climbingIntoFace.Normali.Z) == Math.Sign(entityControls.WalkVector.Z))
				{
					entityControls.WalkVector.Z = 0.0;
				}
			}
			if (entity.Properties.Habitat == EnumHabitat.Underwater)
			{
				entityControls.FlyVector.Set(entityControls.WalkVector);
				Vec3d xYZ = entity.Pos.XYZ;
				Block blockRaw = entity.World.BlockAccessor.GetBlockRaw((int)xYZ.X, (int)xYZ.Y, (int)xYZ.Z, 2);
				Block blockRaw2 = entity.World.BlockAccessor.GetBlockRaw((int)xYZ.X, (int)(xYZ.Y + 1.0), (int)xYZ.Z, 2);
				float num6 = GameMath.Clamp((float)(int)xYZ.Y + (float)blockRaw.LiquidLevel / 8f + (blockRaw2.IsLiquid() ? 1.125f : 0f) - (float)xYZ.Y - (float)entity.SwimmingOffsetY, 0f, 1f);
				num6 = 1f - Math.Min(1f, num6 + 0.5f);
				if (num6 > 0f)
				{
					entityControls.FlyVector.Y = GameMath.Clamp(entityControls.FlyVector.Y, -0.03999999910593033, -0.019999999552965164) * (double)(1f - num6);
					return;
				}
				float num7 = movingSpeed * GlobalConstants.OverallSpeedMultiplier / (float)Math.Sqrt(targetVec.X * targetVec.X + targetVec.Z * targetVec.Z);
				entityControls.FlyVector.Y = targetVec.Y * num7;
			}
			else if (entity.Swimming)
			{
				entityControls.FlyVector.Set(entityControls.WalkVector);
				Vec3d xYZ2 = entity.Pos.XYZ;
				Block blockRaw3 = entity.World.BlockAccessor.GetBlockRaw((int)xYZ2.X, (int)xYZ2.Y, (int)xYZ2.Z, 2);
				Block blockRaw4 = entity.World.BlockAccessor.GetBlockRaw((int)xYZ2.X, (int)(xYZ2.Y + 1.0), (int)xYZ2.Z, 2);
				float num8 = GameMath.Clamp((float)(int)xYZ2.Y + (float)blockRaw3.LiquidLevel / 8f + (blockRaw4.IsLiquid() ? 1.125f : 0f) - (float)xYZ2.Y - (float)entity.SwimmingOffsetY, 0f, 1f);
				num8 = Math.Min(1f, num8 + 0.5f);
				entityControls.FlyVector.Y = GameMath.Clamp(entityControls.FlyVector.Y, 0.019999999552965164, 0.03999999910593033) * (double)num8;
				if (entity.CollidedHorizontally)
				{
					entityControls.FlyVector.Y = 0.05000000074505806;
				}
			}
		}

		private bool IsNearTarget(int waypointOffset, ref bool nearHorizontally)
		{
			if (waypoints.Count - 1 < waypointToReachIndex + waypointOffset)
			{
				return false;
			}
			int index = Math.Min(waypoints.Count - 1, waypointToReachIndex + waypointOffset);
			Vec3d vec3d = waypoints[index];
			double internalY = entity.ServerPos.InternalY;
			sqDistToTarget = vec3d.HorizontalSquareDistanceTo(entity.ServerPos.X, entity.ServerPos.Z);
			double num = (vec3d.Y - internalY) * (vec3d.Y - internalY);
			bool flag = internalY > vec3d.Y;
			sqDistToTarget += (float)Math.Max(0.0, num - (flag ? 1.0 : 0.5));
			if (!nearHorizontally)
			{
				double num2 = vec3d.HorizontalSquareDistanceTo(entity.ServerPos.X, entity.ServerPos.Z);
				nearHorizontally = num2 < (double)(TargetDistance * TargetDistance);
			}
			return sqDistToTarget < TargetDistance * TargetDistance;
		}

		public override void Stop()
		{
			Active = false;
			entity.Controls.Forward = false;
			entity.ServerControls.Forward = false;
			entity.Controls.WalkVector.Set(0.0, 0.0, 0.0);
			stuckCounter = 0;
			distCheckAccum = 0f;
			prevPosAccum = 0f;
			asyncSearchObject = null;
		}

		public override void Retarget()
		{
			Active = true;
			distCheckAccum = 0f;
			prevPosAccum = 0f;
			waypointToReachIndex = waypoints.Count - 1;
		}
	}
	public class PathFindDebug : ModSystem
	{
		private BlockPos start;

		private BlockPos end;

		private ICoreServerAPI sapi;

		private EnumAICreatureType ct;

		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Server;
		}

		public override void StartServerSide(ICoreServerAPI api)
		{
			base.StartServerSide(api);
			sapi = api;
			api.ChatCommands.GetOrCreate("debug").BeginSub("astar").WithDesc("A* path finding debug testing tool")
				.RequiresPrivilege(Privilege.controlserver)
				.RequiresPlayer()
				.WithArgs(api.ChatCommands.Parsers.WordRange("command", "start", "end", "bench", "clear", "ct"), api.ChatCommands.Parsers.OptionalWord("creature type"))
				.HandleWith(onAstarCmd)
				.EndSub();
		}

		private TextCommandResult onAstarCmd(TextCommandCallingArgs args)
		{
			string text = (string)args[0];
			IPlayer player = args.Caller.Player;
			BlockPos asBlockPos = player.Entity.ServerPos.XYZ.AsBlockPos;
			PathfindSystem modSystem = sapi.ModLoader.GetModSystem<PathfindSystem>();
			Cuboidf cuboidf = new Cuboidf(-0.4f, 0f, -0.4f, 0.4f, 1.5f, 0.4f);
			new Cuboidf(-0.2f, 0f, -0.2f, 0.2f, 1.5f, 0.2f);
			new Cuboidf(-0.6f, 0f, -0.6f, 0.6f, 1.5f, 0.6f);
			Cuboidf entityCollBox = cuboidf;
			int maxFallHeight = 3;
			float stepHeight = 1.01f;
			switch (text)
			{
			case "ct":
			{
				string text2 = (string)args[1];
				if (text2 == null)
				{
					return TextCommandResult.Success($"Current creature type is {text2}");
				}
				if (Enum.TryParse<EnumAICreatureType>(text2, out var result))
				{
					ct = result;
					return TextCommandResult.Success($"Creature type set to {text2}");
				}
				return TextCommandResult.Error($"Not a vaild enum type");
			}
			case "start":
				start = asBlockPos.Copy();
				sapi.World.HighlightBlocks(player, 26, new List<BlockPos> { start }, new List<int> { ColorUtil.ColorFromRgba(255, 255, 0, 128) });
				break;
			case "end":
				end = asBlockPos.Copy();
				sapi.World.HighlightBlocks(player, 27, new List<BlockPos> { end }, new List<int> { ColorUtil.ColorFromRgba(255, 0, 255, 128) });
				break;
			case "bench":
			{
				if (start == null || end == null)
				{
					return TextCommandResult.Error("Start/End not set");
				}
				Stopwatch stopwatch = new Stopwatch();
				stopwatch.Start();
				for (int i = 0; i < 15; i++)
				{
					modSystem.FindPath(start, end, maxFallHeight, stepHeight, entityCollBox);
				}
				stopwatch.Stop();
				float num = (float)stopwatch.ElapsedMilliseconds / 15f;
				return TextCommandResult.Success($"15 searches average: {(int)num} ms");
			}
			case "clear":
				start = null;
				end = null;
				sapi.World.HighlightBlocks(player, 2, new List<BlockPos>());
				sapi.World.HighlightBlocks(player, 26, new List<BlockPos>());
				sapi.World.HighlightBlocks(player, 27, new List<BlockPos>());
				break;
			}
			if (start == null || end == null)
			{
				sapi.World.HighlightBlocks(player, 2, new List<BlockPos>());
			}
			if (start != null && end != null)
			{
				Stopwatch stopwatch2 = new Stopwatch();
				stopwatch2.Start();
				List<PathNode> list = modSystem.FindPath(start, end, maxFallHeight, stepHeight, entityCollBox, ct);
				stopwatch2.Stop();
				int num2 = (int)stopwatch2.ElapsedMilliseconds;
				string text3 = $"Search took {num2} ms, {modSystem.astar.NodesChecked} nodes checked";
				if (list == null)
				{
					sapi.World.HighlightBlocks(player, 2, new List<BlockPos>());
					sapi.World.HighlightBlocks(player, 3, new List<BlockPos>());
					return TextCommandResult.Success(text3 + "\nNo path found");
				}
				List<BlockPos> list2 = new List<BlockPos>();
				foreach (PathNode item in list)
				{
					list2.Add(item);
				}
				sapi.World.HighlightBlocks(player, 2, list2, new List<int> { ColorUtil.ColorFromRgba(128, 128, 128, 30) });
				List<Vec3d> list3 = modSystem.ToWaypoints(list);
				list2 = new List<BlockPos>();
				foreach (Vec3d item2 in list3)
				{
					list2.Add(item2.AsBlockPos);
				}
				sapi.World.HighlightBlocks(player, 3, list2, new List<int> { ColorUtil.ColorFromRgba(128, 0, 0, 100) });
				return TextCommandResult.Success(text3);
			}
			return TextCommandResult.Success();
		}
	}
	public class PathfindingAsync : ModSystem, IAsyncServerSystem
	{
		protected ICoreServerAPI api;

		protected AStar astar_offthread;

		protected AStar astar_mainthread;

		protected bool isShuttingDown;

		public ConcurrentQueue<PathfinderTask> PathfinderTasks = new ConcurrentQueue<PathfinderTask>();

		protected readonly Stopwatch totalTime = new Stopwatch();

		protected long lastTickTimeMs;

		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Server;
		}

		public override void StartServerSide(ICoreServerAPI api)
		{
			base.StartServerSide(api);
			this.api = api;
			astar_offthread = new AStar(api);
			astar_mainthread = new AStar(api);
			api.Event.ServerRunPhase(EnumServerRunPhase.Shutdown, delegate
			{
				isShuttingDown = true;
			});
			api.Event.RegisterGameTickListener(OnMainThreadTick, 20);
			api.Server.AddServerThread("ai-pathfinding", this);
		}

		public int OffThreadInterval()
		{
			return 5;
		}

		protected void OnMainThreadTick(float dt)
		{
			int count = PathfinderTasks.Count;
			if (count <= 1)
			{
				return;
			}
			api.World.FrameProfiler.Enter("ai-pathfinding-overflow " + count);
			int num = 1000;
			PathfinderTask pathfinderTask;
			while ((pathfinderTask = Next()) != null && num-- > 0)
			{
				pathfinderTask.waypoints = astar_mainthread.FindPathAsWaypoints(pathfinderTask.startBlockPos, pathfinderTask.targetBlockPos, pathfinderTask.maxFallHeight, pathfinderTask.stepHeight, pathfinderTask.collisionBox, pathfinderTask.searchDepth, pathfinderTask.mhdistanceTolerance);
				pathfinderTask.Finished = true;
				if (isShuttingDown)
				{
					break;
				}
				if (api.World.FrameProfiler.Enabled)
				{
					api.World.FrameProfiler.Mark("path d:" + pathfinderTask.searchDepth + " r:" + ((pathfinderTask.waypoints == null) ? "fail" : pathfinderTask.waypoints.Count.ToString()) + " s:" + pathfinderTask.startBlockPos?.ToString() + " e:" + pathfinderTask.targetBlockPos?.ToString() + " w:" + pathfinderTask.collisionBox.Width);
				}
			}
			api.World.FrameProfiler.Leave();
		}

		public void OnSeparateThreadTick()
		{
			ProcessQueue(astar_offthread, 100);
		}

		public void ProcessQueue(AStar astar, int maxCount)
		{
			PathfinderTask pathfinderTask;
			while ((pathfinderTask = Next()) != null && maxCount-- > 0)
			{
				try
				{
					pathfinderTask.waypoints = astar.FindPathAsWaypoints(pathfinderTask.startBlockPos, pathfinderTask.targetBlockPos, pathfinderTask.maxFallHeight, pathfinderTask.stepHeight, pathfinderTask.collisionBox, pathfinderTask.searchDepth, pathfinderTask.mhdistanceTolerance, pathfinderTask.CreatureType);
				}
				catch (Exception ex)
				{
					pathfinderTask.waypoints = null;
					api.World.Logger.Error("Exception thrown during pathfinding. Will ignore. Exception: {0}", ex.ToString());
				}
				pathfinderTask.Finished = true;
				if (isShuttingDown)
				{
					break;
				}
			}
		}

		protected PathfinderTask Next()
		{
			if (!PathfinderTasks.TryDequeue(out var result))
			{
				return null;
			}
			return result;
		}

		public void EnqueuePathfinderTask(PathfinderTask task)
		{
			PathfinderTasks.Enqueue(task);
		}

		public override void Dispose()
		{
			astar_mainthread?.Dispose();
			astar_mainthread = null;
		}

		public void ThreadDispose()
		{
			astar_offthread.Dispose();
			astar_offthread = null;
		}
	}
	public class StraightLineTraverser : PathTraverserBase
	{
		private float minTurnAnglePerSec;

		private float maxTurnAnglePerSec;

		private Vec3f targetVec = new Vec3f();

		private Vec3d prevPos = new Vec3d();

		public StraightLineTraverser(EntityAgent entity)
			: base(entity)
		{
			if (entity?.Properties.Server?.Attributes?.GetTreeAttribute("pathfinder") != null)
			{
				minTurnAnglePerSec = (float)entity.Properties.Server.Attributes.GetTreeAttribute("pathfinder").GetDecimal("minTurnAnglePerSec", 250.0);
				maxTurnAnglePerSec = (float)entity.Properties.Server.Attributes.GetTreeAttribute("pathfinder").GetDecimal("maxTurnAnglePerSec", 450.0);
			}
			else
			{
				minTurnAnglePerSec = 250f;
				maxTurnAnglePerSec = 450f;
			}
		}

		protected override bool BeginGo()
		{
			entity.Controls.Forward = true;
			entity.ServerControls.Forward = true;
			curTurnRadPerSec = minTurnAnglePerSec + (float)entity.World.Rand.NextDouble() * (maxTurnAnglePerSec - minTurnAnglePerSec);
			curTurnRadPerSec *= 0.87266463f;
			stuckCounter = 0;
			return true;
		}

		public override void OnGameTick(float dt)
		{
			if (!Active)
			{
				return;
			}
			double num = ((entity.Properties.Habitat == EnumHabitat.Land) ? target.SquareDistanceTo(entity.ServerPos.X, target.Y, entity.ServerPos.Z) : target.SquareDistanceTo(entity.ServerPos.X, entity.ServerPos.InternalY, entity.ServerPos.Z));
			if (num < (double)(TargetDistance * TargetDistance))
			{
				Stop();
				OnGoalReached?.Invoke();
				return;
			}
			bool flag = (entity.CollidedVertically && entity.Controls.IsClimbing) || entity.ServerPos.SquareDistanceTo(prevPos) < 2.5E-05 || (entity.CollidedHorizontally && entity.ServerPos.Motion.Y <= 0.0);
			prevPos.Set(entity.ServerPos.X, entity.ServerPos.InternalY, entity.ServerPos.Z);
			stuckCounter = (flag ? (stuckCounter + 1) : 0);
			if (GlobalConstants.OverallSpeedMultiplier > 0f && (float)stuckCounter > 20f / GlobalConstants.OverallSpeedMultiplier)
			{
				Stop();
				OnStuck?.Invoke();
				return;
			}
			EntityControls entityControls = ((entity.MountedOn == null) ? entity.Controls : entity.MountedOn.Controls);
			if (entityControls != null)
			{
				targetVec.Set((float)(target.X - entity.ServerPos.X), (float)(target.Y - entity.ServerPos.InternalY), (float)(target.Z - entity.ServerPos.Z));
				float desiredYaw = 0f;
				if (num >= 0.01)
				{
					desiredYaw = (float)Math.Atan2(targetVec.X, targetVec.Z);
				}
				float nowMoveSpeed = movingSpeed;
				if (num < 1.0)
				{
					nowMoveSpeed = Math.Max(0.005f, movingSpeed * Math.Max((float)num, 0.2f));
				}
				yawToMotion(dt, entityControls, desiredYaw, nowMoveSpeed);
			}
		}

		private void yawToMotion(float dt, EntityControls controls, float desiredYaw, float nowMoveSpeed)
		{
			float num = GameMath.AngleRadDistance(entity.ServerPos.Yaw, desiredYaw);
			float num2 = curTurnRadPerSec * dt * GlobalConstants.OverallSpeedMultiplier * movingSpeed;
			entity.ServerPos.Yaw += GameMath.Clamp(num, 0f - num2, num2);
			entity.ServerPos.Yaw = entity.ServerPos.Yaw % ((float)Math.PI * 2f);
			double z = Math.Cos(entity.ServerPos.Yaw);
			double x = Math.Sin(entity.ServerPos.Yaw);
			controls.WalkVector.Set(x, GameMath.Clamp(targetVec.Y, -1f, 1f), z);
			controls.WalkVector.Mul(nowMoveSpeed * GlobalConstants.OverallSpeedMultiplier / Math.Max(1f, num * 3f));
			if (entity.Properties.RotateModelOnClimb && entity.Controls.IsClimbing && entity.ClimbingOnFace != null && entity.Alive)
			{
				BlockFacing climbingOnFace = entity.ClimbingOnFace;
				if (Math.Sign(climbingOnFace.Normali.X) == Math.Sign(controls.WalkVector.X))
				{
					controls.WalkVector.X = 0.0;
				}
				if (Math.Sign(climbingOnFace.Normali.Z) == Math.Sign(controls.WalkVector.Z))
				{
					controls.WalkVector.Z = 0.0;
				}
			}
			if (entity.Swimming)
			{
				controls.FlyVector.Set(controls.WalkVector);
				Vec3d xYZ = entity.Pos.XYZ;
				Block blockRaw = entity.World.BlockAccessor.GetBlockRaw((int)xYZ.X, (int)xYZ.Y, (int)xYZ.Z, 2);
				Block blockRaw2 = entity.World.BlockAccessor.GetBlockRaw((int)xYZ.X, (int)(xYZ.Y + 1.0), (int)xYZ.Z, 2);
				float num3 = GameMath.Clamp((float)(int)xYZ.Y + (float)blockRaw.LiquidLevel / 8f + (blockRaw2.IsLiquid() ? 1.125f : 0f) - (float)xYZ.Y - (float)entity.SwimmingOffsetY, 0f, 1f);
				num3 = Math.Min(1f, num3 + 0.075f);
				controls.FlyVector.Y = GameMath.Clamp(controls.FlyVector.Y, 0.0020000000949949026, 0.004000000189989805) * (double)num3;
				if (entity.CollidedHorizontally)
				{
					controls.FlyVector.Y = 0.05000000074505806;
				}
			}
		}

		public override void Stop()
		{
			Active = false;
			entity.Controls.Forward = false;
			entity.ServerControls.Forward = false;
			entity.Controls.WalkVector.Set(0.0, 0.0, 0.0);
			stuckCounter = 0;
		}
	}
}
namespace Vintagestory.API.Common
{
	public enum EnumGoalTrigger
	{
		Never,
		Always,
		OnHurt
	}
	public abstract class AiGoalBase
	{
		public Random rand;

		public EntityAgent entity;

		public IWorldAccessor world;

		protected float priority;

		protected float priorityForCancel;

		protected int mincooldown;

		protected int maxcooldown;

		protected double mincooldownHours;

		protected double maxcooldownHours;

		protected long cooldownUntilMs;

		protected double cooldownUntilTotalHours;

		protected PathTraverserBase pathTraverser;

		private Queue<AiActionBase> activeActions = new Queue<AiActionBase>();

		public virtual float Priority => priority;

		public virtual float PriorityForCancel => priorityForCancel;

		public AiGoalBase(EntityAgent entity)
		{
			this.entity = entity;
			world = entity.World;
			rand = new Random((int)entity.EntityId);
			pathTraverser = entity.GetBehavior<EntityBehaviorGoalAI>().PathTraverser;
		}

		public virtual void LoadConfig(JsonObject taskConfig, JsonObject aiConfig)
		{
			priority = taskConfig["priority"].AsFloat();
			priorityForCancel = taskConfig["priorityForCancel"].AsFloat(priority);
			mincooldown = (taskConfig["mincooldown"]?.AsInt()).Value;
			maxcooldown = (taskConfig["maxcooldown"]?.AsInt(100)).Value;
			mincooldownHours = (taskConfig["mincooldownHours"]?.AsDouble()).Value;
			maxcooldownHours = (taskConfig["maxcooldownHours"]?.AsDouble()).Value;
			int value = (taskConfig["initialMinCoolDown"]?.AsInt(mincooldown)).Value;
			int value2 = (taskConfig["initialMaxCoolDown"]?.AsInt(maxcooldown)).Value;
			cooldownUntilMs = entity.World.ElapsedMilliseconds + value + entity.World.Rand.Next(value2 - value);
		}

		public virtual bool ShouldExecuteAll()
		{
			if (cooldownUntilMs > entity.World.ElapsedMilliseconds)
			{
				return false;
			}
			if (cooldownUntilTotalHours > entity.World.Calendar.TotalHours)
			{
				return false;
			}
			return ShouldExecute();
		}

		protected abstract bool ShouldExecute();

		public virtual void StartExecuteAll()
		{
			StartExecute();
		}

		protected virtual void StartExecute()
		{
		}

		public virtual bool ContinueExecuteAll(float dt)
		{
			return ContinueExecute(dt);
		}

		protected abstract bool ContinueExecute(float dt);

		public virtual void FinishExecuteAll(bool cancelled)
		{
			cooldownUntilMs = entity.World.ElapsedMilliseconds + mincooldown + entity.World.Rand.Next(maxcooldown - mincooldown);
			cooldownUntilTotalHours = entity.World.Calendar.TotalHours + mincooldownHours + entity.World.Rand.NextDouble() * (maxcooldownHours - mincooldownHours);
			FinishExecute(cancelled);
		}

		protected virtual void FinishExecute(bool cancelled)
		{
		}

		public virtual void OnStateChanged(EnumEntityState beforeState)
		{
			if (entity.State == EnumEntityState.Active)
			{
				cooldownUntilMs = entity.World.ElapsedMilliseconds + mincooldown + entity.World.Rand.Next(maxcooldown - mincooldown);
			}
		}

		public virtual bool Notify(string key, object data)
		{
			return false;
		}
	}
