	public class ModCompatiblityUtil : ModSystem
	{
		public static AssetCategory compatibility;

		public static string[] partiallyWorkingCategories = new string[2] { "shapes", "textures" };

		public static List<string> LoadedModIds { get; private set; } = new List<string>();

		public override double ExecuteOrder()
		{
			return 0.04;
		}

		public override void StartPre(ICoreAPI api)
		{
			compatibility = new AssetCategory("compatibility", AffectsGameplay: true, EnumAppSide.Universal);
		}

		public override void AssetsLoaded(ICoreAPI api)
		{
			LoadedModIds = api.ModLoader.Mods.Select((Mod m) => m.Info.ModID).ToList();
			RemapFromCompatbilityFolder(api);
		}

		private void RemapFromCompatbilityFolder(ICoreAPI api)
		{
			int num = 0;
			int num2 = 0;
			foreach (Mod mod in api.ModLoader.Mods)
			{
				string text = "compatibility/" + mod.Info.ModID + "/";
				foreach (IAsset item in api.Assets.GetManyInCategory("compatibility", mod.Info.ModID + "/"))
				{
					AssetLocation assetLocation = new AssetLocation(mod.Info.ModID, item.Location.Path.Remove(0, text.Length));
					if (api.Assets.AllAssets.ContainsKey(assetLocation))
					{
						num2++;
					}
					else
					{
						num++;
					}
					if ((assetLocation.Category.SideType & api.Side) != 0)
					{
						api.Assets.Add(assetLocation, item);
					}
				}
			}
			api.World.Logger.Notification("Compatibility lib: {0} assets added, {1} assets replaced.", num, num2);
		}
	}
	public class JsonExport : ModSystem
	{
		private ICoreServerAPI api;

		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Server;
		}

		public override void StartServerSide(ICoreServerAPI api)
		{
			base.StartServerSide(api);
			api.ChatCommands.GetOrCreate("dev").BeginSubCommand("jsonexport").WithDescription("Export items and blocks as json files")
				.RequiresPrivilege(Privilege.controlserver)
				.HandleWith(CmdExport)
				.EndSubCommand();
			this.api = api;
		}

		private TextCommandResult CmdExport(TextCommandCallingArgs textCommandCallingArgs)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("[");
			int num = 0;
			for (int i = 0; i < api.World.Blocks.Count; i++)
			{
				Block block = api.World.Blocks[i];
				if (block != null && !(block.Code == null))
				{
					if (num > 0)
					{
						stringBuilder.Append(",");
					}
					stringBuilder.Append("{");
					stringBuilder.Append($"\"name\": \"{new ItemStack(block).GetName()}\", ");
					stringBuilder.Append($"\"code\": \"{block.Code}\", ");
					stringBuilder.Append($"\"material\": \"{block.BlockMaterial}\", ");
					stringBuilder.Append($"\"shape\": \"{block.Shape.Base.Path}\", ");
					stringBuilder.Append($"\"tool\": \"{block.Tool}\"");
					stringBuilder.Append("}");
					num++;
				}
			}
			stringBuilder.Append("]");
			File.WriteAllText("blocks.json", stringBuilder.ToString());
			stringBuilder = new StringBuilder();
			stringBuilder.Append("[");
			num = 0;
			for (int j = 0; j < api.World.Items.Count; j++)
			{
				Item item = api.World.Items[j];
				if (item != null && !(item.Code == null))
				{
					if (num > 0)
					{
						stringBuilder.Append(",");
					}
					stringBuilder.Append("{");
					stringBuilder.Append($"\"name\": \"{new ItemStack(item).GetName()}\", ");
					stringBuilder.Append($"\"code\": \"{item.Code}\", ");
					stringBuilder.Append($"\"shape\": \"{item.Shape?.Base?.Path}\", ");
					stringBuilder.Append($"\"tool\": \"{item.Tool}\"");
					stringBuilder.Append("}");
					num++;
				}
			}
			stringBuilder.Append("]");
			File.WriteAllText("items.json", stringBuilder.ToString());
			return TextCommandResult.Success("All Blocks and Items written to block.json and item.json in " + AppDomain.CurrentDomain.BaseDirectory);
		}
	}
