	public class AttachedContainerWorkspace
	{
		public enum EntityClientPacketId
		{
			OpenAttachedInventory = 1001
		}

		private const int mouseBuildRepeatDelayMs = 250;

		public Entity entity;

		protected BagInventory bagInv;

		protected GuiDialogCreatureContents dlg;

		protected InventoryGeneric wrapperInv;

		protected Action onRequireSave;

		private long lastMouseActionTime;

		public BagInventory BagInventory => bagInv;

		public InventoryGeneric WrapperInv => wrapperInv;

		public AttachedContainerWorkspace(Entity entity, Action onRequireSave)
		{
			this.entity = entity;
			this.onRequireSave = onRequireSave;
			bagInv = new BagInventory(entity.Api, null);
		}

		public void OnInteract(ItemSlot bagSlot, int slotIndex, Entity onEntity, EntityAgent byEntity, Vec3d hitPosition)
		{
			if (!TryLoadInv(bagSlot, slotIndex, onEntity))
			{
				return;
			}
			EntityPlayer entityPlayer = byEntity as EntityPlayer;
			IPlayer player = onEntity.World.PlayerByUid(entityPlayer.PlayerUID);
			bool flag = false;
			if (onEntity.World.Side == EnumAppSide.Client)
			{
				long tickCount = Environment.TickCount64;
				if (tickCount - lastMouseActionTime < 250)
				{
					return;
				}
				lastMouseActionTime = tickCount;
				if (player.InventoryManager.OpenedInventories.FirstOrDefault((IInventory inv) => inv.InventoryID == wrapperInv.InventoryID) != null)
				{
					Close(player);
					return;
				}
				player.InventoryManager.OpenInventory(wrapperInv);
				dlg = new GuiDialogCreatureContents(wrapperInv, onEntity, onEntity.Api as ICoreClientAPI, "attachedcontainer-" + slotIndex, bagSlot.GetStackName(), new DlgPositioner(entity, slotIndex));
				dlg.packetIdOffset = slotIndex << 11;
				if (dlg.TryOpen())
				{
					ICoreClientAPI obj = onEntity.World.Api as ICoreClientAPI;
					wrapperInv.Open(player);
					obj.Network.SendEntityPacket(onEntity.EntityId, 1001 + dlg.packetIdOffset);
					flag = true;
				}
				dlg.OnClosed += delegate
				{
					Close(player);
				};
			}
			else
			{
				player.InventoryManager?.OpenInventory(wrapperInv);
				flag = true;
			}
			if (flag)
			{
				entity.World.Logger.Audit("{0} opened held bag inventory ({3}) on entity {1}/{2}", player?.PlayerName, entity.EntityId, entity.GetName(), wrapperInv.InventoryID);
			}
		}

		public void Close(IPlayer player)
		{
			if (dlg != null && dlg.IsOpened())
			{
				dlg?.TryClose();
			}
			dlg?.Dispose();
			dlg = null;
			if (player != null && wrapperInv != null)
			{
				player.InventoryManager.CloseInventoryAndSync(wrapperInv);
				entity.World.Logger.Audit("{0} closed held bag inventory {3} on entity {1}/{2}", player?.PlayerName, entity.EntityId, entity.GetName(), wrapperInv.InventoryID);
			}
		}

		public bool TryLoadInv(ItemSlot bagSlot, int slotIndex, Entity entity)
		{
			if (bagSlot.Empty)
			{
				return false;
			}
			IHeldBag collectibleInterface = bagSlot.Itemstack.Collectible.GetCollectibleInterface<IHeldBag>();
			if (collectibleInterface == null || collectibleInterface.GetQuantitySlots(bagSlot.Itemstack) <= 0)
			{
				return false;
			}
			List<ItemSlot> list = new List<ItemSlot> { bagSlot };
			if (wrapperInv != null)
			{
				bagInv.ReloadBagInventory(wrapperInv, list.ToArray());
				return true;
			}
			wrapperInv = new InventoryGeneric(entity.Api);
			bagInv.ReloadBagInventory(wrapperInv, list.ToArray());
			wrapperInv.Init(bagInv.Count, "mountedbaginv", slotIndex + "-" + entity.EntityId, onNewSlot);
			if (entity.World.Side == EnumAppSide.Server)
			{
				wrapperInv.SlotModified += Inv_SlotModified;
			}
			return true;
		}

		private ItemSlot onNewSlot(int slotId, InventoryGeneric self)
		{
			return bagInv[slotId];
		}

		private void Inv_SlotModified(int slotid)
		{
			ItemSlot itemSlot = wrapperInv[slotid];
			bagInv.SaveSlotIntoBag((ItemSlotBagContent)itemSlot);
			onRequireSave?.Invoke();
		}

		public void OnReceivedClientPacket(IServerPlayer player, int packetid, byte[] data, ItemSlot bagSlot, int slotIndex, ref EnumHandling handled)
		{
			if (packetid < 1000)
			{
				if (wrapperInv != null && wrapperInv.HasOpened(player))
				{
					wrapperInv.InvNetworkUtil.HandleClientPacket(player, packetid, data);
					handled = EnumHandling.PreventSubsequent;
				}
			}
			else if (packetid == 1001)
			{
				OnInteract(bagSlot, slotIndex, entity, player.Entity, null);
			}
		}

		public void OnDespawn(EntityDespawnData despawn)
		{
			dlg?.TryClose();
			if (wrapperInv == null)
			{
				return;
			}
			foreach (string openedByPlayerGUId in wrapperInv.openedByPlayerGUIds)
			{
				IPlayer player = entity.Api.World.PlayerByUid(openedByPlayerGUId);
				player?.InventoryManager.CloseInventoryAndSync(wrapperInv);
				if (player != null)
				{
					entity.World.Logger.Audit("{0} closed held bag inventory {3} on entity {1}/{2}", player?.PlayerName, entity.EntityId, entity.GetName(), wrapperInv.InventoryID);
				}
			}
		}
	}
	public class EntityBlockFallingRenderer : EntityRenderer, ITerrainMeshPool
	{
		protected EntityBlockFalling blockFallingEntity;

		protected MultiTextureMeshRef meshRef;

		protected Block block;

		protected Matrixf ModelMat = new Matrixf();

		private Vec3d prevPos = new Vec3d();

		private Vec3d curPos = new Vec3d();

		internal bool DoRender;

		private MeshData mesh = new MeshData(4, 3);

		private double rotaccum;

		public EntityBlockFallingRenderer(Entity entity, ICoreClientAPI api)
			: base(entity, api)
		{
			blockFallingEntity = (EntityBlockFalling)entity;
			block = blockFallingEntity.Block;
			entity.PhysicsUpdateWatcher = OnPhysicsTick;
			if (!blockFallingEntity.InitialBlockRemoved)
			{
				int x = blockFallingEntity.blockEntityAttributes?.GetInt("posx", blockFallingEntity.initialPos.X) ?? blockFallingEntity.initialPos.X;
				int y = blockFallingEntity.blockEntityAttributes?.GetInt("posy", blockFallingEntity.initialPos.Y) ?? blockFallingEntity.initialPos.Y;
				int z = blockFallingEntity.blockEntityAttributes?.GetInt("posz", blockFallingEntity.initialPos.Z) ?? blockFallingEntity.initialPos.Z;
				api.World.BlockAccessor.GetBlockEntity(new BlockPos(x, y, z))?.OnTesselation(this, capi.Tesselator);
				if (mesh.VerticesCount > 0)
				{
					mesh.CustomBytes = null;
					mesh.CustomFloats = null;
					mesh.CustomInts = null;
					meshRef = capi.Render.UploadMultiTextureMesh(mesh);
				}
			}
			if (meshRef == null)
			{
				MeshData defaultBlockMesh = api.TesselatorManager.GetDefaultBlockMesh(block);
				meshRef = api.Render.UploadMultiTextureMesh(defaultBlockMesh);
			}
			_ = block.FirstTextureInventory.Baked.TextureSubId;
			prevPos.Set(entity.Pos.X + (double)entity.SelectionBox.X1, entity.Pos.Y + (double)entity.SelectionBox.Y1, entity.Pos.Z + (double)entity.SelectionBox.Z1);
		}

		public void OnPhysicsTick(float nextAccum, Vec3d prevPos)
		{
			this.prevPos.Set(prevPos.X + (double)entity.SelectionBox.X1, prevPos.Y + (double)entity.SelectionBox.Y1, prevPos.Z + (double)entity.SelectionBox.Z1);
		}

		public void AddMeshData(MeshData data, int lodlevel = 1)
		{
			if (data != null)
			{
				mesh.AddMeshData(data);
			}
		}

		public void AddMeshData(MeshData data, ColorMapData colormapdata, int lodlevel = 1)
		{
			if (data != null)
			{
				mesh.AddMeshData(data);
			}
		}

		public void AddMeshData(MeshData data, float[] tfMatrix, int lodLevel = 1)
		{
			if (data != null)
			{
				mesh.AddMeshData(data);
			}
		}

		public override void DoRender3DOpaque(float dt, bool isShadowPass)
		{
			if (!isShadowPass && DoRender && (blockFallingEntity.InitialBlockRemoved || entity.World.BlockAccessor.GetBlock(blockFallingEntity.initialPos).Id == 0))
			{
				rotaccum += dt;
				curPos.Set(entity.Pos.X + (double)entity.SelectionBox.X1, entity.Pos.Y + (double)entity.SelectionBox.Y1, entity.Pos.Z + (double)entity.SelectionBox.Z1);
				RenderFallingBlockEntity();
			}
		}

		private void RenderFallingBlockEntity()
		{
			IRenderAPI render = capi.Render;
			render.GlDisableCullFace();
			render.GlToggleBlend(blend: true);
			float num = (entity.Collided ? 4f : 1.5f);
			IStandardShaderProgram standardShaderProgram = render.PreparedStandardShader((int)entity.Pos.X, (int)(entity.Pos.Y + 0.2), (int)entity.Pos.Z);
			Vec3d cameraPos = capi.World.Player.Entity.CameraPos;
			standardShaderProgram.ModelMatrix = ModelMat.Identity().Translate(curPos.X - cameraPos.X + (double)(GameMath.Sin((float)capi.InWorldEllapsedMilliseconds / 120f + 30f) / 20f / num), curPos.Y - cameraPos.Y, curPos.Z - cameraPos.Z + (double)(GameMath.Cos((float)capi.InWorldEllapsedMilliseconds / 110f + 20f) / 20f / num)).RotateX((float)(Math.Sin(rotaccum * 10.0) / 10.0 / (double)num))
				.RotateZ((float)(Math.Cos(10.0 + rotaccum * 9.0) / 10.0 / (double)num))
				.Values;
			standardShaderProgram.ViewMatrix = render.CameraMatrixOriginf;
			standardShaderProgram.ProjectionMatrix = render.CurrentProjectionMatrix;
			render.RenderMultiTextureMesh(meshRef, "tex");
			standardShaderProgram.Stop();
		}

		public override void Dispose()
		{
			meshRef?.Dispose();
		}
	}
	public class ModSystemItemRendererOptimizer : ModSystem, IRenderer, IDisposable
	{
		private int itemCount;

		private ICoreClientAPI capi;

		public double RenderOrder => 1.0;

		public int RenderRange => 1;

		public void OnRenderFrame(float deltaTime, EnumRenderStage stage)
		{
			EntityItemRenderer.RenderCount = 0;
		}

		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Client;
		}

		public override void StartClientSide(ICoreClientAPI api)
		{
			capi = api;
			api.Event.RegisterRenderer(this, EnumRenderStage.Before);
			api.Event.RegisterGameTickListener(onTick, 1001);
		}

		private void onTick(float dt)
		{
			itemCount = 0;
			foreach (KeyValuePair<long, Entity> loadedEntity in capi.World.LoadedEntities)
			{
				if (loadedEntity.Value is EntityItem)
				{
					itemCount++;
				}
			}
			EntityItemRenderer.RunWittySkipRenderAlgorithm = itemCount > 400;
			EntityItemRenderer.RenderModulo = itemCount / 200;
			EntityItemRenderer.LastPos.Set(-99, -99, -99);
		}
	}
	public class EntityItemRenderer : EntityRenderer
	{
		public static bool RunWittySkipRenderAlgorithm;

		public static BlockPos LastPos = new BlockPos();

		public static int LastCollectibleId;

		public static int RenderCount;

		public static int RenderModulo;

		private EntityItem entityitem;

		private long touchGroundMS;

		public float[] ModelMat = Mat4f.Create();

		private float scaleRand;

		private float yRotRand;

		private Vec3d lerpedPos = new Vec3d();

		private ItemSlot inslot;

		private float accum;

		private Vec4f particleOutTransform = new Vec4f();

		private Vec4f glowRgb = new Vec4f();

		private bool rotateWhenFalling;

		private float xangle;

		private float yangle;

		private float zangle;

		public EntityItemRenderer(Entity entity, ICoreClientAPI api)
			: base(entity, api)
		{
			entityitem = (EntityItem)entity;
			inslot = entityitem.Slot;
			rotateWhenFalling = inslot.Itemstack?.Collectible?.Attributes?["rotateWhenFalling"].AsBool(defaultValue: true) ?? true;
			scaleRand = (float)api.World.Rand.NextDouble() / 20f - 0.025f;
			touchGroundMS = entityitem.itemSpawnedMilliseconds - api.World.Rand.Next(5000);
			yRotRand = (float)api.World.Rand.NextDouble() * ((float)Math.PI * 2f);
			lerpedPos = entity.Pos.XYZ;
		}

		public override void DoRender3DOpaque(float dt, bool isShadowPass)
		{
			if (isShadowPass && !entity.IsRendered)
			{
				return;
			}
			if (RunWittySkipRenderAlgorithm)
			{
				int num = (int)entity.Pos.X;
				int num2 = (int)entity.Pos.Y;
				int num3 = (int)entity.Pos.Z;
				int num4 = ((entityitem.Itemstack.Class != EnumItemClass.Block) ? 1 : (-1)) * entityitem.Itemstack.Id;
				if (LastPos.X == num && LastPos.Y == num2 && LastPos.Z == num3 && LastCollectibleId == num4)
				{
					if (entity.EntityId % RenderModulo != 0L)
					{
						return;
					}
				}
				else
				{
					LastPos.Set(num, num2, num3);
				}
				LastCollectibleId = num4;
			}
			IRenderAPI render = capi.Render;
			lerpedPos.X += (entity.Pos.X - lerpedPos.X) * 22.0 * (double)dt;
			lerpedPos.Y += (entity.Pos.InternalY - lerpedPos.Y) * 22.0 * (double)dt;
			lerpedPos.Z += (entity.Pos.Z - lerpedPos.Z) * 22.0 * (double)dt;
			ItemRenderInfo itemStackRenderInfo = render.GetItemStackRenderInfo(inslot, EnumItemRenderTarget.Ground, dt);
			if (itemStackRenderInfo.ModelRef == null || itemStackRenderInfo.Transform == null)
			{
				return;
			}
			IStandardShaderProgram standardShaderProgram = null;
			LoadModelMatrix(itemStackRenderInfo, isShadowPass, dt);
			string textureSampleName = "tex";
			if (isShadowPass)
			{
				textureSampleName = "tex2d";
				float[] array = Mat4f.Mul(ModelMat, capi.Render.CurrentModelviewMatrix, ModelMat);
				Mat4f.Mul(array, capi.Render.CurrentProjectionMatrix, array);
				capi.Render.CurrentActiveShader.UniformMatrix("mvpMatrix", array);
				capi.Render.CurrentActiveShader.Uniform("origin", new Vec3f());
			}
			else
			{
				standardShaderProgram = render.StandardShader;
				standardShaderProgram.Use();
				standardShaderProgram.RgbaTint = (entity.Swimming ? new Vec4f(0.5f, 0.5f, 0.5f, 1f) : ColorUtil.WhiteArgbVec);
				standardShaderProgram.DontWarpVertices = 0;
				standardShaderProgram.NormalShaded = 1;
				standardShaderProgram.AlphaTest = itemStackRenderInfo.AlphaTest;
				standardShaderProgram.DamageEffect = itemStackRenderInfo.DamageEffect;
				if (entity.Swimming)
				{
					standardShaderProgram.AddRenderFlags = (int)(((entityitem.Itemstack.Collectible.MaterialDensity <= 1000) ? 1u : 0u) << 12);
					standardShaderProgram.WaterWaveCounter = capi.Render.ShaderUniforms.WaterWaveCounter;
				}
				else
				{
					standardShaderProgram.AddRenderFlags = 0;
				}
				standardShaderProgram.OverlayOpacity = itemStackRenderInfo.OverlayOpacity;
				if (itemStackRenderInfo.OverlayTexture != null && itemStackRenderInfo.OverlayOpacity > 0f)
				{
					standardShaderProgram.Tex2dOverlay2D = itemStackRenderInfo.OverlayTexture.TextureId;
					standardShaderProgram.OverlayTextureSize = new Vec2f(itemStackRenderInfo.OverlayTexture.Width, itemStackRenderInfo.OverlayTexture.Height);
					standardShaderProgram.BaseTextureSize = new Vec2f(itemStackRenderInfo.TextureSize.Width, itemStackRenderInfo.TextureSize.Height);
					TextureAtlasPosition textureAtlasPosition = render.GetTextureAtlasPosition(entityitem.Itemstack);
					standardShaderProgram.BaseUvOrigin = new Vec2f(textureAtlasPosition.x1, textureAtlasPosition.y1);
				}
				BlockPos asBlockPos = entityitem.Pos.AsBlockPos;
				Vec4f lightRGBs = capi.World.BlockAccessor.GetLightRGBs(asBlockPos.X, asBlockPos.InternalY, asBlockPos.Z);
				int num5 = (int)entityitem.Itemstack.Collectible.GetTemperature(capi.World, entityitem.Itemstack);
				float[] incandescenceColorAsColor4f = ColorUtil.GetIncandescenceColorAsColor4f(num5);
				int num6 = GameMath.Clamp((num5 - 550) / 2, 0, 255);
				glowRgb.R = incandescenceColorAsColor4f[0];
				glowRgb.G = incandescenceColorAsColor4f[1];
				glowRgb.B = incandescenceColorAsColor4f[2];
				glowRgb.A = (float)num6 / 255f;
				standardShaderProgram.ExtraGlow = num6;
				standardShaderProgram.RgbaAmbientIn = render.AmbientColor;
				standardShaderProgram.RgbaLightIn = lightRGBs;
				standardShaderProgram.RgbaGlowIn = glowRgb;
				standardShaderProgram.RgbaFogIn = render.FogColor;
				standardShaderProgram.FogMinIn = render.FogMin;
				standardShaderProgram.FogDensityIn = render.FogDensity;
				standardShaderProgram.ExtraGodray = 0f;
				standardShaderProgram.NormalShaded = (itemStackRenderInfo.NormalShaded ? 1 : 0);
				standardShaderProgram.ProjectionMatrix = render.CurrentProjectionMatrix;
				standardShaderProgram.ViewMatrix = render.CameraMatrixOriginf;
				standardShaderProgram.ModelMatrix = ModelMat;
				ItemStack itemstack = entityitem.Itemstack;
				AdvancedParticleProperties[] array2 = itemstack.Block?.ParticleProperties;
				if (itemstack.Block != null && !capi.IsGamePaused)
				{
					Mat4f.MulWithVec4(ModelMat, new Vec4f(itemstack.Block.TopMiddlePos.X, itemstack.Block.TopMiddlePos.Y - 0.4f, itemstack.Block.TopMiddlePos.Z - 0.5f, 0f), particleOutTransform);
					accum += dt;
					if (array2 != null && array2.Length != 0 && accum > 0.025f)
					{
						accum %= 0.025f;
						foreach (AdvancedParticleProperties advancedParticleProperties in array2)
						{
							advancedParticleProperties.basePos.X = (double)particleOutTransform.X + entity.Pos.X;
							advancedParticleProperties.basePos.Y = (double)particleOutTransform.Y + entity.Pos.InternalY;
							advancedParticleProperties.basePos.Z = (double)particleOutTransform.Z + entity.Pos.Z;
							entityitem.World.SpawnParticles(advancedParticleProperties);
						}
					}
				}
			}
			if (!itemStackRenderInfo.CullFaces)
			{
				render.GlDisableCullFace();
			}
			render.RenderMultiTextureMesh(itemStackRenderInfo.ModelRef, textureSampleName);
			if (!itemStackRenderInfo.CullFaces)
			{
				render.GlEnableCullFace();
			}
			if (!isShadowPass)
			{
				standardShaderProgram.AddRenderFlags = 0;
				standardShaderProgram.DamageEffect = 0f;
				standardShaderProgram.Stop();
			}
		}

		private void LoadModelMatrix(ItemRenderInfo renderInfo, bool isShadowPass, float dt)
		{
			EntityPlayer entityPlayer = capi.World.Player.Entity;
			Mat4f.Identity(ModelMat);
			Mat4f.Translate(ModelMat, ModelMat, (float)(lerpedPos.X - entityPlayer.CameraPos.X), (float)(lerpedPos.Y - entityPlayer.CameraPos.Y), (float)(lerpedPos.Z - entityPlayer.CameraPos.Z));
			float num = 0.2f * renderInfo.Transform.ScaleXYZ.X;
			float num2 = 0.2f * renderInfo.Transform.ScaleXYZ.Y;
			float num3 = 0.2f * renderInfo.Transform.ScaleXYZ.Z;
			float num4 = 0f;
			float num5 = 0f;
			if (!isShadowPass)
			{
				long elapsedMilliseconds = capi.World.ElapsedMilliseconds;
				bool flag = !entity.Collided && !entity.Swimming && !capi.IsGamePaused;
				if (!flag)
				{
					touchGroundMS = elapsedMilliseconds;
				}
				if (entity.Collided)
				{
					xangle *= 0.55f;
					yangle *= 0.55f;
					zangle *= 0.55f;
				}
				else if (rotateWhenFalling)
				{
					float num6 = Math.Min(1L, (elapsedMilliseconds - touchGroundMS) / 200);
					float num7 = (flag ? (1000f * dt / 7f * num6) : 0f);
					yangle += num7;
					xangle += num7;
					zangle += num7;
				}
				if (entity.Swimming)
				{
					float num8 = 1f;
					if (entityitem.Itemstack.Collectible.MaterialDensity > 1000)
					{
						num4 = GameMath.Sin((float)((double)elapsedMilliseconds / 1000.0)) / 50f;
						num5 = (0f - GameMath.Sin((float)((double)elapsedMilliseconds / 3000.0))) / 50f;
						num8 = 0.1f;
					}
					xangle = GameMath.Sin((float)((double)elapsedMilliseconds / 1000.0)) * 8f * num8;
					yangle = GameMath.Cos((float)((double)elapsedMilliseconds / 2000.0)) * 3f * num8;
					zangle = (0f - GameMath.Sin((float)((double)elapsedMilliseconds / 3000.0))) * 8f * num8;
				}
			}
			ModelTransform transform = renderInfo.Transform;
			FastVec3f translation = transform.Translation;
			FastVec3f rotation = transform.Rotation;
			Mat4f.Translate(ModelMat, ModelMat, num4 + translation.X, translation.Y, num5 + translation.Z);
			Mat4f.Scale(ModelMat, ModelMat, new float[3]
			{
				num + scaleRand,
				num2 + scaleRand,
				num3 + scaleRand
			});
			Mat4f.RotateY(ModelMat, ModelMat, (float)Math.PI / 180f * (rotation.Y + yangle) + (transform.Rotate ? yRotRand : 0f));
			Mat4f.RotateZ(ModelMat, ModelMat, (float)Math.PI / 180f * (rotation.Z + zangle));
			Mat4f.RotateX(ModelMat, ModelMat, (float)Math.PI / 180f * (rotation.X + xangle));
			Mat4f.Translate(ModelMat, ModelMat, 0f - transform.Origin.X, 0f - transform.Origin.Y, 0f - transform.Origin.Z);
		}

		public override void Dispose()
		{
		}
	}
	public enum RenderMode
	{
		FirstPerson,
		ImmersiveFirstPerson,
		ThirdPerson
	}
	public class EntityPlayerShapeRenderer : EntityShapeRenderer
	{
		private MultiTextureMeshRef firstPersonMeshRef;

		private MultiTextureMeshRef thirdPersonMeshRef;

		private bool watcherRegistered;

		private EntityPlayer entityPlayer;

		private ModSystemFpHands modSys;

		private RenderMode renderMode;

		private float smoothedBodyYaw;

		private bool previfpMode;

		private static ModelTransform DefaultTongTransform = new ModelTransform
		{
			Translation = new FastVec3f(-0.68f, -0.52f, -0.6f),
			Rotation = new FastVec3f(-26f, -13f, -88f),
			Origin = new FastVec3f(0.5f, 0f, 0.5f),
			Scale = 0.7f
		};

		public float? HeldItemPitchFollowOverride { get; set; }

		protected bool IsSelf => entity.EntityId == capi.World.Player.Entity.EntityId;

		public override bool DisplayChatMessages => true;

		public virtual float HandRenderFov => (float)capi.Settings.Int["fpHandsFoV"] * ((float)Math.PI / 180f);

		public EntityPlayerShapeRenderer(Entity entity, ICoreClientAPI api)
			: base(entity, api)
		{
			entityPlayer = entity as EntityPlayer;
			modSys = api.ModLoader.GetModSystem<ModSystemFpHands>();
		}

		public override void OnEntityLoaded()
		{
			base.OnEntityLoaded();
		}

		public override void TesselateShape()
		{
			if (entityPlayer.GetBehavior<EntityBehaviorPlayerInventory>().Inventory == null)
			{
				return;
			}
			defaultTexSource = GetTextureSource();
			Tesselate();
			if (watcherRegistered)
			{
				return;
			}
			previfpMode = capi.Settings.Bool["immersiveFpMode"];
			if (IsSelf)
			{
				capi.Settings.Bool.AddWatcher("immersiveFpMode", delegate(bool on)
				{
					entity.MarkShapeModified();
					(entityPlayer.AnimManager as PlayerAnimationManager).OnIfpModeChanged(previfpMode, on);
				});
			}
			watcherRegistered = true;
		}

		protected override void onMeshReady(MeshData meshData)
		{
			base.onMeshReady(meshData);
			if (!IsSelf)
			{
				thirdPersonMeshRef = meshRefOpaque;
			}
		}

		public void Tesselate()
		{
			if (!IsSelf)
			{
				base.TesselateShape();
			}
			else
			{
				if (!loaded)
				{
					return;
				}
				TesselateShape(delegate(MeshData meshData)
				{
					disposeMeshes();
					if (!capi.IsShuttingDown && meshData.VerticesCount > 0)
					{
						MeshData meshData2 = meshData.EmptyClone();
						thirdPersonMeshRef = capi.Render.UploadMultiTextureMesh(meshData);
						determineRenderMode();
						if (renderMode == RenderMode.ImmersiveFirstPerson)
						{
							HashSet<int> skipJointIds = new HashSet<int>();
							loadJointIdsRecursive(entity.AnimManager.Animator.GetPosebyName("Neck"), skipJointIds);
							meshData2.AddMeshData(meshData, (int i) => !skipJointIds.Contains(meshData.CustomInts.Values[i * 4]));
						}
						else
						{
							HashSet<int> includeJointIds = new HashSet<int>();
							loadJointIdsRecursive(entity.AnimManager.Animator.GetPosebyName("UpperArmL"), includeJointIds);
							loadJointIdsRecursive(entity.AnimManager.Animator.GetPosebyName("UpperArmR"), includeJointIds);
							meshData2.AddMeshData(meshData, (int i) => includeJointIds.Contains(meshData.CustomInts.Values[i * 4]));
						}
						firstPersonMeshRef = capi.Render.UploadMultiTextureMesh(meshData2);
					}
				});
			}
		}

		private void loadJointIdsRecursive(ElementPose elementPose, HashSet<int> outList)
		{
			outList.Add(elementPose.ForElement.JointId);
			foreach (ElementPose childElementPose in elementPose.ChildElementPoses)
			{
				loadJointIdsRecursive(childElementPose, outList);
			}
		}

		private void disposeMeshes()
		{
			if (firstPersonMeshRef != null)
			{
				firstPersonMeshRef.Dispose();
				firstPersonMeshRef = null;
			}
			if (thirdPersonMeshRef != null)
			{
				thirdPersonMeshRef.Dispose();
				thirdPersonMeshRef = null;
			}
			if (meshRefOpaque != null)
			{
				meshRefOpaque.Dispose();
				meshRefOpaque = null;
			}
		}

		public override void BeforeRender(float dt)
		{
			RenderMode renderMode = this.renderMode;
			determineRenderMode();
			if ((renderMode == RenderMode.FirstPerson && this.renderMode == RenderMode.ImmersiveFirstPerson) || (renderMode == RenderMode.ImmersiveFirstPerson && this.renderMode == RenderMode.FirstPerson))
			{
				entity.MarkShapeModified();
				(entityPlayer.AnimManager as PlayerAnimationManager).OnIfpModeChanged(previfpMode, this.renderMode == RenderMode.ImmersiveFirstPerson);
			}
			base.BeforeRender(dt);
		}

		private void determineRenderMode()
		{
			if (IsSelf)
			{
				IClientPlayer clientPlayer = player;
				if (clientPlayer != null && clientPlayer.CameraMode == EnumCameraMode.FirstPerson)
				{
					if (capi.Settings.Bool["immersiveFpMode"] && !capi.Render.CameraStuck)
					{
						ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("tiredness");
						if (treeAttribute == null || treeAttribute.GetInt("isSleeping") != 1)
						{
							renderMode = RenderMode.ImmersiveFirstPerson;
							return;
						}
					}
					renderMode = RenderMode.FirstPerson;
					return;
				}
			}
			renderMode = RenderMode.ThirdPerson;
		}

		public override void RenderToGui(float dt, double posX, double posY, double posZ, float yawDelta, float size)
		{
			if (IsSelf)
			{
				meshRefOpaque = thirdPersonMeshRef;
			}
			base.RenderToGui(dt, posX, posY, posZ, yawDelta, size);
		}

		public override void DoRender2D(float dt)
		{
			if (IsSelf)
			{
				IClientPlayer clientPlayer = player;
				if (clientPlayer != null && clientPlayer.CameraMode == EnumCameraMode.FirstPerson)
				{
					return;
				}
			}
			base.DoRender2D(dt);
		}

		public override Vec3d getAboveHeadPosition(EntityPlayer entityPlayer)
		{
			if (IsSelf)
			{
				return new Vec3d(entityPlayer.CameraPos.X + entityPlayer.LocalEyePos.X, entityPlayer.CameraPos.Y + 0.4 + entityPlayer.LocalEyePos.Y, entityPlayer.CameraPos.Z + entityPlayer.LocalEyePos.Z);
			}
			return base.getAboveHeadPosition(entityPlayer);
		}

		public override void DoRender3DOpaque(float dt, bool isShadowPass)
		{
			if (IsSelf)
			{
				entityPlayer.selfNowShadowPass = isShadowPass;
			}
			bool flag = renderMode == RenderMode.FirstPerson && !isShadowPass;
			loadModelMatrixForPlayer(entity, IsSelf, dt, isShadowPass);
			if (IsSelf && (renderMode == RenderMode.ImmersiveFirstPerson || isShadowPass))
			{
				OriginPos.Set(0f, 0f, 0f);
			}
			if (flag && capi.HideGuis)
			{
				return;
			}
			if (flag)
			{
				pMatrixNormalFov = (float[])capi.Render.CurrentProjectionMatrix.Clone();
				capi.Render.Set3DProjection(capi.Render.ShaderUniforms.ZFar, HandRenderFov);
				pMatrixHandFov = (float[])capi.Render.CurrentProjectionMatrix.Clone();
			}
			else
			{
				pMatrixHandFov = null;
				pMatrixNormalFov = null;
			}
			if (isShadowPass)
			{
				DoRender3DAfterOIT(dt, isShadowPass: true);
			}
			if (DoRenderHeldItem && !entity.AnimManager.ActiveAnimationsByAnimCode.ContainsKey("lie") && !isSpectator)
			{
				RenderHeldItem(dt, isShadowPass, right: false);
				RenderHeldItem(dt, isShadowPass, right: true);
			}
			if (flag)
			{
				if (!capi.Settings.Bool["hideFpHands"] && !entityPlayer.GetBehavior<EntityBehaviorTiredness>().IsSleeping)
				{
					IShaderProgram fpModeHandShader = modSys.fpModeHandShader;
					meshRefOpaque = firstPersonMeshRef;
					fpModeHandShader.Use();
					fpModeHandShader.Uniform("rgbaAmbientIn", capi.Render.AmbientColor);
					fpModeHandShader.Uniform("rgbaFogIn", capi.Render.FogColor);
					fpModeHandShader.Uniform("fogMinIn", capi.Render.FogMin);
					fpModeHandShader.Uniform("fogDensityIn", capi.Render.FogDensity);
					fpModeHandShader.UniformMatrix("projectionMatrix", capi.Render.CurrentProjectionMatrix);
					fpModeHandShader.Uniform("alphaTest", 0.05f);
					fpModeHandShader.Uniform("lightPosition", capi.Render.ShaderUniforms.LightPosition3D);
					fpModeHandShader.Uniform("depthOffset", -0.3f - GameMath.Max(0f, (float)capi.Settings.Int["fieldOfView"] / 90f - 1f) / 2f);
					capi.Render.GlPushMatrix();
					capi.Render.GlLoadMatrix(capi.Render.CameraMatrixOrigin);
					base.DoRender3DOpaqueBatched(dt, isShadowPass: false);
					capi.Render.GlPopMatrix();
					fpModeHandShader.Stop();
				}
				capi.Render.Reset3DProjection();
			}
		}

		protected override IShaderProgram getReadyShader()
		{
			if (!entityPlayer.selfNowShadowPass && renderMode == RenderMode.FirstPerson)
			{
				IShaderProgram fpModeItemShader = modSys.fpModeItemShader;
				fpModeItemShader.Use();
				fpModeItemShader.Uniform("depthOffset", -0.3f - GameMath.Max(0f, (float)capi.Settings.Int["fieldOfView"] / 90f - 1f) / 2f);
				fpModeItemShader.Uniform("ssaoAttn", 1f);
				return fpModeItemShader;
			}
			return base.getReadyShader();
		}

		protected override void RenderHeldItem(float dt, bool isShadowPass, bool right)
		{
			if (IsSelf)
			{
				entityPlayer.selfNowShadowPass = isShadowPass;
			}
			if (right)
			{
				ItemSlot itemSlot = eagent?.RightHandItemSlot;
				if (itemSlot is ItemSlotSkill)
				{
					return;
				}
				ItemStack itemStack = itemSlot?.Itemstack;
				ItemStack itemStack2 = eagent?.LeftHandItemSlot?.Itemstack;
				if (itemStack != null && itemStack.Collectible.GetTemperature(entity.World, itemStack) > 200f && itemStack2 != null && itemStack2.ItemAttributes?.IsTrue("heatResistant") == true)
				{
					AttachmentPointAndPose apap = entity.AnimManager?.Animator?.GetAttachmentPointPose("LeftHand");
					ItemRenderInfo itemStackRenderInfo = capi.Render.GetItemStackRenderInfo(itemSlot, EnumItemRenderTarget.HandTpOff, dt);
					itemStackRenderInfo.Transform = itemStack.ItemAttributes?["onTongTransform"].AsObject(DefaultTongTransform) ?? DefaultTongTransform;
					RenderItem(dt, isShadowPass, itemStack, apap, itemStackRenderInfo);
					return;
				}
			}
			bool flag = renderMode == RenderMode.FirstPerson;
			if ((flag && !capi.Settings.Bool["hideFpHands"]) || !flag)
			{
				base.RenderHeldItem(dt, isShadowPass, right);
			}
		}

		public override void DoRender3DOpaqueBatched(float dt, bool isShadowPass)
		{
			if (renderMode != RenderMode.FirstPerson || isShadowPass)
			{
				if (isShadowPass)
				{
					meshRefOpaque = thirdPersonMeshRef;
				}
				else
				{
					meshRefOpaque = ((renderMode == RenderMode.ImmersiveFirstPerson) ? firstPersonMeshRef : thirdPersonMeshRef);
				}
				base.DoRender3DOpaqueBatched(dt, isShadowPass);
			}
		}

		public void loadModelMatrixForPlayer(Entity entity, bool isSelf, float dt, bool isShadowPass)
		{
			EntityPlayer entityPlayer = capi.World.Player.Entity;
			Mat4f.Identity(ModelMat);
			if (isSelf)
			{
				Matrixf matrixf = entityPlayer.MountedOn?.RenderTransform;
				if (matrixf != null)
				{
					ModelMat = Mat4f.Mul(ModelMat, ModelMat, matrixf.Values);
				}
			}
			else
			{
				Vec3f otherPlayerRenderOffset = GetOtherPlayerRenderOffset();
				Mat4f.Translate(ModelMat, ModelMat, otherPlayerRenderOffset.X, otherPlayerRenderOffset.Y, otherPlayerRenderOffset.Z);
				Matrixf matrixf2 = this.entityPlayer.MountedOn?.RenderTransform;
				if (matrixf2 != null)
				{
					ModelMat = Mat4f.Mul(ModelMat, ModelMat, matrixf2.Values);
				}
			}
			float num = ((entity.Properties.Client.Shape != null) ? entity.Properties.Client.Shape.rotateX : 0f);
			float num2 = ((entity.Properties.Client.Shape != null) ? entity.Properties.Client.Shape.rotateY : 0f);
			float num3 = ((entity.Properties.Client.Shape != null) ? entity.Properties.Client.Shape.rotateZ : 0f);
			float num4 = Math.Min(0.05f, dt);
			if (!isSelf && this.entityPlayer.MountedOn?.Entity != null)
			{
				smoothedBodyYaw = (bodyYawLerped = this.entityPlayer.MountedOn.Entity.Pos.Yaw);
			}
			else
			{
				IClientPlayer clientPlayer = player;
				if (clientPlayer == null || clientPlayer.CameraMode != EnumCameraMode.FirstPerson)
				{
					float val = GameMath.AngleRadDistance(bodyYawLerped, eagent.BodyYaw);
					bodyYawLerped += GameMath.Clamp(val, (0f - num4) * 8f, num4 * 8f);
					float num5 = bodyYawLerped;
					smoothedBodyYaw = num5;
				}
				else
				{
					float num5 = ((renderMode != RenderMode.ThirdPerson) ? eagent.BodyYaw : eagent.Pos.Yaw);
					if (!isShadowPass)
					{
						smoothCameraTurning(num5, num4);
					}
				}
			}
			float num6 = ((this.entityPlayer == null) ? 0f : this.entityPlayer.WalkPitch);
			float valueOrDefault = (this.entityPlayer.MountedOn?.SeatPosition?.Pitch).GetValueOrDefault();
			Mat4f.RotateX(ModelMat, ModelMat, entity.Pos.Roll + num * ((float)Math.PI / 180f));
			Mat4f.RotateY(ModelMat, ModelMat, smoothedBodyYaw + (90f + num2) * ((float)Math.PI / 180f));
			if ((!isSelf || !eagent.Swimming || renderMode != RenderMode.FirstPerson) && (((entityPlayer == null || !entityPlayer.Controls.Gliding) && entityPlayer.MountedOn == null) || renderMode != RenderMode.FirstPerson))
			{
				Mat4f.RotateZ(ModelMat, ModelMat, num6 + num3 * ((float)Math.PI / 180f));
				if (valueOrDefault != 0f)
				{
					Mat4f.Translate(ModelMat, ModelMat, 0f, -0.5f, 0f);
					Mat4f.RotateZ(ModelMat, ModelMat, valueOrDefault);
					Mat4f.Translate(ModelMat, ModelMat, 0f, 0.5f, 0f);
				}
			}
			Mat4f.RotateX(ModelMat, ModelMat, nowSwivelRad);
			if (entityPlayer != null && renderMode == RenderMode.FirstPerson && !isShadowPass)
			{
				float num7 = eagent.RightHandItemSlot?.Itemstack?.ItemAttributes?["heldItemPitchFollow"].AsFloat(0.75f) ?? 0.75f;
				float num8 = eagent.MountedOn?.FpHandPitchFollow ?? 1f;
				float num9 = ((entityPlayer != null && entityPlayer.Controls.IsFlying) ? 1f : (HeldItemPitchFollowOverride ?? (num7 * num8)));
				Mat4f.Translate(ModelMat, ModelMat, 0f, (float)entity.LocalEyePos.Y, 0f);
				Mat4f.RotateZ(ModelMat, ModelMat, (entity.Pos.Pitch - (float)Math.PI) * num9);
				Mat4f.Translate(ModelMat, ModelMat, 0f, 0f - (float)entity.LocalEyePos.Y, 0f);
			}
			if (renderMode == RenderMode.FirstPerson && !isShadowPass)
			{
				Mat4f.Translate(ModelMat, ModelMat, 0f, capi.Settings.Float["fpHandsYOffset"], 0f);
			}
			float num10 = entity.WatchedAttributes.GetFloat("intoxication");
			intoxIntensity += (num10 - intoxIntensity) * dt / 3f;
			capi.Render.PerceptionEffects.ApplyToTpPlayer(entity as EntityPlayer, ModelMat, intoxIntensity);
			float size = entity.Properties.Client.Size;
			Mat4f.Scale(ModelMat, ModelMat, new float[3] { size, size, size });
			Mat4f.Translate(ModelMat, ModelMat, -0.5f, 0f, -0.5f);
		}

		private void smoothCameraTurning(float bodyYaw, float mdt)
		{
			float value = GameMath.AngleRadDistance(smoothedBodyYaw, bodyYaw);
			smoothedBodyYaw += Math.Max(0f, Math.Abs(value) - 0.6f) * (float)Math.Sign(value);
			value = GameMath.AngleRadDistance(smoothedBodyYaw, eagent.BodyYaw);
			smoothedBodyYaw += value * mdt * 25f;
		}

		protected Vec3f GetOtherPlayerRenderOffset()
		{
			EntityPlayer entityPlayer = capi.World.Player.Entity;
			IMountable mountable = entityPlayer.MountedOn?.MountSupplier;
			IMountableSeat mountedOn = (entity as EntityAgent).MountedOn;
			IMountable mountable2 = mountedOn?.MountSupplier;
			if (mountable != null && mountable == mountable2)
			{
				EntityPos seatPosition = entityPlayer.MountedOn.SeatPosition;
				EntityPos seatPosition2 = mountedOn.SeatPosition;
				return new Vec3f((float)(0.0 - seatPosition.X + seatPosition2.X), (float)(0.0 - seatPosition.Y + seatPosition2.Y), (float)(0.0 - seatPosition.Z + seatPosition2.Z));
			}
			if (mountedOn != null)
			{
				return new Vec3f((float)(mountedOn.SeatPosition.X - entityPlayer.CameraPos.X), (float)(mountedOn.SeatPosition.InternalY - entityPlayer.CameraPos.Y), (float)(mountedOn.SeatPosition.Z - entityPlayer.CameraPos.Z));
			}
			return new Vec3f((float)(entity.Pos.X - entityPlayer.CameraPos.X), (float)(entity.Pos.InternalY - entityPlayer.CameraPos.Y), (float)(entity.Pos.Z - entityPlayer.CameraPos.Z));
		}

		protected override void determineSidewaysSwivel(float dt)
		{
			if (entityPlayer.MountedOn != null)
			{
				entityPlayer.sidewaysSwivelAngle = (nowSwivelRad = 0f);
				return;
			}
			double num = Math.Atan2(entity.Pos.Motion.Z, entity.Pos.Motion.X);
			double num2 = entity.Pos.Motion.LengthSq();
			if (num2 > 0.001 && entity.OnGround)
			{
				float val = GameMath.AngleRadDistance((float)prevAngleSwing, (float)num);
				float num3 = nowSwivelRad;
				float num4 = GameMath.Clamp(val, -0.05f, 0.05f) * dt * 40f * (float)Math.Min(0.02500000037252903, num2) * 80f;
				EntityAgent entityAgent = eagent;
				nowSwivelRad = num3 - num4 * (float)((entityAgent == null || !entityAgent.Controls.Backward) ? 1 : (-1));
				nowSwivelRad = GameMath.Clamp(nowSwivelRad, -0.3f, 0.3f);
			}
			nowSwivelRad *= Math.Min(0.99f, 1f - 0.1f * dt * 60f);
			prevAngleSwing = num;
			entityPlayer.sidewaysSwivelAngle = nowSwivelRad;
		}

		public override void Dispose()
		{
			base.Dispose();
			firstPersonMeshRef?.Dispose();
			thirdPersonMeshRef?.Dispose();
		}
	}
