			requiresNearbyEntityRange = taskConfig["requiresNearbyEntityRange"].AsFloat(5f);
			string text = taskConfig["failBlockCode"].AsString();
			if (text != null)
			{
				failBlockCode = new AssetLocation(text);
			}
		}

		public override bool ShouldExecute()
		{
			if (entity.World.Rand.NextDouble() > 0.03)
			{
				return false;
			}
			if (lastPOISearchTotalMs + 15000 > entity.World.ElapsedMilliseconds)
			{
				return false;
			}
			if (cooldownUntilMs > entity.World.ElapsedMilliseconds)
			{
				return false;
			}
			if (cooldownUntilTotalHours > entity.World.Calendar.TotalHours)
			{
				return false;
			}
			if (!PreconditionsSatisifed())
			{
				return false;
			}
			PortionsEatenForLay = 3f;
			if (!DidConsumeFood(PortionsEatenForLay))
			{
				return false;
			}
			if (attemptLayEggTotalHours <= 0.0)
			{
				attemptLayEggTotalHours = entity.World.Calendar.TotalHours;
			}
			lastPOISearchTotalMs = entity.World.ElapsedMilliseconds;
			targetPoi = FindPOI(42) as IAnimalNest;
			if (targetPoi == null)
			{
				LayEggOnGround();
			}
			return targetPoi != null;
		}

		private IPointOfInterest FindPOI(int radius)
		{
			return porregistry.GetWeightedNearestPoi(entity.ServerPos.XYZ, radius, delegate(IPointOfInterest poi)
			{
				if (poi.Type != "nest")
				{
					return false;
				}
				if (poi is IAnimalNest animalNest && !animalNest.Occupied(entity) && animalNest.IsSuitableFor(entity, nestTypes))
				{
					failedSeekTargets.TryGetValue(animalNest, out var value);
					if (value == null || value.Count < 4 || value.LastTryMs < world.ElapsedMilliseconds - 60000)
					{
						return true;
					}
				}
				return false;
			});
		}

		public float MinDistanceToTarget()
		{
			return 0.01f;
		}

		public override void StartExecute()
		{
			if (animMeta != null)
			{
				animMeta.EaseInSpeed = 1f;
				animMeta.EaseOutSpeed = 1f;
				entity.AnimManager.StartAnimation(animMeta);
			}
			nowStuck = false;
			sitTimeNow = 0f;
			laid = false;
			pathTraverser.NavigateTo_Async(targetPoi.Position, moveSpeed, MinDistanceToTarget() - 0.1f, OnGoalReached, OnStuck, null, 1000, 1);
			sitAnimStarted = false;
		}

		public override bool CanContinueExecute()
		{
			return pathTraverser.Ready;
		}

		protected virtual ItemStack MakeEggItem(string chickCode)
		{
			ICoreAPI api = entity.Api;
			JsonItemStack[] array = entity?.Properties.Attributes?["eggTypes"].AsArray<JsonItemStack>();
			ItemStack itemStack;
			if (array == null)
			{
				string text = "egg-chicken-raw";
				if (entity != null)
				{
					api.Logger.Warning(string.Concat("No egg type specified for entity ", entity.Code, ", falling back to ", text));
				}
				itemStack = new ItemStack(api.World.GetItem(text));
			}
			else
			{
				JsonItemStack jsonItemStack = array[api.World.Rand.Next(array.Length)];
				if (!jsonItemStack.Resolve(api.World, null, printWarningOnError: false))
				{
					api.Logger.Warning(string.Concat("Failed to resolve egg ", jsonItemStack.Type.ToString(), " with code ", jsonItemStack.Code, " for entity ", entity.Code));
					return null;
				}
				itemStack = new ItemStack(jsonItemStack.ResolvedItemstack.Collectible);
			}
			if (chickCode != null)
			{
				TreeAttribute treeAttribute = new TreeAttribute();
				chickCode = AssetLocation.Create(chickCode, entity?.Code.Domain ?? "game");
				treeAttribute.SetString("code", chickCode);
				EntityAgent entityAgent = entity;
				treeAttribute.SetInt("generation", (entityAgent != null) ? (entityAgent.WatchedAttributes.GetInt("generation") + 1) : 0);
				treeAttribute.SetDouble("incubationDays", incubationDays);
				EntityAgent entityAgent2 = entity;
				if (entityAgent2 != null)
				{
					treeAttribute.SetLong("herdID", entityAgent2.HerdId);
				}
				itemStack.Attributes["chick"] = treeAttribute;
			}
			return itemStack;
		}

		public override bool ContinueExecute(float dt)
		{
			if (!IsInValidDayTimeHours(initialRandomness: false))
			{
				return false;
			}
			if (targetPoi.Occupied(entity))
			{
				onBadTarget();
				return false;
			}
			Vec3d position = targetPoi.Position;
			double num = position.HorizontalSquareDistanceTo(entity.ServerPos.X, entity.ServerPos.Z);
			pathTraverser.CurrentTarget.X = position.X;
			pathTraverser.CurrentTarget.Y = position.Y;
			pathTraverser.CurrentTarget.Z = position.Z;
			float num2 = MinDistanceToTarget();
			if (num <= (double)num2)
			{
				pathTraverser.Stop();
				if (animMeta != null)
				{
					entity.AnimManager.StopAnimation(animMeta.Code);
				}
				entity.GetBehavior<EntityBehaviorMultiply>();
				if (!targetPoi.IsSuitableFor(entity, nestTypes))
				{
					onBadTarget();
					return false;
				}
				targetPoi.SetOccupier(entity);
				if (sitAnimMeta != null && !sitAnimStarted)
				{
					entity.AnimManager.StartAnimation(sitAnimMeta);
					sitAnimStarted = true;
					sitEndDay = entity.World.Calendar.TotalDays + (double)sitDays;
				}
				sitTimeNow += dt;
				if (sitTimeNow >= layTime && !laid)
				{
					laid = true;
					string chickCode = null;
					if (GetRequiredEntityNearby() != null && chickCodes.Length != 0)
					{
						chickCode = chickCodes[entity.World.Rand.Next(chickCodes.Length)];
					}
					if (targetPoi.TryAddEgg(MakeEggItem(chickCode)))
					{
						ConsumeFood(PortionsEatenForLay);
						attemptLayEggTotalHours = -1.0;
						MakeLaySound();
						failedSeekTargets.Remove(targetPoi);
						return false;
					}
				}
				if (entity.World.Calendar.TotalDays >= sitEndDay)
				{
					failedSeekTargets.Remove(targetPoi);
					return false;
				}
			}
			else if (!pathTraverser.Active)
			{
				float x = (float)entity.World.Rand.NextDouble() * 0.3f - 0.15f;
				float z = (float)entity.World.Rand.NextDouble() * 0.3f - 0.15f;
				pathTraverser.NavigateTo(targetPoi.Position.AddCopy(x, 0f, z), moveSpeed, MinDistanceToTarget() - 0.15f, OnGoalReached, OnStuck, null, giveUpWhenNoPath: false, 500);
			}
			if (nowStuck)
			{
				return false;
			}
			if (attemptLayEggTotalHours > 0.0 && entity.World.Calendar.TotalHours - attemptLayEggTotalHours > 12.0)
			{
				LayEggOnGround();
				return false;
			}
			return true;
		}

		public override void FinishExecute(bool cancelled)
		{
			base.FinishExecute(cancelled);
			attemptLayEggTotalHours = -1.0;
			pathTraverser.Stop();
			if (sitAnimMeta != null)
			{
				entity.AnimManager.StopAnimation(sitAnimMeta.Code);
			}
			targetPoi?.SetOccupier(null);
			if (cancelled)
			{
				cooldownUntilTotalHours = 0.0;
			}
		}

		private void OnStuck()
		{
			nowStuck = true;
			onBadTarget();
		}

		private void onBadTarget()
		{
			IAnimalNest animalNest = null;
			if (attemptLayEggTotalHours >= 0.0 && entity.World.Calendar.TotalHours - attemptLayEggTotalHours > 12.0)
			{
				LayEggOnGround();
			}
			else if (base.rand.NextDouble() > 0.4)
			{
				animalNest = FindPOI(18) as IAnimalNest;
			}
			failedSeekTargets.TryGetValue(targetPoi, out var value);
			if (value == null)
			{
				value = (failedSeekTargets[targetPoi] = new FailedAttempt());
			}
			value.Count++;
			value.LastTryMs = world.ElapsedMilliseconds;
			if (animalNest != null)
			{
				targetPoi = animalNest;
				nowStuck = false;
				sitTimeNow = 0f;
				laid = false;
				pathTraverser.NavigateTo_Async(targetPoi.Position, moveSpeed, MinDistanceToTarget() - 0.1f, OnGoalReached, OnStuck, null, 1000, 1);
				sitAnimStarted = false;
			}
		}

		private void OnGoalReached()
		{
			pathTraverser.Active = true;
			failedSeekTargets.Remove(targetPoi);
		}

		private bool DidConsumeFood(float portion)
		{
			ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("hunger");
			if (treeAttribute == null)
			{
				return false;
			}
			return treeAttribute.GetFloat("saturation") >= portion;
		}

		private bool ConsumeFood(float portion)
		{
			ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("hunger");
			if (treeAttribute == null)
			{
				return false;
			}
			float num = treeAttribute.GetFloat("saturation");
			if (num >= portion)
			{
				float num2 = ((entity.World.Rand.NextDouble() < 0.25) ? portion : 1f);
				treeAttribute.SetFloat("saturation", num - num2);
				return true;
			}
			return false;
		}

		private Entity GetRequiredEntityNearby()
		{
			if (requiresNearbyEntityCode == null)
			{
				return null;
			}
			return entity.World.GetNearestEntity(entity.ServerPos.XYZ, requiresNearbyEntityRange, requiresNearbyEntityRange, delegate(Entity e)
			{
				if (e.WildCardMatch(new AssetLocation(requiresNearbyEntityCode)))
				{
					ITreeAttribute treeAttribute = e.WatchedAttributes.GetTreeAttribute("hunger");
					if (!e.WatchedAttributes.GetBool("doesEat") || treeAttribute == null)
					{
						return true;
					}
					treeAttribute.SetFloat("saturation", Math.Max(0f, treeAttribute.GetFloat("saturation") - 1f));
					return true;
				}
				return false;
			});
		}

		private void LayEggOnGround()
		{
			if (!(entity.World.Rand.NextDouble() > onGroundChance))
			{
				Block block = entity.World.GetBlock(failBlockCode);
				if (block != null && (TryPlace(block, 0, 0, 0) || TryPlace(block, 1, 0, 0) || TryPlace(block, 0, 0, -1) || TryPlace(block, -1, 0, 0) || TryPlace(block, 0, 0, 1)))
				{
					ConsumeFood(PortionsEatenForLay);
					attemptLayEggTotalHours = -1.0;
				}
			}
		}

		private bool TryPlace(Block block, int dx, int dy, int dz)
		{
			IBlockAccessor blockAccessor = entity.World.BlockAccessor;
			BlockPos blockPos = entity.ServerPos.XYZ.AsBlockPos.Add(dx, dy, dz);
			if (blockAccessor.GetBlock(blockPos, 2).IsLiquid())
			{
				return false;
			}
			if (!blockAccessor.GetBlock(blockPos).IsReplacableBy(block))
			{
				return false;
			}
			blockPos.Y--;
			if (blockAccessor.GetMostSolidBlock(blockPos).CanAttachBlockAt(blockAccessor, block, blockPos, BlockFacing.UP))
			{
				blockPos.Y++;
				blockAccessor.SetBlock(block.BlockId, blockPos);
				BlockEntityTransient obj = blockAccessor.GetBlockEntity(blockPos) as BlockEntityTransient;
				obj?.SetPlaceTime(entity.World.Calendar.TotalHours);
				if (obj != null && obj.IsDueTransition())
				{
					blockAccessor.SetBlock(0, blockPos);
				}
				return true;
			}
			return false;
		}

		private void MakeLaySound()
		{
			if (sound == null)
			{
				return;
			}
			if (soundStartMs > 0)
			{
				entity.World.RegisterCallback(delegate
				{
					entity.World.PlaySoundAt(sound, entity, null, randomizePitch: true, soundRange);
					lastSoundTotalMs = entity.World.ElapsedMilliseconds;
				}, soundStartMs);
			}
			else
			{
				entity.World.PlaySoundAt(sound, entity, null, randomizePitch: true, soundRange);
				lastSoundTotalMs = entity.World.ElapsedMilliseconds;
			}
		}
	}
	public enum EnumAttackPattern
	{
		DirectAttack,
		CircleTarget
	}
	public class AiTaskSeekEntity : AiTaskBaseTargetable
	{
		protected Vec3d targetPos;

		private readonly Vec3d ownPos = new Vec3d();

		protected float moveSpeed = 0.02f;

		protected float seekingRange = 25f;

		protected float belowTempSeekingRange = 25f;

		protected float belowTempThreshold = -999f;

		protected float maxFollowTime = 60f;

		protected bool stopNow;

		protected bool active;

		protected float currentFollowTime;

		protected bool alarmHerd;

		protected bool leapAtTarget;

		protected float leapHeightMul = 1f;

		protected string leapAnimationCode = "jump";

		protected float leapChance = 1f;

		protected EnumAttackPattern attackPattern;

		protected EnumAICreatureType? creatureType;

		protected long finishedMs;

		protected bool jumpAnimOn;

		protected long lastSearchTotalMs;

		protected long attackModeBeginTotalMs;

		protected long lastHurtByTargetTotalMs;

		protected float extraTargetDistance;

		protected bool lowTempRangeMode;

		protected bool revengeRangeMode;

		protected bool lastPathfindOk;

		protected int searchWaitMs = 4000;

		protected Vec3d lastGoalReachedPos;

		protected Dictionary<long, int> futilityCounters;

		private float executionChance;

		private long jumpedMS;

		private float lastPathUpdateSeconds;

		public float NowSeekRange { get; set; }

		protected bool RecentlyHurt => entity.World.ElapsedMilliseconds - lastHurtByTargetTotalMs < 10000;

		protected bool RemainInOffensiveMode => entity.World.ElapsedMilliseconds - attackModeBeginTotalMs < 20000;

		public AiTaskSeekEntity(EntityAgent entity, JsonObject taskConfig, JsonObject aiConfig)
			: base(entity, taskConfig, aiConfig)
		{
			base.Id = "seekentity";
			tamingGenerations = taskConfig["tamingGenerations"].AsFloat(10f);
			JsonObject jsonObject = taskConfig["leapAnimation"];
			leapAnimationCode = ((jsonObject.Token == null) ? "jump" : jsonObject.AsString());
			leapChance = taskConfig["leapChance"].AsFloat(1f);
			leapHeightMul = taskConfig["leapHeightMul"].AsFloat(1f);
			moveSpeed = taskConfig["movespeed"].AsFloat(0.02f);
			extraTargetDistance = taskConfig["extraTargetDistance"].AsFloat();
			seekingRange = taskConfig["seekingRange"].AsFloat(25f);
			belowTempSeekingRange = taskConfig["belowTempSeekingRange"].AsFloat(25f);
			belowTempThreshold = taskConfig["belowTempThreshold"].AsFloat(-999f);
			maxFollowTime = taskConfig["maxFollowTime"].AsFloat(60f);
			alarmHerd = taskConfig["alarmHerd"].AsBool();
			leapAtTarget = taskConfig["leapAtTarget"].AsBool();
			retaliateAttacks = taskConfig["retaliateAttacks"].AsBool(defaultValue: true);
			executionChance = taskConfig["executionChance"].AsFloat(0.1f);
			searchWaitMs = taskConfig["searchWaitMs"].AsInt(4000);
			if (taskConfig["aiCreatureType"].Exists)
			{
				creatureType = (EnumAICreatureType)taskConfig["aiCreatureType"].AsInt();
			}
		}

		public override bool ShouldExecute()
		{
			if (base.noEntityCodes && (attackedByEntity == null || !retaliateAttacks))
			{
				return false;
			}
			if (base.rand.NextDouble() > (double)executionChance && (WhenInEmotionState == null || !IsInEmotionState(WhenInEmotionState)) && !base.RecentlyAttacked)
			{
				return false;
			}
			if (!PreconditionsSatisifed())
			{
				return false;
			}
			if (WhenInEmotionState == null && base.rand.NextDouble() > 0.5)
			{
				return false;
			}
			if (lastSearchTotalMs + searchWaitMs > entity.World.ElapsedMilliseconds)
			{
				return false;
			}
			if (jumpAnimOn && entity.World.ElapsedMilliseconds - finishedMs > 2000)
			{
				entity.AnimManager.StopAnimation("jump");
			}
			if (cooldownUntilMs > entity.World.ElapsedMilliseconds && !base.RecentlyAttacked)
			{
				return false;
			}
			lastSearchTotalMs = entity.World.ElapsedMilliseconds;
			if (!base.RecentlyAttacked)
			{
				attackedByEntity = null;
				revengeRangeMode = false;
			}
			NowSeekRange = getSeekRange();
			if (retaliateAttacks && attackedByEntity != null && attackedByEntity.Alive && attackedByEntity.IsInteractable && IsTargetableEntity(attackedByEntity, NowSeekRange, ignoreEntityCode: true) && !entity.ToleratesDamageFrom(attackedByEntity))
			{
				targetEntity = attackedByEntity;
				targetPos = targetEntity.ServerPos.XYZ;
				revengeRangeMode = true;
				return true;
			}
			bool fullyTamed = (float)GetOwnGeneration() >= tamingGenerations;
			ownPos.SetWithDimension(entity.ServerPos);
			targetEntity = partitionUtil.GetNearestEntity(ownPos, NowSeekRange, (!noTags) ? ((ActionConsumable<Entity>)((Entity e) => (!fullyTamed || (!isNonAttackingPlayer(e) && !entity.ToleratesDamageFrom(attackedByEntity))) && IsTargetableEntityWithTags(e, NowSeekRange))) : ((targetEntityFirstLetters.Length == 0) ? ((ActionConsumable<Entity>)((Entity e) => (!fullyTamed || (!isNonAttackingPlayer(e) && !entity.ToleratesDamageFrom(attackedByEntity))) && IsTargetableEntityNoTagsAll(e, NowSeekRange))) : ((ActionConsumable<Entity>)((Entity e) => (!fullyTamed || (!isNonAttackingPlayer(e) && !entity.ToleratesDamageFrom(attackedByEntity))) && IsTargetableEntityNoTagsNoAll(e, NowSeekRange)))), EnumEntitySearchType.Creatures);
			if (targetEntity != null)
			{
				if (alarmHerd && entity.HerdId > 0)
				{
					entity.World.GetNearestEntity(ownPos, NowSeekRange, NowSeekRange, delegate(Entity e)
					{
						EntityAgent entityAgent = e as EntityAgent;
						if (e.EntityId != entity.EntityId && entityAgent != null && entityAgent.Alive && entityAgent.HerdId == entity.HerdId)
						{
							entityAgent.Notify("seekEntity", targetEntity);
						}
						return false;
					});
				}
				targetPos = targetEntity.ServerPos.XYZ;
				if (entity.ServerPos.SquareDistanceTo(targetPos) <= (double)MinDistanceToTarget())
				{
					return false;
				}
				return true;
			}
			return false;
		}

		protected float getSeekRange()
		{
			float num = seekingRange;
			if (belowTempThreshold > -99f && entity.World.BlockAccessor.GetClimateAt(entity.Pos.AsBlockPos, EnumGetClimateMode.ForSuppliedDate_TemperatureOnly, entity.World.Calendar.TotalDays).Temperature <= belowTempThreshold)
			{
				num = belowTempSeekingRange;
			}
			if (retaliateAttacks && attackedByEntity != null && attackedByEntity.Alive && attackedByEntity.IsInteractable && IsTargetableEntity(attackedByEntity, NowSeekRange * 1.5f, ignoreEntityCode: true) && !entity.ToleratesDamageFrom(attackedByEntity))
			{
				num *= 1.5f;
			}
			return num;
		}

		public float MinDistanceToTarget()
		{
			return extraTargetDistance + Math.Max(0.1f, targetEntity.SelectionBox.XSize / 2f + entity.SelectionBox.XSize / 2f);
		}

		public override void StartExecute()
		{
			stopNow = false;
			active = true;
			currentFollowTime = 0f;
			attackPattern = EnumAttackPattern.DirectAttack;
			int searchDepth = 3500;
			if (world.Rand.NextDouble() < 0.05)
			{
				searchDepth = 10000;
			}
			pathTraverser.NavigateTo_Async(targetPos.Clone(), moveSpeed, MinDistanceToTarget(), OnGoalReached, OnStuck, OnSeekUnable, searchDepth, 1, creatureType);
		}

		private void OnSeekUnable()
		{
			OnSiegeUnable();
		}

		private void OnSiegeUnable()
		{
			if (targetPos.DistanceTo(entity.ServerPos.XYZ) < NowSeekRange && !TryCircleTarget())
			{
				OnCircleTargetUnable();
			}
		}

		public void OnCircleTargetUnable()
		{
			entity.GetBehavior<EntityBehaviorTaskAI>().TaskManager.AllTasks.ForEach(delegate(IAiTask t)
			{
				(t as AiTaskFleeEntity)?.InstaFleeFrom(targetEntity);
			});
		}

		private bool TryCircleTarget()
		{
			targetPos.SquareDistanceTo(entity.Pos);
			int searchDepth = 3500;
			attackPattern = EnumAttackPattern.CircleTarget;
			lastPathfindOk = false;
			float num = (float)Math.Atan2(entity.ServerPos.X - targetPos.X, entity.ServerPos.Z - targetPos.Z);
			for (int i = 0; i < 3; i++)
			{
				double value = (double)num + 0.5 + world.Rand.NextDouble() / 2.0;
				double num2 = 4.0 + world.Rand.NextDouble() * 6.0;
				double x = GameMath.Sin(value) * num2;
				double z = GameMath.Cos(value) * num2;
				targetPos.Add(x, 0.0, z);
				int num3 = 0;
				bool flag = false;
				BlockPos blockPos = new BlockPos((int)targetPos.X, (int)targetPos.Y, (int)targetPos.Z);
				int num4 = 0;
				while (num3 < 5)
				{
					if (world.BlockAccessor.GetBlockBelow(blockPos, num4).SideSolid[BlockFacing.UP.Index] && !world.CollisionTester.IsColliding(world.BlockAccessor, entity.SelectionBox, new Vec3d((double)blockPos.X + 0.5, blockPos.Y - num4 + 1, (double)blockPos.Z + 0.5), alsoCheckTouch: false))
					{
						flag = true;
						targetPos.Y -= num4;
						targetPos.Y += 1.0;
						break;
					}
					if (world.BlockAccessor.GetBlockAbove(blockPos, num4).SideSolid[BlockFacing.UP.Index] && !world.CollisionTester.IsColliding(world.BlockAccessor, entity.SelectionBox, new Vec3d((double)blockPos.X + 0.5, blockPos.Y + num4 + 1, (double)blockPos.Z + 0.5), alsoCheckTouch: false))
					{
						flag = true;
						targetPos.Y += num4;
						targetPos.Y += 1.0;
						break;
					}
					num3++;
					num4++;
				}
				if (flag)
				{
					pathTraverser.NavigateTo_Async(targetPos.Clone(), moveSpeed, MinDistanceToTarget(), OnGoalReached, OnStuck, OnCircleTargetUnable, searchDepth, 1);
					return true;
				}
			}
			return false;
		}

		public override bool CanContinueExecute()
		{
			if (pathTraverser.Ready)
			{
				attackModeBeginTotalMs = entity.World.ElapsedMilliseconds;
				lastPathfindOk = true;
			}
			return pathTraverser.Ready;
		}

		private double getDistanceToTarget()
		{
			if (targetEntity == null)
			{
				return double.MaxValue;
			}
			Cuboidd cuboidd = targetEntity.SelectionBox.ToDouble().Translate(targetEntity.ServerPos.X, targetEntity.ServerPos.InternalY, targetEntity.ServerPos.Z);
			Vec3d vec = entity.ServerPos.XYZ.Add(0.0, entity.SelectionBox.Y2 / 2f, 0.0).Ahead(entity.SelectionBox.XSize / 2f, 0f, entity.ServerPos.Yaw);
			return cuboidd.ShortestDistanceFrom(vec);
		}

		public override bool ContinueExecute(float dt)
		{
			if (!IsInValidDayTimeHours(initialRandomness: false))
			{
				return false;
			}
			if (currentFollowTime == 0f && (!stopNow || world.Rand.NextDouble() < 0.25))
			{
				base.StartExecute();
			}
			currentFollowTime += dt;
			lastPathUpdateSeconds += dt;
			double distanceToTarget = getDistanceToTarget();
			if (attackPattern == EnumAttackPattern.DirectAttack && lastPathUpdateSeconds >= 0.75f && targetPos.SquareDistanceTo(targetEntity.ServerPos.X, targetEntity.ServerPos.InternalY, targetEntity.ServerPos.Z) >= 9f)
			{
				targetPos.Set(targetEntity.ServerPos.X + targetEntity.ServerPos.Motion.X * 10.0, targetEntity.ServerPos.InternalY, targetEntity.ServerPos.Z + targetEntity.ServerPos.Motion.Z * 10.0);
				pathTraverser.NavigateTo(targetPos, moveSpeed, MinDistanceToTarget(), OnGoalReached, OnStuck, null, giveUpWhenNoPath: false, 2000, 1);
				lastPathUpdateSeconds = 0f;
			}
			if (leapAtTarget && !entity.AnimManager.IsAnimationActive(animMeta.Code))
			{
				RunningAnimation animationState = entity.AnimManager.Animator.GetAnimationState(leapAnimationCode);
				if (animationState == null || !animationState.Active)
				{
					animMeta.EaseInSpeed = 1f;
					animMeta.EaseOutSpeed = 1f;
					entity.AnimManager.StartAnimation(animMeta);
				}
			}
			if (jumpAnimOn && entity.World.ElapsedMilliseconds - finishedMs > 2000)
			{
				entity.AnimManager.StopAnimation(leapAnimationCode);
				animMeta.EaseInSpeed = 1f;
				animMeta.EaseOutSpeed = 1f;
				entity.AnimManager.StartAnimation(animMeta);
			}
			if (attackPattern == EnumAttackPattern.DirectAttack)
			{
				pathTraverser.CurrentTarget.X = targetEntity.ServerPos.X;
				pathTraverser.CurrentTarget.Y = targetEntity.ServerPos.InternalY;
				pathTraverser.CurrentTarget.Z = targetEntity.ServerPos.Z;
			}
			EntityPlayer obj = targetEntity as EntityPlayer;
			bool flag = obj != null && obj.Player?.WorldData.CurrentGameMode == EnumGameMode.Creative;
			if (!flag && leapAtTarget && base.rand.NextDouble() < (double)leapChance)
			{
				bool flag2 = entity.World.ElapsedMilliseconds - jumpedMS < 3000;
				if (distanceToTarget > 0.5 && distanceToTarget < 4.0 && !flag2 && targetEntity.ServerPos.Y + 0.1 >= entity.ServerPos.Y)
				{
					double num = (targetEntity.ServerPos.X + targetEntity.ServerPos.Motion.X * 80.0 - entity.ServerPos.X) / 30.0;
					double num2 = (targetEntity.ServerPos.Z + targetEntity.ServerPos.Motion.Z * 80.0 - entity.ServerPos.Z) / 30.0;
					entity.ServerPos.Motion.Add(num, (double)leapHeightMul * GameMath.Max(0.13, (targetEntity.ServerPos.Y - entity.ServerPos.Y) / 30.0), num2);
					float yaw = (float)Math.Atan2(num, num2);
					entity.ServerPos.Yaw = yaw;
					jumpedMS = entity.World.ElapsedMilliseconds;
					finishedMs = entity.World.ElapsedMilliseconds;
					if (leapAnimationCode != null)
					{
						entity.AnimManager.StopAnimation("walk");
						entity.AnimManager.StopAnimation("run");
						entity.AnimManager.StartAnimation(new AnimationMetaData
						{
							Animation = leapAnimationCode,
							Code = leapAnimationCode
						}.Init());
						jumpAnimOn = true;
					}
				}
				if (flag2 && !entity.Collided && distanceToTarget < 0.5)
				{
					entity.ServerPos.Motion /= 2f;
				}
			}
			float num3 = MinDistanceToTarget();
			if (targetEntity.Alive && !stopNow && !flag && pathTraverser.Active && currentFollowTime < maxFollowTime && distanceToTarget < (double)NowSeekRange)
			{
				if (!(distanceToTarget > (double)num3))
				{
					if (targetEntity is EntityAgent entityAgent)
					{
						return entityAgent.ServerControls.TriesToMove;
					}
					return false;
				}
				return true;
			}
			return false;
		}

		public override void FinishExecute(bool cancelled)
		{
			base.FinishExecute(cancelled);
			finishedMs = entity.World.ElapsedMilliseconds;
			pathTraverser.Stop();
			active = false;
		}

		public override bool Notify(string key, object data)
		{
			if (key == "seekEntity")
			{
				targetEntity = (Entity)data;
				targetPos = targetEntity.ServerPos.XYZ;
				return true;
			}
			return false;
		}

		public override void OnEntityHurt(DamageSource source, float damage)
		{
			base.OnEntityHurt(source, damage);
			if (targetEntity != source.GetCauseEntity() && active)
			{
				return;
			}
			lastHurtByTargetTotalMs = entity.World.ElapsedMilliseconds;
			float num = ((source.GetCauseEntity() == null) ? 0f : ((float)source.GetCauseEntity().ServerPos.DistanceTo(entity.ServerPos)));
			float seekRange = getSeekRange();
			if (num > seekRange)
			{
				entity.GetBehavior<EntityBehaviorTaskAI>().TaskManager.AllTasks.ForEach(delegate(IAiTask t)
				{
					(t as AiTaskFleeEntity)?.InstaFleeFrom(targetEntity);
				});
			}
		}

		private void OnStuck()
		{
			stopNow = true;
		}

		private void OnGoalReached()
		{
			if (attackPattern != EnumAttackPattern.DirectAttack)
			{
				return;
			}
			if (lastGoalReachedPos != null && (double)lastGoalReachedPos.SquareDistanceTo(entity.Pos) < 0.001)
			{
				if (futilityCounters == null)
				{
					futilityCounters = new Dictionary<long, int>();
				}
				else
				{
					futilityCounters.TryGetValue(targetEntity.EntityId, out var value);
					value++;
					futilityCounters[targetEntity.EntityId] = value;
					if (value > 19)
					{
						return;
					}
				}
			}
			lastGoalReachedPos = new Vec3d(entity.Pos);
			pathTraverser.Retarget();
		}

		public override bool CanSense(Entity e, double range)
		{
			bool flag = base.CanSense(e, range);
			if (flag && futilityCounters != null && futilityCounters.TryGetValue(e.EntityId, out var value) && value > 0)
			{
				value -= 2;
				futilityCounters[e.EntityId] = value;
				return false;
			}
			return flag;
		}
	}
	internal class FailedAttempt
	{
		public long LastTryMs;

		public int Count;
	}
	public class AiTaskSeekFoodAndEat : AiTaskBase
	{
		private AssetLocation eatSound;

		private POIRegistry porregistry;

		private IAnimalFoodSource targetPoi;

		private float moveSpeed = 0.02f;

		private long stuckatMs;

		private bool nowStuck;

		private float eatTime = 1f;

		private float eatTimeNow;

		private bool soundPlayed;

		private bool doConsumePortion = true;

		private bool eatAnimStarted;

		private bool eatLooseItems;

		private float quantityEaten;

		private AnimationMetaData eatAnimMeta;

		private AnimationMetaData eatAnimMetaLooseItems;

		private Dictionary<IAnimalFoodSource, FailedAttempt> failedSeekTargets = new Dictionary<IAnimalFoodSource, FailedAttempt>();

		private float extraTargetDist;

		private long lastPOISearchTotalMs;

		public CreatureDiet Diet;

		private EntityBehaviorMultiplyBase bhMultiply;

		private ICoreAPI api;

		public AiTaskSeekFoodAndEat(EntityAgent entity, JsonObject taskConfig, JsonObject aiConfig)
			: base(entity, taskConfig, aiConfig)
		{
			api = entity.Api;
			porregistry = api.ModLoader.GetModSystem<POIRegistry>();
			entity.WatchedAttributes.SetBool("doesEat", value: true);
			string text = taskConfig["eatSound"].AsString();
			if (text != null)
			{
				eatSound = new AssetLocation(text).WithPathPrefix("sounds/");
			}
			moveSpeed = taskConfig["movespeed"].AsFloat(0.02f);
			eatTime = taskConfig["eatTime"].AsFloat(1.5f);
			doConsumePortion = taskConfig["doConsumePortion"].AsBool(defaultValue: true);
			eatLooseItems = taskConfig["eatLooseItems"].AsBool(defaultValue: true);
			Diet = entity.Properties.Attributes["creatureDiet"].AsObject<CreatureDiet>();
			if (Diet == null)
			{
				api.Logger.Warning("Creature " + entity.Code.ToShortString() + " has SeekFoodAndEat task but no Diet specified");
			}
			if (taskConfig["eatAnimation"].Exists)
			{
				eatAnimMeta = new AnimationMetaData
				{
					Code = taskConfig["eatAnimation"].AsString()?.ToLowerInvariant(),
					Animation = taskConfig["eatAnimation"].AsString()?.ToLowerInvariant(),
					AnimationSpeed = taskConfig["eatAnimationSpeed"].AsFloat(1f)
				}.Init();
			}
			if (taskConfig["eatAnimationLooseItems"].Exists)
			{
				eatAnimMetaLooseItems = new AnimationMetaData
				{
					Code = taskConfig["eatAnimationLooseItems"].AsString()?.ToLowerInvariant(),
					Animation = taskConfig["eatAnimationLooseItems"].AsString()?.ToLowerInvariant(),
					AnimationSpeed = taskConfig["eatAnimationSpeedLooseItems"].AsFloat(1f)
				}.Init();
			}
		}

		public override void AfterInitialize()
		{
			bhMultiply = entity.GetBehavior<EntityBehaviorMultiplyBase>();
		}

		public override bool ShouldExecute()
		{
			if (entity.World.Rand.NextDouble() < 0.005)
			{
				return false;
			}
			if (lastPOISearchTotalMs + 15000 > entity.World.ElapsedMilliseconds)
			{
				return false;
			}
			if (cooldownUntilMs > entity.World.ElapsedMilliseconds)
			{
				return false;
			}
			if (cooldownUntilTotalHours > entity.World.Calendar.TotalHours)
			{
				return false;
			}
			if (!PreconditionsSatisifed())
			{
				return false;
			}
			if (bhMultiply != null && !bhMultiply.ShouldEat && entity.World.Rand.NextDouble() < 0.996)
			{
				return false;
			}
			if (Diet == null)
			{
				return false;
			}
			targetPoi = null;
			extraTargetDist = 0f;
			lastPOISearchTotalMs = entity.World.ElapsedMilliseconds;
			if (eatLooseItems)
			{
				api.ModLoader.GetModSystem<EntityPartitioning>().WalkEntities(entity.ServerPos.XYZ, 10.0, delegate(Entity e)
				{
					if (e is EntityItem entityItem && suitableFoodSource(entityItem.Itemstack))
					{
						targetPoi = new LooseItemFoodSource(entityItem);
						return false;
					}
					return true;
				}, EnumEntitySearchType.Inanimate);
			}
			if (targetPoi == null)
			{
				targetPoi = porregistry.GetNearestPoi(entity.ServerPos.XYZ, 48f, delegate(IPointOfInterest poi)
				{
					if (poi.Type != "food")
					{
						return false;
					}
					IAnimalFoodSource key;
					IAnimalFoodSource animalFoodSource = (key = poi as IAnimalFoodSource);
					if (animalFoodSource != null && animalFoodSource.IsSuitableFor(entity, Diet))
					{
						failedSeekTargets.TryGetValue(key, out var value);
						if (value == null || value.Count < 4 || value.LastTryMs < world.ElapsedMilliseconds - 60000)
						{
							return true;
						}
					}
					return false;
				}) as IAnimalFoodSource;
			}
			return targetPoi != null;
		}

		private bool suitableFoodSource(ItemStack itemStack)
		{
			EnumFoodCategory foodSourceCategory = itemStack?.Collectible?.NutritionProps?.FoodCategory ?? EnumFoodCategory.NoNutrition;
			string[] foodSourceTags = itemStack?.ItemAttributes?["foodTags"].AsArray<string>() ?? Array.Empty<string>();
			return Diet.Matches(foodSourceCategory, foodSourceTags);
		}

		public float MinDistanceToTarget()
		{
			return Math.Max(extraTargetDist + 0.6f, entity.SelectionBox.XSize / 2f + 0.05f);
		}

		public override void StartExecute()
		{
			base.StartExecute();
			stuckatMs = -9999L;
			nowStuck = false;
			soundPlayed = false;
			eatTimeNow = 0f;
			pathTraverser.NavigateTo_Async(targetPoi.Position, moveSpeed, MinDistanceToTarget() - 0.1f, OnGoalReached, OnStuck, null, 1000, 1);
			eatAnimStarted = false;
		}

		public override bool CanContinueExecute()
		{
			return pathTraverser.Ready;
		}

		public override bool ContinueExecute(float dt)
		{
			if (!IsInValidDayTimeHours(initialRandomness: false))
			{
				return false;
			}
			Vec3d position = targetPoi.Position;
			pathTraverser.CurrentTarget.X = position.X;
			pathTraverser.CurrentTarget.Y = position.Y;
			pathTraverser.CurrentTarget.Z = position.Z;
			double num = entity.SelectionBox.ToDouble().Translate(entity.ServerPos.X, entity.ServerPos.Y, entity.ServerPos.Z).ShortestDistanceFrom(position);
			float num2 = MinDistanceToTarget();
			if (num <= (double)num2)
			{
				pathTraverser.Stop();
				if (animMeta != null)
				{
					entity.AnimManager.StopAnimation(animMeta.Code);
				}
				if (bhMultiply != null && !bhMultiply.ShouldEat)
				{
					return false;
				}
				if (!targetPoi.IsSuitableFor(entity, Diet))
				{
					return false;
				}
				if (eatAnimMeta != null && !eatAnimStarted)
				{
					entity.AnimManager.StartAnimation((targetPoi is LooseItemFoodSource && eatAnimMetaLooseItems != null) ? eatAnimMetaLooseItems : eatAnimMeta);
					eatAnimStarted = true;
				}
				eatTimeNow += dt;
				if (targetPoi is LooseItemFoodSource { ItemStack: not null } looseItemFoodSource)
				{
					entity.World.SpawnCubeParticles(targetPoi.Position, looseItemFoodSource.ItemStack, 0.25f, 1, 0.25f + 0.5f * (float)entity.World.Rand.NextDouble());
				}
				if (eatTimeNow > eatTime * 0.75f && !soundPlayed)
				{
					soundPlayed = true;
					if (eatSound != null)
					{
						entity.World.PlaySoundAt(eatSound, entity, null, randomizePitch: true, 16f);
					}
				}
				if (eatTimeNow >= eatTime)
				{
					ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("hunger");
					if (treeAttribute == null)
					{
						treeAttribute = (ITreeAttribute)(entity.WatchedAttributes["hunger"] = new TreeAttribute());
					}
					if (doConsumePortion)
					{
						float num3 = targetPoi.ConsumeOnePortion(entity);
						quantityEaten += num3;
						treeAttribute.SetFloat("saturation", num3 + treeAttribute.GetFloat("saturation"));
						entity.WatchedAttributes.SetDouble("lastMealEatenTotalHours", entity.World.Calendar.TotalHours);
						entity.WatchedAttributes.MarkPathDirty("hunger");
					}
					else
					{
						quantityEaten = 1f;
					}
					failedSeekTargets.Remove(targetPoi);
					return false;
				}
			}
			else if (!pathTraverser.Active)
			{
				float x = (float)entity.World.Rand.NextDouble() * 0.3f - 0.15f;
				float z = (float)entity.World.Rand.NextDouble() * 0.3f - 0.15f;
				if (!pathTraverser.NavigateTo(targetPoi.Position.AddCopy(x, 0f, z), moveSpeed, num2 - 0.15f, OnGoalReached, OnStuck, null, giveUpWhenNoPath: false, 500, 1))
				{
					return false;
				}
			}
			if (nowStuck && (float)entity.World.ElapsedMilliseconds > (float)stuckatMs + eatTime * 1000f)
			{
				return false;
			}
			return true;
		}

		public override void FinishExecute(bool cancelled)
		{
			EntityBehaviorMultiply behavior = entity.GetBehavior<EntityBehaviorMultiply>();
			if (behavior != null && behavior.PortionsLeftToEat > 0f && !behavior.IsPregnant)
			{
				cooldownUntilTotalHours += mincooldownHours + entity.World.Rand.NextDouble() * (maxcooldownHours - mincooldownHours);
			}
			else
			{
				cooldownUntilTotalHours = api.World.Calendar.TotalHours + mincooldownHours + entity.World.Rand.NextDouble() * (maxcooldownHours - mincooldownHours);
			}
			pathTraverser.Stop();
			if (eatAnimMeta != null)
			{
				entity.AnimManager.StopAnimation(eatAnimMeta.Code);
			}
			if (animMeta != null)
			{
				entity.AnimManager.StopAnimation(animMeta.Code);
			}
			if (cancelled)
			{
				cooldownUntilTotalHours = 0.0;
			}
			if (quantityEaten < 1f)
			{
				cooldownUntilTotalHours = 0.0;
			}
			else
			{
				quantityEaten = 0f;
			}
		}

		private void OnStuck()
		{
			stuckatMs = entity.World.ElapsedMilliseconds;
			nowStuck = true;
			failedSeekTargets.TryGetValue(targetPoi, out var value);
			if (value == null)
			{
				value = (failedSeekTargets[targetPoi] = new FailedAttempt());
			}
			value.Count++;
			value.LastTryMs = world.ElapsedMilliseconds;
		}

		private void OnGoalReached()
		{
			pathTraverser.Active = true;
			failedSeekTargets.Remove(targetPoi);
		}
	}
	public class PlayerPoi : IAnimalFoodSource, IPointOfInterest
	{
		private EntityPlayer plr;

		private Vec3d pos = new Vec3d();

		public Vec3d Position
		{
			get
			{
				pos.Set(plr.Pos.X, plr.Pos.Y, plr.Pos.Z);
				return pos;
			}
		}

		public string Type => "food";

		public PlayerPoi(EntityPlayer plr)
		{
			this.plr = plr;
		}

		public float ConsumeOnePortion(Entity entity)
		{
			return 0f;
		}

		public bool IsSuitableFor(Entity entity, CreatureDiet diet)
		{
			return false;
		}
	}
	public class LooseItemFoodSource : IAnimalFoodSource, IPointOfInterest
	{
		private EntityItem entity;

		public ItemStack ItemStack => entity.Itemstack;

		public Vec3d Position => entity.ServerPos.XYZ;

		public string Type => "food";

		public LooseItemFoodSource(EntityItem entity)
		{
			this.entity = entity;
		}

		public float ConsumeOnePortion(Entity entity)
		{
			this.entity.Itemstack.StackSize--;
			if (this.entity.Itemstack.StackSize <= 0)
			{
				this.entity.Die();
			}
			if (this.entity.Itemstack.StackSize < 0)
			{
				return 0f;
			}
			return 1f;
		}

		public bool IsSuitableFor(Entity entity, CreatureDiet diet)
		{
			return true;
		}
	}
	public class AiTaskStayCloseToEntity : AiTaskBase
	{
		protected Entity targetEntity;

		protected float moveSpeed = 0.03f;

		protected float range = 8f;

		protected float maxDistance = 3f;

		protected string entityCode;

		protected bool stuck;

		protected bool onlyIfLowerId;

		protected bool allowTeleport;

		protected float teleportAfterRange;

		protected int teleportToRange;

		public int TeleportMaxRange;

		public float minSeekSeconds = 3f;

		protected Vec3d targetOffset = new Vec3d();

		protected Vec3d initialTargetPos;

		public int allowTeleportCount;

		private float executingSeconds;

		private int stuckCounter;

		private long cooldownUntilTotalMs;

		public AiTaskStayCloseToEntity(EntityAgent entity, JsonObject taskConfig, JsonObject aiConfig)
			: base(entity, taskConfig, aiConfig)
		{
			moveSpeed = taskConfig["movespeed"].AsFloat(0.03f);
			range = taskConfig["searchRange"].AsFloat(8f);
			maxDistance = taskConfig["maxDistance"].AsFloat(3f);
			minSeekSeconds = taskConfig["minSeekSeconds"].AsFloat(3f);
			onlyIfLowerId = taskConfig["onlyIfLowerId"].AsBool();
			entityCode = taskConfig["entityCode"].AsString();
			allowTeleport = taskConfig["allowTeleport"].AsBool();
			teleportAfterRange = taskConfig["teleportAfterRange"].AsFloat(30f);
			teleportToRange = taskConfig["teleportToRange"].AsInt(1);
			TeleportMaxRange = taskConfig["teleportMaxRange"].AsInt(int.MaxValue);
		}

		public override bool ShouldExecute()
		{
			if (base.rand.NextDouble() > 0.009999999776482582)
			{
				return false;
			}
			if (stuckCounter > 3)
			{
				stuckCounter = 0;
				cooldownUntilTotalMs = entity.World.ElapsedMilliseconds + 60000;
			}
			if (entity.World.ElapsedMilliseconds < cooldownUntilMs)
			{
				return false;
			}
			if (targetEntity == null || !targetEntity.Alive)
			{
				if (onlyIfLowerId)
				{
					targetEntity = entity.World.GetNearestEntity(entity.ServerPos.XYZ, range, 2f, (Entity e) => e.EntityId < entity.EntityId && e.Code.Path.Equals(entityCode));
				}
				else
				{
					targetEntity = entity.World.GetNearestEntity(entity.ServerPos.XYZ, range, 2f, (Entity e) => e.Code.Path.Equals(entityCode));
				}
			}
			if (targetEntity != null && (!targetEntity.Alive || targetEntity.ShouldDespawn))
			{
				targetEntity = null;
			}
			if (targetEntity == null)
			{
				return false;
			}
			double x = targetEntity.ServerPos.X;
			double y = targetEntity.ServerPos.Y;
			double z = targetEntity.ServerPos.Z;
			return (double)entity.ServerPos.SquareDistanceTo(x, y, z) > (double)(maxDistance * maxDistance);
		}

		public override void StartExecute()
		{
			base.StartExecute();
			executingSeconds = 0f;
			initialTargetPos = targetEntity.ServerPos.XYZ;
			if (targetEntity.ServerPos.DistanceTo(entity.ServerPos) > (double)TeleportMaxRange)
			{
				stuck = true;
				return;
			}
			float xSize = targetEntity.SelectionBox.XSize;
			pathTraverser.NavigateTo_Async(targetEntity.ServerPos.XYZ, moveSpeed, xSize + 0.2f, OnGoalReached, OnStuck, OnNoPath, 1000, 1);
			targetOffset.Set(entity.World.Rand.NextDouble() * 2.0 - 1.0, 0.0, entity.World.Rand.NextDouble() * 2.0 - 1.0);
			stuck = false;
		}

		public override bool CanContinueExecute()
		{
			return pathTraverser.Ready;
		}

		public override bool ContinueExecute(float dt)
		{
			if (!IsInValidDayTimeHours(initialRandomness: false))
			{
				return false;
			}
			if (initialTargetPos.DistanceTo(targetEntity.ServerPos.XYZ) > 3f)
			{
				initialTargetPos = targetEntity.ServerPos.XYZ;
				pathTraverser.Retarget();
			}
			double x = targetEntity.ServerPos.X + targetOffset.X;
			double y = targetEntity.ServerPos.Y;
			double z = targetEntity.ServerPos.Z + targetOffset.Z;
			pathTraverser.CurrentTarget.X = x;
			pathTraverser.CurrentTarget.Y = y;
			pathTraverser.CurrentTarget.Z = z;
			float num = entity.ServerPos.SquareDistanceTo(x, y, z);
			if (num < 9f)
			{
				pathTraverser.Stop();
				return false;
			}
			if ((allowTeleport || allowTeleportCount > 0) && executingSeconds > 4f && (num > teleportAfterRange * teleportAfterRange || stuck) && entity.World.Rand.NextDouble() < 0.05)
			{
				tryTeleport();
			}
			executingSeconds += dt;
			if (stuck || !pathTraverser.Active)
			{
				return executingSeconds < minSeekSeconds;
			}
			return true;
		}

		private Vec3d findDecentTeleportPos()
		{
			IBlockAccessor blockAccessor = entity.World.BlockAccessor;
			Random random = entity.World.Rand;
			Vec3d vec3d = new Vec3d();
			BlockPos blockPos = new BlockPos();
			for (int i = teleportToRange; i < teleportToRange + 30; i++)
			{
				float num = GameMath.Clamp((float)i / 5f, 2f, 4.5f);
				double num2 = random.NextDouble() * 2.0 * (double)num - (double)num;
				double num3 = random.NextDouble() * 2.0 * (double)num - (double)num;
				for (int j = 0; j < 8; j++)
				{
					int num4 = (1 - j % 2 * 2) * (int)Math.Ceiling((float)j / 2f);
					vec3d.Set(targetEntity.ServerPos.X + num2, targetEntity.ServerPos.Y + (double)num4, targetEntity.ServerPos.Z + num3);
					blockPos.Set((int)vec3d.X, (int)vec3d.Y, (int)vec3d.Z);
					Block block = blockAccessor.GetBlock(blockPos);
					Cuboidf[] collisionBoxes = block.GetCollisionBoxes(blockAccessor, blockPos);
					if (collisionBoxes != null && collisionBoxes.Length != 0)
					{
						continue;
					}
					JsonObject attributes = block.Attributes;
					if (attributes != null && attributes["insideDamage"].AsInt() > 0)
					{
						continue;
					}
					blockPos.Set((int)vec3d.X, (int)vec3d.Y - 1, (int)vec3d.Z);
					Block block2 = blockAccessor.GetBlock(blockPos);
					collisionBoxes = block2.GetCollisionBoxes(blockAccessor, blockPos);
					if (collisionBoxes == null || collisionBoxes.Length == 0)
					{
						continue;
					}
					JsonObject attributes2 = block2.Attributes;
					if (attributes2 == null || attributes2["insideDamage"].AsInt() <= 0)
					{
						vec3d.Y = (float)((int)vec3d.Y - 1) + collisionBoxes.Max((Cuboidf c) => c.Y2);
						return vec3d;
					}
				}
			}
			return null;
		}

		protected void tryTeleport()
		{
			if ((!allowTeleport && allowTeleportCount <= 0) || targetEntity == null)
			{
				return;
			}
			Vec3d vec3d = findDecentTeleportPos();
			if (vec3d != null)
			{
				entity.TeleportToDouble(vec3d.X, vec3d.Y, vec3d.Z, delegate
				{
					initialTargetPos = targetEntity.ServerPos.XYZ;
					pathTraverser.Retarget();
					allowTeleportCount = Math.Max(0, allowTeleportCount - 1);
				});
			}
		}

		public override void FinishExecute(bool cancelled)
		{
			if (stuck)
			{
				stuckCounter++;
			}
			else
			{
				stuckCounter = 0;
			}
			base.FinishExecute(cancelled);
		}

		protected void OnStuck()
		{
			stuck = true;
		}

		public void OnNoPath()
		{
		}

		protected virtual void OnGoalReached()
		{
		}
	}
	public class AiTaskUseInventory : AiTaskBase
	{
		protected AssetLocation useSound;

		protected float useTime = 1f;

		protected float useTimeNow;

		protected bool soundPlayed;

		protected bool doConsumePortion = true;

		protected HashSet<EnumFoodCategory> eatItemCategories = new HashSet<EnumFoodCategory>();

		protected HashSet<AssetLocation> eatItemCodes = new HashSet<AssetLocation>();

		protected bool isEdible;

		public AiTaskUseInventory(EntityAgent entity, JsonObject taskConfig, JsonObject aiConfig)
			: base(entity, taskConfig, aiConfig)
		{
			JsonObject jsonObject = taskConfig["useSound"];
			if (jsonObject.Exists)
			{
				string text = jsonObject.AsString();
				if (text != null)
				{
					useSound = new AssetLocation(text).WithPathPrefix("sounds/");
				}
			}
			useTime = taskConfig["useTime"].AsFloat(1.5f);
			EnumFoodCategory[] array = taskConfig["eatItemCategories"].AsArray(Array.Empty<EnumFoodCategory>());
			foreach (EnumFoodCategory item in array)
			{
				eatItemCategories.Add(item);
			}
			AssetLocation[] array2 = taskConfig["eatItemCodes"].AsArray(Array.Empty<AssetLocation>());
			foreach (AssetLocation item2 in array2)
			{
				eatItemCodes.Add(item2);
			}
		}

		public override bool ShouldExecute()
		{
			if (entity.World.Rand.NextDouble() < 0.005)
			{
				return false;
			}
			if (cooldownUntilMs > entity.World.ElapsedMilliseconds)
			{
				return false;
			}
			if (cooldownUntilTotalHours > entity.World.Calendar.TotalHours)
			{
				return false;
			}
			if (!PreconditionsSatisifed())
			{
				return false;
			}
			EntityBehaviorMultiplyBase behavior = entity.GetBehavior<EntityBehaviorMultiplyBase>();
			if (behavior != null && !behavior.ShouldEat && entity.World.Rand.NextDouble() < 0.996)
			{
				return false;
			}
			ItemSlot leftHandItemSlot = entity.LeftHandItemSlot;
			if (leftHandItemSlot.Empty)
			{
				return false;
			}
			isEdible = false;
			EnumFoodCategory? enumFoodCategory = leftHandItemSlot.Itemstack.Collectible?.NutritionProps?.FoodCategory;
			if (enumFoodCategory.HasValue && eatItemCategories.Contains(enumFoodCategory.Value))
			{
				isEdible = true;
				return true;
			}
			AssetLocation assetLocation = leftHandItemSlot.Itemstack?.Collectible?.Code;
			if (assetLocation != null && eatItemCodes.Contains(assetLocation))
			{
				isEdible = true;
				return true;
			}
			if (!leftHandItemSlot.Empty)
			{
				entity.World.SpawnItemEntity(leftHandItemSlot.TakeOutWhole(), entity.ServerPos.XYZ);
			}
			return false;
		}

		public override void StartExecute()
		{
			base.StartExecute();
			soundPlayed = false;
			useTimeNow = 0f;
		}

		public override bool ContinueExecute(float dt)
		{
			if (!IsInValidDayTimeHours(initialRandomness: false))
			{
				return false;
			}
			useTimeNow += dt;
			if (useTimeNow > useTime * 0.75f && !soundPlayed)
			{
				soundPlayed = true;
				if (useSound != null)
				{
					entity.World.PlaySoundAt(useSound, entity, null, randomizePitch: true, 16f);
				}
			}
			if (entity.LeftHandItemSlot == null || entity.LeftHandItemSlot.Empty)
			{
				return false;
			}
			entity.World.SpawnCubeParticles(entity.ServerPos.XYZ, entity.LeftHandItemSlot.Itemstack, 0.25f, 1, 0.25f + 0.5f * (float)entity.World.Rand.NextDouble());
			if (useTimeNow >= useTime)
			{
				if (isEdible)
				{
					ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("hunger");
					if (treeAttribute == null)
					{
						treeAttribute = (ITreeAttribute)(entity.WatchedAttributes["hunger"] = new TreeAttribute());
					}
					if (doConsumePortion)
					{
						float num = 1f;
						treeAttribute.SetFloat("saturation", num + treeAttribute.GetFloat("saturation"));
					}
				}
				entity.LeftHandItemSlot.TakeOut(1);
				return false;
			}
			return true;
		}

		public override void FinishExecute(bool cancelled)
		{
			base.FinishExecute(cancelled);
			if (cancelled)
			{
				cooldownUntilTotalHours = 0.0;
			}
		}
	}
	public class AiTaskWander : AiTaskBase
	{
		public Vec3d MainTarget;

		private bool done;

		private float moveSpeed = 0.03f;

		private float wanderChance = 0.02f;

		private float maxHeight = 7f;

		private float? preferredLightLevel;

		private float targetDistance = 0.12f;

		private NatFloat wanderRangeHorizontal = NatFloat.createStrongerInvexp(3f, 40f);

		private NatFloat wanderRangeVertical = NatFloat.createStrongerInvexp(3f, 10f);

		public bool StayCloseToSpawn;

		public Vec3d SpawnPosition;

		public double MaxDistanceToSpawn;

		private long lastTimeInRangeMs;

		private int failedWanders;

		private bool needsToTele;

		private float tryStartAnimAgain = 0.1f;

		public float WanderRangeMul
		{
			get
			{
				return entity.Attributes.GetFloat("wanderRangeMul", 1f);
			}
			set
			{
				entity.Attributes.SetFloat("wanderRangeMul", value);
			}
		}

		public int FailedConsecutivePathfinds
		{
			get
			{
				return entity.Attributes.GetInt("failedConsecutivePathfinds");
			}
			set
			{
				entity.Attributes.SetInt("failedConsecutivePathfinds", value);
			}
		}

		public AiTaskWander(EntityAgent entity, JsonObject taskConfig, JsonObject aiConfig)
			: base(entity, taskConfig, aiConfig)
		{
			float num = 3f;
			float num2 = 30f;
			if (taskConfig["maxDistanceToSpawn"].Exists)
			{
				StayCloseToSpawn = true;
				MaxDistanceToSpawn = taskConfig["maxDistanceToSpawn"].AsDouble(10.0);
				SpawnPosition = new Vec3d(entity.Attributes.GetDouble("spawnX"), entity.Attributes.GetDouble("spawnY"), entity.Attributes.GetDouble("spawnZ"));
				BlockPos blockPos = entity.WatchedAttributes.GetBlockPos("importOffset");
				if (blockPos != null)
				{
					SpawnPosition.Add(blockPos);
				}
			}
			targetDistance = taskConfig["targetDistance"].AsFloat(0.12f);
			moveSpeed = taskConfig["movespeed"].AsFloat(0.03f);
			wanderChance = taskConfig["wanderChance"].AsFloat(0.02f);
			num = taskConfig["wanderRangeMin"].AsFloat(3f);
			num2 = taskConfig["wanderRangeMax"].AsFloat(30f);
			wanderRangeHorizontal = NatFloat.createInvexp(num, num2);
			maxHeight = taskConfig["maxHeight"].AsFloat(7f);
			preferredLightLevel = taskConfig["preferredLightLevel"].AsFloat(-99f);
			if (preferredLightLevel < 0f)
			{
				preferredLightLevel = null;
			}
		}

		public override void OnEntityLoaded()
		{
			if (StayCloseToSpawn && (SpawnPosition == null || (SpawnPosition.X == 0.0 && SpawnPosition.Z == 0.0) || !entity.Attributes.HasAttribute("spawnX")))
			{
				OnEntitySpawn();
			}
		}

		public override void OnEntitySpawn()
		{
			entity.Attributes.SetDouble("spawnX", entity.ServerPos.X);
			entity.Attributes.SetDouble("spawnY", entity.ServerPos.Y);
			entity.Attributes.SetDouble("spawnZ", entity.ServerPos.Z);
			SpawnPosition = entity.ServerPos.XYZ;
		}

		public Vec3d loadNextWanderTarget()
		{
			EnumHabitat habitat = entity.Properties.Habitat;
			int num = 9;
			Vec4d vec4d = null;
			Vec4d vec4d2 = new Vec4d();
			BlockPos blockPos = new BlockPos(entity.Pos.Dimension);
			if (FailedConsecutivePathfinds > 10)
			{
				WanderRangeMul = Math.Max(0.1f, WanderRangeMul * 0.9f);
			}
			else
			{
				WanderRangeMul = Math.Min(1f, WanderRangeMul * 1.1f);
				if (base.rand.NextDouble() < 0.05)
				{
					WanderRangeMul = Math.Min(1f, WanderRangeMul * 1.5f);
				}
			}
			float num2 = WanderRangeMul;
			if (base.rand.NextDouble() < 0.05)
			{
				num2 *= 3f;
			}
			while (num-- > 0)
			{
				double num3 = wanderRangeHorizontal.nextFloat() * (float)(base.rand.Next(2) * 2 - 1) * num2;
				double num4 = wanderRangeVertical.nextFloat() * (float)(base.rand.Next(2) * 2 - 1) * num2;
				double num5 = wanderRangeHorizontal.nextFloat() * (float)(base.rand.Next(2) * 2 - 1) * num2;
				vec4d2.X = entity.ServerPos.X + num3;
				vec4d2.Y = entity.ServerPos.InternalY + num4;
				vec4d2.Z = entity.ServerPos.Z + num5;
				vec4d2.W = 1.0;
				if (StayCloseToSpawn)
				{
					double num6 = (double)vec4d2.SquareDistanceTo(SpawnPosition) / (MaxDistanceToSpawn * MaxDistanceToSpawn);
					vec4d2.W = 1.0 - num6;
				}
				switch (habitat)
				{
				case EnumHabitat.Air:
				{
					int rainMapHeightAt = world.BlockAccessor.GetRainMapHeightAt((int)vec4d2.X, (int)vec4d2.Z);
					vec4d2.Y = Math.Min(vec4d2.Y, (float)rainMapHeightAt + maxHeight);
					if (entity.World.BlockAccessor.GetBlockRaw((int)vec4d2.X, (int)vec4d2.Y, (int)vec4d2.Z, 2).IsLiquid())
					{
						vec4d2.W = 0.0;
					}
					break;
				}
				case EnumHabitat.Land:
				{
					vec4d2.Y = moveDownToFloor((int)vec4d2.X, vec4d2.Y, (int)vec4d2.Z);
					if (vec4d2.Y < 0.0)
					{
						vec4d2.W = 0.0;
						break;
					}
					if (entity.World.BlockAccessor.GetBlockRaw((int)vec4d2.X, (int)vec4d2.Y, (int)vec4d2.Z, 2).IsLiquid())
					{
						vec4d2.W /= 2.0;
					}
					bool stop = false;
					bool willFall = false;
					float yaw = (float)Math.Atan2(num3, num5) + (float)Math.PI / 2f;
					Vec3d vec3d = vec4d2.XYZ.Ahead(1.0, 0f, yaw);
					Vec3d vec3d2 = entity.ServerPos.XYZ.Ahead(1.0, 0f, yaw);
					int prevY = (int)vec3d2.Y;
					GameMath.BresenHamPlotLine2d((int)vec3d2.X, (int)vec3d2.Z, (int)vec3d.X, (int)vec3d.Z, delegate(int x, int z)
					{
						if (!stop)
						{
							double num8 = moveDownToFloor(x, prevY, z);
							if (num8 < 0.0 || (double)prevY - num8 > 4.0)
							{
								willFall = true;
								stop = true;
							}
							if (num8 - (double)prevY > 2.0)
							{
								stop = true;
							}
							prevY = (int)num8;
						}
					});
					if (willFall)
					{
						vec4d2.W = 0.0;
					}
					break;
				}
				case EnumHabitat.Sea:
					if (!entity.World.BlockAccessor.GetBlockRaw((int)vec4d2.X, (int)vec4d2.Y, (int)vec4d2.Z, 2).IsLiquid())
					{
						vec4d2.W = 0.0;
					}
					break;
				case EnumHabitat.Underwater:
					if (!entity.World.BlockAccessor.GetBlockRaw((int)vec4d2.X, (int)vec4d2.Y, (int)vec4d2.Z, 2).IsLiquid())
					{
						vec4d2.W = 0.0;
					}
					else
					{
						vec4d2.W = 1.0 / (Math.Abs(num4) + 1.0);
					}
					break;
				}
				if (vec4d2.W > 0.0)
				{
					for (int num7 = 0; num7 < BlockFacing.HORIZONTALS.Length; num7++)
					{
						BlockFacing blockFacing = BlockFacing.HORIZONTALS[num7];
						if (entity.World.BlockAccessor.IsSideSolid((int)vec4d2.X + blockFacing.Normali.X, (int)vec4d2.Y, (int)vec4d2.Z + blockFacing.Normali.Z, blockFacing.Opposite))
						{
							vec4d2.W *= 0.5;
						}
					}
				}
				if (preferredLightLevel.HasValue && vec4d2.W != 0.0)
				{
					blockPos.Set((int)vec4d2.X, (int)vec4d2.Y, (int)vec4d2.Z);
					int val = Math.Abs((int)preferredLightLevel.Value - entity.World.BlockAccessor.GetLightLevel(blockPos, EnumLightLevelType.MaxLight));
					vec4d2.W /= Math.Max(1, val);
				}
				if (vec4d == null || vec4d2.W > vec4d.W)
				{
					vec4d = new Vec4d(vec4d2.X, vec4d2.Y, vec4d2.Z, vec4d2.W);
					if (vec4d2.W >= 1.0)
					{
						break;
					}
				}
			}
			if (vec4d.W > 0.0)
			{
				FailedConsecutivePathfinds = Math.Max(FailedConsecutivePathfinds - 3, 0);
				return vec4d.XYZ;
			}
			FailedConsecutivePathfinds++;
			return null;
		}

		private double moveDownToFloor(int x, double y, int z)
		{
			int num = 5;
			while (num-- > 0)
			{
				if (world.BlockAccessor.IsSideSolid(x, (int)y, z, BlockFacing.UP))
				{
					return y + 1.0;
				}
				y -= 1.0;
			}
			return -1.0;
		}

		public override bool ShouldExecute()
		{
			if (base.rand.NextDouble() > (double)((failedWanders > 0) ? (1f - wanderChance * 4f * (float)failedWanders) : wanderChance))
			{
				failedWanders = 0;
				return false;
			}
			needsToTele = false;
			if (StayCloseToSpawn)
			{
				double num = entity.ServerPos.XYZ.SquareDistanceTo(SpawnPosition);
				long elapsedMilliseconds = entity.World.ElapsedMilliseconds;
				if (num > MaxDistanceToSpawn * MaxDistanceToSpawn)
				{
					if (elapsedMilliseconds - lastTimeInRangeMs > 120000 && entity.World.GetNearestEntity(entity.ServerPos.XYZ, 15f, 15f, (Entity e) => e is EntityPlayer) == null)
					{
						needsToTele = true;
					}
					MainTarget = SpawnPosition.Clone();
					return true;
				}
				lastTimeInRangeMs = elapsedMilliseconds;
			}
			MainTarget = loadNextWanderTarget();
			return MainTarget != null;
		}

		public override void StartExecute()
		{
			base.StartExecute();
			if (needsToTele && StayCloseToSpawn)
			{
				entity.TeleportTo(SpawnPosition);
				done = true;
			}
			else
			{
				done = false;
				pathTraverser.WalkTowards(MainTarget, moveSpeed, targetDistance, OnGoalReached, OnStuck);
				tryStartAnimAgain = 0.1f;
			}
		}

		public override bool ContinueExecute(float dt)
		{
			base.ContinueExecute(dt);
			if (!IsInValidDayTimeHours(initialRandomness: false))
			{
				return false;
			}
			if (animMeta != null && tryStartAnimAgain > 0f && (tryStartAnimAgain -= dt) <= 0f)
			{
				entity.AnimManager.StartAnimation(animMeta);
			}
			if (entity.Controls.IsClimbing && entity.Properties.CanClimbAnywhere && entity.ClimbingIntoFace != null)
			{
				BlockFacing climbingIntoFace = entity.ClimbingIntoFace;
				if (Math.Sign(climbingIntoFace.Normali.X) == Math.Sign(pathTraverser.CurrentTarget.X - entity.ServerPos.X))
				{
					pathTraverser.CurrentTarget.X = entity.ServerPos.X;
				}
				if (Math.Sign(climbingIntoFace.Normali.Y) == Math.Sign(pathTraverser.CurrentTarget.Y - entity.ServerPos.Y))
				{
					pathTraverser.CurrentTarget.Y = entity.ServerPos.Y;
				}
				if (Math.Sign(climbingIntoFace.Normali.Z) == Math.Sign(pathTraverser.CurrentTarget.Z - entity.ServerPos.Z))
				{
					pathTraverser.CurrentTarget.Z = entity.ServerPos.Z;
				}
			}
			if ((double)MainTarget.HorizontalSquareDistanceTo(entity.ServerPos.X, entity.ServerPos.Z) < 0.5)
			{
				pathTraverser.Stop();
				return false;
			}
			return !done;
		}

		public override void FinishExecute(bool cancelled)
		{
			base.FinishExecute(cancelled);
			if (cancelled)
			{
				pathTraverser.Stop();
			}
		}

		private void OnStuck()
		{
			done = true;
			failedWanders++;
		}

		private void OnGoalReached()
		{
			done = true;
			failedWanders = 0;
		}
	}
	public class AiTaskJealousMeleeAttack : AiTaskMeleeAttack
