			WanderRangeVertical = new NatFloat(wanderVerticalRangeMin, wanderVerticalRangeMax, EnumDistribution.INVEXP);
			StayCloseToSpawn = MaxDistanceToSpawn > 0.0;
			IgnoreLightLevel = PreferredLightLevel < 0;
		}
	}
	public class AiTaskWanderR : AiTaskBaseR
	{
		protected int failedWanders;

		protected long lastTimeInRangeMs;

		protected bool spawnPositionSet;

		protected Vec3d mainTarget = new Vec3d();

		protected Vec3d spawnPosition = new Vec3d();

		protected bool needsToTeleport;

		private readonly Vec4d bestTarget = new Vec4d();

		private readonly Vec4d currentTarget = new Vec4d();

		private readonly BlockPos blockPosBuffer = new BlockPos(0);

		private AiTaskWanderConfig Config => GetConfig<AiTaskWanderConfig>();

		protected float WanderRangeMul
		{
			get
			{
				return entity.Attributes.GetFloat("wanderRangeMul", 1f);
			}
			set
			{
				entity.Attributes.SetFloat("wanderRangeMul", value);
			}
		}

		protected int FailedConsecutivePathfinds
		{
			get
			{
				return entity.Attributes.GetInt("failedConsecutivePathfinds");
			}
			set
			{
				entity.Attributes.SetInt("failedConsecutivePathfinds", value);
			}
		}

		public AiTaskWanderR(EntityAgent entity, JsonObject taskConfig, JsonObject aiConfig)
			: base(entity, taskConfig, aiConfig)
		{
			baseConfig = AiTaskBaseR.LoadConfig<AiTaskWanderConfig>(entity, taskConfig, aiConfig);
			spawnPosition = new Vec3d(entity.Attributes.GetDouble("spawnX"), entity.Attributes.GetDouble("spawnY"), entity.Attributes.GetDouble("spawnZ"));
		}

		public override bool ShouldExecute()
		{
			if (!PreconditionsSatisficed())
			{
				return false;
			}
			failedWanders = 0;
			needsToTeleport = false;
			if (!Config.StayCloseToSpawn)
			{
				return LoadNextWanderTarget();
			}
			long elapsedMilliseconds = entity.World.ElapsedMilliseconds;
			if ((double)entity.ServerPos.XYZ.SquareDistanceTo(spawnPosition.X, spawnPosition.Y, spawnPosition.Z) <= Config.MaxDistanceToSpawn * Config.MaxDistanceToSpawn)
			{
				lastTimeInRangeMs = elapsedMilliseconds;
				return false;
			}
			if (elapsedMilliseconds - lastTimeInRangeMs > Config.TeleportToSpawnTimeout && entity.World.GetNearestEntity(entity.ServerPos.XYZ, Config.NoPlayersRange, Config.NoPlayersRange, (Entity target) => target is EntityPlayer) == null)
			{
				needsToTeleport = true;
			}
			mainTarget = spawnPosition;
			return true;
		}

		public override void StartExecute()
		{
			base.StartExecute();
			if (needsToTeleport)
			{
				entity.TeleportTo((int)spawnPosition.X, (int)spawnPosition.Y, (int)spawnPosition.Z);
				stopTask = true;
			}
			else
			{
				pathTraverser.WalkTowards(mainTarget, Config.MoveSpeed, Config.MinDistanceToTarget, OnGoalReached, OnStuck);
			}
		}

		public override bool ContinueExecute(float dt)
		{
			if (!base.ContinueExecute(dt))
			{
				return false;
			}
			if (entity.Controls.IsClimbing && entity.Properties.CanClimbAnywhere && entity.ClimbingIntoFace != null)
			{
				BlockFacing climbingIntoFace = entity.ClimbingIntoFace;
				if (Math.Sign(climbingIntoFace.Normali.X) == Math.Sign(pathTraverser.CurrentTarget.X - entity.ServerPos.X))
				{
					pathTraverser.CurrentTarget.X = entity.ServerPos.X;
				}
				if (Math.Sign(climbingIntoFace.Normali.Y) == Math.Sign(pathTraverser.CurrentTarget.Y - entity.ServerPos.Y))
				{
					pathTraverser.CurrentTarget.Y = entity.ServerPos.Y;
				}
				if (Math.Sign(climbingIntoFace.Normali.Z) == Math.Sign(pathTraverser.CurrentTarget.Z - entity.ServerPos.Z))
				{
					pathTraverser.CurrentTarget.Z = entity.ServerPos.Z;
				}
			}
			if ((double)mainTarget.HorizontalSquareDistanceTo(entity.ServerPos.X, entity.ServerPos.Z) < 0.5)
			{
				pathTraverser.Stop();
				return false;
			}
			return true;
		}

		public override void FinishExecute(bool cancelled)
		{
			base.FinishExecute(cancelled);
			if (cancelled)
			{
				pathTraverser.Stop();
			}
		}

		public override void OnEntityLoaded()
		{
			if (!entity.Attributes.HasAttribute("spawnX"))
			{
				OnEntitySpawn();
			}
		}

		public override void OnEntitySpawn()
		{
			entity.Attributes.SetDouble("spawnX", entity.ServerPos.X);
			entity.Attributes.SetDouble("spawnY", entity.ServerPos.Y);
			entity.Attributes.SetDouble("spawnZ", entity.ServerPos.Z);
			spawnPosition.Set(entity.ServerPos.XYZ);
		}

		protected override bool CheckExecutionChance()
		{
			return base.Rand.NextDouble() <= (double)((failedWanders > 0) ? (1f - Config.ExecutionChance * 4f * (float)failedWanders) : Config.ExecutionChance);
		}

		protected virtual bool LoadNextWanderTarget()
		{
			EnumHabitat habitat = entity.Properties.Habitat;
			bool flag = false;
			if (FailedConsecutivePathfinds > 10)
			{
				WanderRangeMul = Math.Max(0.1f, WanderRangeMul * 0.9f);
			}
			else
			{
				WanderRangeMul = Math.Min(1f, WanderRangeMul * 1.1f);
				if (Config.DoRandomWanderRangeChanges && base.Rand.NextDouble() < 0.05)
				{
					WanderRangeMul = Math.Min(1f, WanderRangeMul * 1.5f);
				}
			}
			float num = WanderRangeMul;
			if (Config.DoRandomWanderRangeChanges && base.Rand.NextDouble() < 0.05)
			{
				num *= 3f;
			}
			for (int i = 0; i < Config.MaxBlocksChecked; i++)
			{
				double num2 = Config.WanderRangeHorizontal.nextFloat() * (float)(base.Rand.Next(2) * 2 - 1) * num;
				double num3 = Config.WanderRangeVertical.nextFloat() * (float)(base.Rand.Next(2) * 2 - 1) * num;
				double num4 = Config.WanderRangeHorizontal.nextFloat() * (float)(base.Rand.Next(2) * 2 - 1) * num;
				currentTarget.X = entity.ServerPos.X + num2;
				currentTarget.Y = entity.ServerPos.InternalY + num3;
				currentTarget.Z = entity.ServerPos.Z + num4;
				currentTarget.W = 1.0;
				if (Config.StayCloseToSpawn)
				{
					double num5 = (double)currentTarget.SquareDistanceTo(spawnPosition) / (Config.MaxDistanceToSpawn * Config.MaxDistanceToSpawn);
					currentTarget.W = 1.0 - num5;
				}
				switch (habitat)
				{
				case EnumHabitat.Air:
				{
					int rainMapHeightAt = world.BlockAccessor.GetRainMapHeightAt((int)currentTarget.X, (int)currentTarget.Z);
					currentTarget.Y = Math.Min(currentTarget.Y, (float)rainMapHeightAt + Config.MaxHeight);
					if (entity.World.BlockAccessor.GetBlockRaw((int)currentTarget.X, (int)currentTarget.Y, (int)currentTarget.Z, 2).IsLiquid())
					{
						currentTarget.W = 0.0;
					}
					break;
				}
				case EnumHabitat.Land:
				{
					currentTarget.Y = MoveDownToFloor((int)currentTarget.X, currentTarget.Y, (int)currentTarget.Z);
					if (currentTarget.Y < 0.0)
					{
						currentTarget.W = 0.0;
						break;
					}
					if (entity.World.BlockAccessor.GetBlockRaw((int)currentTarget.X, (int)currentTarget.Y, (int)currentTarget.Z, 2).IsLiquid())
					{
						currentTarget.W /= 2.0;
					}
					bool stop = false;
					bool willFall = false;
					float yaw = (float)Math.Atan2(num2, num4) + (float)Math.PI / 2f;
					Vec3d vec3d = new Vec3d(currentTarget.X, currentTarget.Y, currentTarget.Z).Ahead(1.0, 0f, yaw);
					Vec3d vec3d2 = new Vec3d(entity.ServerPos.X, entity.ServerPos.Y, entity.ServerPos.Z).Ahead(1.0, 0f, yaw);
					int prevY = (int)vec3d2.Y;
					GameMath.BresenHamPlotLine2d((int)vec3d2.X, (int)vec3d2.Z, (int)vec3d.X, (int)vec3d.Z, delegate(int x, int z)
					{
						if (!stop)
						{
							double num7 = MoveDownToFloor(x, prevY, z);
							if (num7 < 0.0 || (double)prevY - num7 > 4.0)
							{
								willFall = true;
								stop = true;
							}
							if (num7 - (double)prevY > 2.0)
							{
								stop = true;
							}
							prevY = (int)num7;
						}
					});
					if (willFall)
					{
						currentTarget.W = 0.0;
					}
					break;
				}
				case EnumHabitat.Sea:
					if (!entity.World.BlockAccessor.GetBlockRaw((int)currentTarget.X, (int)currentTarget.Y, (int)currentTarget.Z, 2).IsLiquid())
					{
						currentTarget.W = 0.0;
					}
					break;
				case EnumHabitat.Underwater:
					if (!entity.World.BlockAccessor.GetBlockRaw((int)currentTarget.X, (int)currentTarget.Y, (int)currentTarget.Z, 2).IsLiquid())
					{
						currentTarget.W = 0.0;
					}
					else
					{
						currentTarget.W = 1.0 / (Math.Abs(num3) + 1.0);
					}
					break;
				}
				if (currentTarget.W > 0.0)
				{
					for (int num6 = 0; num6 < BlockFacing.HORIZONTALS.Length; num6++)
					{
						if (entity.World.BlockAccessor.IsSideSolid((int)currentTarget.X + BlockFacing.HORIZONTALS[num6].Normali.X, (int)currentTarget.Y, (int)currentTarget.Z + BlockFacing.HORIZONTALS[num6].Normali.Z, BlockFacing.HORIZONTALS[num6].Opposite))
						{
							currentTarget.W *= 0.5;
						}
					}
				}
				if (!Config.IgnoreLightLevel && currentTarget.W != 0.0)
				{
					blockPosBuffer.Set((int)currentTarget.X, (int)currentTarget.Y, (int)currentTarget.Z);
					int val = Math.Abs(Config.PreferredLightLevel - entity.World.BlockAccessor.GetLightLevel(blockPosBuffer, Config.PreferredLightLevelType));
					currentTarget.W /= Math.Max(1, val);
				}
				if (!flag || currentTarget.W > bestTarget.W)
				{
					flag = true;
					bestTarget.Set(currentTarget.X, currentTarget.Y, currentTarget.Z, currentTarget.W);
					if (currentTarget.W >= 1.0)
					{
						break;
					}
				}
			}
			if (bestTarget.W > 0.0)
			{
				FailedConsecutivePathfinds = Math.Max(FailedConsecutivePathfinds - 3, 0);
				mainTarget.Set(bestTarget.X, bestTarget.Y, bestTarget.Z);
				return true;
			}
			FailedConsecutivePathfinds++;
			return false;
		}

		protected virtual double MoveDownToFloor(int x, double y, int z)
		{
			int num = 5;
			while (num-- > 0)
			{
				if (world.BlockAccessor.IsSideSolid(x, (int)y, z, BlockFacing.UP))
				{
					return y + 1.0;
				}
				y -= 1.0;
			}
			return -1.0;
		}

		protected virtual void OnStuck()
		{
			stopTask = true;
			failedWanders++;
		}

		protected virtual void OnGoalReached()
		{
			stopTask = true;
			failedWanders = 0;
		}
	}
	public class EntityBehaviorAimingAccuracy : EntityBehavior
	{
		public Random Rand;

		public bool IsAiming;

		private List<AccuracyModifier> modifiers = new List<AccuracyModifier>();

		public EntityBehaviorAimingAccuracy(Entity entity)
			: base(entity)
		{
			EntityAgent entityAgent = entity as EntityAgent;
			modifiers.Add(new BaseAimingAccuracy(entityAgent));
			modifiers.Add(new MovingAimingAccuracy(entityAgent));
			modifiers.Add(new SprintAimingAccuracy(entityAgent));
			modifiers.Add(new OnHurtAimingAccuracy(entityAgent));
			entity.Attributes.RegisterModifiedListener("aiming", OnAimingChanged);
			Rand = new Random((int)(entity.EntityId + entity.World.ElapsedMilliseconds));
		}

		private void OnAimingChanged()
		{
			bool isAiming = IsAiming;
			IsAiming = entity.Attributes.GetInt("aiming") > 0;
			if (isAiming == IsAiming)
			{
				return;
			}
			if (IsAiming && entity.World is IServerWorldAccessor)
			{
				double value = Rand.NextDouble() - 0.5;
				double value2 = Rand.NextDouble() - 0.5;
				entity.WatchedAttributes.SetDouble("aimingRandPitch", value);
				entity.WatchedAttributes.SetDouble("aimingRandYaw", value2);
			}
			for (int i = 0; i < modifiers.Count; i++)
			{
				if (IsAiming)
				{
					modifiers[i].BeginAim();
				}
				else
				{
					modifiers[i].EndAim();
				}
			}
		}

		public override void OnGameTick(float deltaTime)
		{
			if (IsAiming)
			{
				if (!entity.Alive)
				{
					entity.Attributes.SetInt("aiming", 0);
				}
				float accuracy = 0f;
				for (int i = 0; i < modifiers.Count; i++)
				{
					modifiers[i].Update(deltaTime, ref accuracy);
				}
				entity.Attributes.SetFloat("aimingAccuracy", accuracy);
			}
		}

		public override void OnEntityReceiveDamage(DamageSource damageSource, ref float damage)
		{
			base.OnEntityReceiveDamage(damageSource, ref damage);
			if (damageSource.Type != EnumDamageType.Heal)
			{
				for (int i = 0; i < modifiers.Count; i++)
				{
					modifiers[i].OnHurt(damage);
				}
			}
		}

		public override string PropertyName()
		{
			return "aimingaccuracy";
		}
	}
	public class AccuracyModifier
	{
		internal EntityAgent entity;

		internal long aimStartMs;

		public float SecondsSinceAimStart => (float)(entity.World.ElapsedMilliseconds - aimStartMs) / 1000f;

		public AccuracyModifier(EntityAgent entity)
		{
			this.entity = entity;
		}

		public virtual void BeginAim()
		{
			aimStartMs = entity.World.ElapsedMilliseconds;
		}

		public virtual void EndAim()
		{
		}

		public virtual void OnHurt(float damage)
		{
		}

		public virtual void Update(float dt, ref float accuracy)
		{
		}
	}
	public class BaseAimingAccuracy : AccuracyModifier
	{
		public BaseAimingAccuracy(EntityAgent entity)
			: base(entity)
		{
		}

		public override void Update(float dt, ref float accuracy)
		{
			float blended = entity.Stats.GetBlended("rangedWeaponsAcc");
			float blended2 = entity.Stats.GetBlended("rangedWeaponsSpeed");
			float max = Math.Min(1f - 0.075f / blended, 1f);
			accuracy = GameMath.Clamp(base.SecondsSinceAimStart * blended2 * 1.7f, 0f, max);
			if (base.SecondsSinceAimStart >= 0.75f)
			{
				accuracy += GameMath.Sin(base.SecondsSinceAimStart * 8f) / 80f / Math.Max(1f, blended);
			}
		}
	}
	public class MovingAimingAccuracy : AccuracyModifier
	{
		private float accuracyPenalty;

		public MovingAimingAccuracy(EntityAgent entity)
			: base(entity)
		{
		}

		public override void Update(float dt, ref float accuracy)
		{
			float blended = entity.Stats.GetBlended("rangedWeaponsAcc");
			if (entity.Controls.TriesToMove)
			{
				accuracyPenalty = GameMath.Clamp(accuracyPenalty + dt / 0.75f, 0f, 0.2f);
			}
			else
			{
				accuracyPenalty = GameMath.Clamp(accuracyPenalty - dt / 2f, 0f, 0.2f);
			}
			accuracy -= accuracyPenalty / Math.Max(1f, blended);
		}
	}
	public class SprintAimingAccuracy : AccuracyModifier
	{
		private float accuracyPenalty;

		public SprintAimingAccuracy(EntityAgent entity)
			: base(entity)
		{
		}

		public override void Update(float dt, ref float accuracy)
		{
			float blended = entity.Stats.GetBlended("rangedWeaponsAcc");
			if (entity.Controls.TriesToMove && entity.Controls.Sprint)
			{
				accuracyPenalty = GameMath.Clamp(accuracyPenalty + dt / 0.75f, 0f, 0.3f);
			}
			else
			{
				accuracyPenalty = GameMath.Clamp(accuracyPenalty - dt / 2f, 0f, 0.3f);
			}
			accuracy -= accuracyPenalty / Math.Max(1f, blended);
		}
	}
	public class OnHurtAimingAccuracy : AccuracyModifier
	{
		private float accuracyPenalty;

		public OnHurtAimingAccuracy(EntityAgent entity)
			: base(entity)
		{
		}

		public override void Update(float dt, ref float accuracy)
		{
			accuracyPenalty = GameMath.Clamp(accuracyPenalty - dt / 3f, 0f, 0.4f);
		}

		public override void OnHurt(float damage)
		{
			if (damage > 3f)
			{
				float blended = entity.Stats.GetBlended("rangedWeaponsAcc");
				accuracyPenalty = -0.4f / Math.Max(1f, blended);
			}
		}
	}
	public class EntityBehaviorBreathe : EntityBehavior
	{
		private ITreeAttribute oxygenTree;

		private float oxygenCached = -1f;

		private float maxOxygen;

		private Cuboidd tmp = new Cuboidd();

		private float breathAccum;

		private float padding = 0.1f;

		private Block suffocationSourceBlock;

		private float damageAccum;

		public float Oxygen
		{
			get
			{
				return oxygenCached = oxygenTree.GetFloat("currentoxygen");
			}
			set
			{
				if (value != oxygenCached)
				{
					oxygenCached = value;
					oxygenTree.SetFloat("currentoxygen", value);
					entity.WatchedAttributes.MarkPathDirty("oxygen");
				}
			}
		}

		public float MaxOxygen
		{
			get
			{
				return maxOxygen;
			}
			set
			{
				maxOxygen = value;
				oxygenTree.SetFloat("maxoxygen", value);
				entity.WatchedAttributes.MarkPathDirty("oxygen");
			}
		}

		public bool HasAir
		{
			get
			{
				return oxygenTree.GetBool("hasair");
			}
			set
			{
				if (oxygenTree.GetBool("hasair") != value)
				{
					oxygenTree.SetBool("hasair", value);
					entity.WatchedAttributes.MarkPathDirty("oxygen");
				}
			}
		}

		public EntityBehaviorBreathe(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			base.Initialize(properties, typeAttributes);
			oxygenTree = entity.WatchedAttributes.GetTreeAttribute("oxygen");
			if (oxygenTree == null)
			{
				entity.WatchedAttributes.SetAttribute("oxygen", oxygenTree = new TreeAttribute());
				float defaultValue = 40000f;
				if (entity is EntityPlayer)
				{
					defaultValue = entity.World.Config.GetAsInt("lungCapacity", 40000);
				}
				MaxOxygen = typeAttributes["maxoxygen"].AsFloat(defaultValue);
				Oxygen = typeAttributes["currentoxygen"].AsFloat(MaxOxygen);
				HasAir = true;
			}
			else
			{
				maxOxygen = oxygenTree.GetFloat("maxoxygen");
			}
			breathAccum = (float)entity.World.Rand.NextDouble();
		}

		public override void OnEntityRevive()
		{
			Oxygen = MaxOxygen;
		}

		public void Check()
		{
			maxOxygen = oxygenTree.GetFloat("maxoxygen");
			if (entity.World.Side == EnumAppSide.Client)
			{
				return;
			}
			bool hasAir = true;
			if (entity is EntityPlayer)
			{
				EntityPlayer entityPlayer = (EntityPlayer)entity;
				EnumGameMode currentGameMode = entity.World.PlayerByUid(entityPlayer.PlayerUID).WorldData.CurrentGameMode;
				if (currentGameMode == EnumGameMode.Creative || currentGameMode == EnumGameMode.Spectator)
				{
					HasAir = true;
					return;
				}
			}
			EntityPos sidedPos = entity.SidedPos;
			double num = (entity.Swimming ? entity.Properties.SwimmingEyeHeight : entity.Properties.EyeHeight);
			double num2 = (sidedPos.Y + num) % 1.0;
			BlockPos blockPos = new BlockPos((int)(sidedPos.X + entity.LocalEyePos.X), (int)(sidedPos.Y + num), (int)(sidedPos.Z + entity.LocalEyePos.Z), sidedPos.Dimension);
			Block block = entity.World.BlockAccessor.GetBlock(blockPos, 3);
			JsonObject attributes = block.Attributes;
			if (attributes == null || attributes["asphyxiating"].AsBool(defaultValue: true))
			{
				Cuboidf[] collisionBoxes = block.GetCollisionBoxes(entity.World.BlockAccessor, blockPos);
				Cuboidf cuboidf = new Cuboidf();
				if (collisionBoxes != null)
				{
					for (int i = 0; i < collisionBoxes.Length; i++)
					{
						cuboidf.Set(collisionBoxes[i]);
						cuboidf.OmniGrowBy(0f - padding);
						tmp.Set((float)blockPos.X + cuboidf.X1, (float)blockPos.Y + cuboidf.Y1, (float)blockPos.Z + cuboidf.Z1, (float)blockPos.X + cuboidf.X2, (float)blockPos.Y + cuboidf.Y2, (float)blockPos.Z + cuboidf.Z2);
						cuboidf.OmniGrowBy(padding);
						if (tmp.Contains(sidedPos.X + entity.LocalEyePos.X, sidedPos.Y + entity.LocalEyePos.Y, sidedPos.Z + entity.LocalEyePos.Z))
						{
							Cuboidd other = entity.SelectionBox.ToDouble();
							if (tmp.Intersects(other))
							{
								hasAir = false;
								suffocationSourceBlock = block;
								break;
							}
						}
					}
				}
			}
			if (block.IsLiquid() && (double)((float)block.LiquidLevel / 7f) > num2)
			{
				hasAir = false;
			}
			HasAir = hasAir;
		}

		public override void OnGameTick(float deltaTime)
		{
			if (entity.State == EnumEntityState.Inactive)
			{
				return;
			}
			if (!HasAir)
			{
				float num = (Oxygen = Math.Max(0f, Oxygen - deltaTime * 1000f));
				if (num <= 0f && entity.World.Side == EnumAppSide.Server)
				{
					damageAccum += deltaTime;
					if ((double)damageAccum > 0.75)
					{
						damageAccum = 0f;
						DamageSource damageSource = new DamageSource
						{
							Source = EnumDamageSource.Block,
							SourceBlock = suffocationSourceBlock,
							Type = EnumDamageType.Suffocation
						};
						entity.ReceiveDamage(damageSource, 0.5f);
					}
				}
			}
			else if (Oxygen < maxOxygen)
			{
				Oxygen = Math.Min(maxOxygen, Oxygen + deltaTime * 10000f);
			}
			base.OnGameTick(deltaTime);
			breathAccum += deltaTime;
			if (breathAccum > 1f)
			{
				breathAccum = 0f;
				Check();
			}
		}

		public override string PropertyName()
		{
			return "breathe";
		}
	}
	public class EntityBehaviorCollectEntities : EntityBehavior
	{
		private int waitTicks;

		private int lastCollectedEntityIndex;

		private Vec3d tmp = new Vec3d();

		private float itemsPerSecond = 23f;

		private float unconsumedDeltaTime;

		public EntityBehaviorCollectEntities(Entity entity)
			: base(entity)
		{
		}

		public override void OnGameTick(float deltaTime)
		{
			if (base.entity.State != EnumEntityState.Active || !base.entity.Alive)
			{
				return;
			}
			IPlayer player = (base.entity as EntityPlayer)?.Player;
			IServerPlayer obj = player as IServerPlayer;
			if (obj != null && obj.ItemCollectMode == 1)
			{
				EntityAgent obj2 = base.entity as EntityAgent;
				if (obj2 != null && !obj2.Controls.Sneak)
				{
					return;
				}
			}
			if (base.entity.IsActivityRunning("invulnerable"))
			{
				waitTicks = 3;
			}
			else
			{
				if (waitTicks-- > 0 || (player != null && player.WorldData.CurrentGameMode == EnumGameMode.Spectator))
				{
					return;
				}
				tmp.Set(base.entity.ServerPos.X, base.entity.ServerPos.InternalY + (double)base.entity.SelectionBox.Y1 + (double)(base.entity.SelectionBox.Y2 / 2f), base.entity.ServerPos.Z);
				Entity[] entitiesAround = base.entity.World.GetEntitiesAround(tmp, 1.5f, 1.5f, entityMatcher);
				if (entitiesAround.Length == 0)
				{
					unconsumedDeltaTime = 0f;
					return;
				}
				deltaTime = Math.Min(1f, deltaTime + unconsumedDeltaTime);
				while (deltaTime - 1f / itemsPerSecond > 0f)
				{
					Entity entity = null;
					int i;
					for (i = 0; i < entitiesAround.Length; i++)
					{
						if (entitiesAround[i] != null && i >= lastCollectedEntityIndex)
						{
							entity = entitiesAround[i];
							break;
						}
					}
					if (entity == null)
					{
						entity = entitiesAround[0];
						i = 0;
					}
					if (entity == null)
					{
						return;
					}
					if (!OnFoundCollectible(entity))
					{
						lastCollectedEntityIndex = (lastCollectedEntityIndex + 1) % entitiesAround.Length;
					}
					else
					{
						entitiesAround[i] = null;
					}
					deltaTime -= 1f / itemsPerSecond;
				}
				unconsumedDeltaTime = deltaTime;
			}
		}

		public virtual bool OnFoundCollectible(Entity foundEntity)
		{
			ItemStack itemStack = foundEntity.OnCollected(entity);
			bool flag = false;
			ItemStack itemStack2 = itemStack.Clone();
			if (itemStack != null && itemStack.StackSize > 0)
			{
				flag = entity.TryGiveItemStack(itemStack);
			}
			if (itemStack != null && itemStack.StackSize <= 0)
			{
				foundEntity.Die(EnumDespawnReason.PickedUp);
			}
			if (flag)
			{
				itemStack.Collectible.OnCollected(itemStack, entity);
				TreeAttribute treeAttribute = new TreeAttribute();
				treeAttribute["itemstack"] = new ItemstackAttribute(itemStack2.Clone());
				treeAttribute["byentityid"] = new LongAttribute(entity.EntityId);
				entity.World.Api.Event.PushEvent("onitemcollected", treeAttribute);
				entity.World.PlaySoundAt(new AssetLocation("sounds/player/collect"), entity);
				return true;
			}
			return false;
		}

		private bool entityMatcher(Entity foundEntity)
		{
			return foundEntity.CanCollect(entity);
		}

		public override string PropertyName()
		{
			return "collectitems";
		}
	}
	public class StepParentElementTo : ModelTransform
	{
		[JsonProperty]
		public string ElementName;
	}
	public interface IAttachableToEntity
	{
		int RequiresBehindSlots { get; set; }

		bool IsAttachable(Entity toEntity, ItemStack itemStack);

		void CollectTextures(ItemStack stack, Shape shape, string texturePrefixCode, Dictionary<string, CompositeTexture> intoDict);

		string GetCategoryCode(ItemStack stack);

		CompositeShape GetAttachedShape(ItemStack stack, string slotCode);

		string[] GetDisableElements(ItemStack stack);

		string[] GetKeepElements(ItemStack stack);

		string GetTexturePrefixCode(ItemStack stack);

		static IAttachableToEntity FromCollectible(CollectibleObject cobj)
		{
			IAttachableToEntity collectibleInterface = cobj.GetCollectibleInterface<IAttachableToEntity>();
			if (collectibleInterface != null)
			{
				return collectibleInterface;
			}
			return FromAttributes(cobj);
		}

		static IAttachableToEntity FromAttributes(CollectibleObject cobj)
		{
			AttributeAttachableToEntity attributeAttachableToEntity = cobj.Attributes?["attachableToEntity"].AsObject<AttributeAttachableToEntity>(null, cobj.Code.Domain);
			if (attributeAttachableToEntity == null)
			{
				JsonObject attributes = cobj.Attributes;
				if (attributes != null && attributes["wearableAttachment"].Exists)
				{
					return new AttributeAttachableToEntity
					{
						CategoryCode = (cobj.Attributes["clothescategory"].AsString() ?? cobj.Attributes?["attachableToEntity"]["categoryCode"].AsString()),
						KeepElements = cobj.Attributes["keepElements"].AsArray<string>(),
						DisableElements = cobj.Attributes["disableElements"].AsArray<string>()
					};
				}
			}
			return attributeAttachableToEntity;
		}

		static void CollectTexturesFromCollectible(ItemStack stack, string texturePrefixCode, Shape gearShape, Dictionary<string, CompositeTexture> intoDict)
		{
			if (gearShape.Textures == null)
			{
				gearShape.Textures = new Dictionary<string, AssetLocation>();
			}
			IDictionary<string, CompositeTexture> dictionary;
			if (stack.Class != EnumItemClass.Block)
			{
				IDictionary<string, CompositeTexture> textures = stack.Item.Textures;
				dictionary = textures;
			}
			else
			{
				dictionary = stack.Block.Textures;
			}
			IDictionary<string, CompositeTexture> dictionary2 = dictionary;
			if (dictionary2 == null)
			{
				return;
			}
			foreach (KeyValuePair<string, CompositeTexture> item in dictionary2)
			{
				gearShape.Textures[item.Key] = item.Value.Base;
			}
		}
	}
	public class AttributeAttachableToEntity : IAttachableToEntity
	{
		public string CategoryCode { get; set; }

		public CompositeShape AttachedShape { get; set; }

		public string[] DisableElements { get; set; }

		public string[] KeepElements { get; set; }

		public string TexturePrefixCode { get; set; }

		public OrderedDictionary<string, CompositeShape> AttachedShapeBySlotCode { get; set; }

		public int RequiresBehindSlots { get; set; }

		public string GetTexturePrefixCode(ItemStack stack)
		{
			return TexturePrefixCode;
		}

		public void CollectTextures(ItemStack stack, Shape gearShape, string texturePrefixCode, Dictionary<string, CompositeTexture> intoDict)
		{
			IAttachableToEntity.CollectTexturesFromCollectible(stack, texturePrefixCode, gearShape, intoDict);
		}

		public CompositeShape GetAttachedShape(ItemStack stack, string slotCode)
		{
			if (AttachedShape != null)
			{
				return AttachedShape;
			}
			if (AttachedShapeBySlotCode != null)
			{
				foreach (KeyValuePair<string, CompositeShape> item in AttachedShapeBySlotCode)
				{
					if (WildcardUtil.Match(item.Key, slotCode))
					{
						return item.Value;
					}
				}
			}
			if (stack.Class != EnumItemClass.Item)
			{
				return stack.Block.Shape;
			}
			return stack.Item.Shape;
		}

		public string GetCategoryCode(ItemStack stack)
		{
			return CategoryCode;
		}

		public string[] GetDisableElements(ItemStack stack)
		{
			return DisableElements;
		}

		public string[] GetKeepElements(ItemStack stack)
		{
			return KeepElements;
		}

		public bool IsAttachable(Entity toEntity, ItemStack itemStack)
		{
			return true;
		}
	}
	public abstract class EntityBehaviorContainer : EntityBehavior
	{
		protected ICoreAPI Api;

		private InWorldContainer container;

		public bool hideClothing;

		private bool eventRegistered;

		private bool dropContentsOnDeath;

		public abstract InventoryBase Inventory { get; }

		public abstract string InventoryClassName { get; }

		protected EntityBehaviorContainer(Entity entity)
			: base(entity)
		{
			container = new InWorldContainer(() => Inventory, InventoryClassName);
		}

		public override bool TryEarlyLoadCollectibleMappings(IWorldAccessor worldForCollectibleResolve, Dictionary<int, AssetLocation> oldBlockIdMapping, Dictionary<int, AssetLocation> oldItemIdMapping, bool resolveImports, EntityProperties entityProperties, JsonObject behaviorConfig)
		{
			OnLoadCollectibleMappings(worldForCollectibleResolve, oldBlockIdMapping, oldItemIdMapping, resolveImports);
			return true;
		}

		public override bool ShouldEarlyLoadCollectibleMappings()
		{
			return true;
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			Api = entity.World.Api;
			container.Init(Api, () => entity.Pos.AsBlockPos, delegate
			{
				entity.WatchedAttributes.MarkPathDirty(InventoryClassName);
			});
			if (Api.Side == EnumAppSide.Client)
			{
				entity.WatchedAttributes.RegisterModifiedListener(InventoryClassName, inventoryModified);
			}
			dropContentsOnDeath = attributes?.IsTrue("dropContentsOnDeath") ?? false;
		}

		private void inventoryModified()
		{
			loadInv();
			entity.MarkShapeModified();
		}

		public override void OnGameTick(float deltaTime)
		{
			if (!eventRegistered && Inventory != null)
			{
				eventRegistered = true;
				Inventory.SlotModified += Inventory_SlotModified;
			}
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			if (Inventory != null)
			{
				Inventory.SlotModified -= Inventory_SlotModified;
			}
		}

		protected void Inventory_SlotModifiedBackpack(int slotid)
		{
			if (entity is EntityPlayer entityPlayer && entityPlayer.Player.InventoryManager.GetOwnInventory("backpack")[slotid] is ItemSlotBackpack)
			{
				entity.MarkShapeModified();
			}
		}

		protected virtual void Inventory_SlotModified(int slotid)
		{
			entity.MarkShapeModified();
		}

		public override void OnTesselation(ref Shape entityShape, string shapePathForLogging, ref bool shapeIsCloned, ref string[] willDeleteElements)
		{
			try
			{
				addGearToShape(ref entityShape, shapePathForLogging, ref shapeIsCloned, ref willDeleteElements);
			}
			catch (Exception innerException)
			{
				throw new Exception(string.Concat("Error tesselating entity ", entity.Code, " at ", entity.Pos.AsBlockPos?.ToString()), innerException);
			}
			base.OnTesselation(ref entityShape, shapePathForLogging, ref shapeIsCloned, ref willDeleteElements);
			if (Inventory != null)
			{
				ItemSlot itemSlot = Inventory.MaxBy((ItemSlot slot) => (!slot.Empty) ? slot.Itemstack.Collectible.LightHsv[2] : 0);
				if (!itemSlot.Empty)
				{
					entity.LightHsv = itemSlot.Itemstack.Collectible.GetLightHsv(entity.World.BlockAccessor, null, itemSlot.Itemstack);
				}
				else
				{
					entity.LightHsv = null;
				}
			}
		}

		protected Shape addGearToShape(ref Shape entityShape, string shapePathForLogging, ref bool shapeIsCloned, ref string[] willDeleteElements)
		{
			IInventory inventory = Inventory;
			if (inventory == null || (!(entity is EntityPlayer) && inventory.Empty))
			{
				return entityShape;
			}
			foreach (ItemSlot item in inventory)
			{
				if (!item.Empty && !hideClothing && ShouldAddGearToShape(item))
				{
					entityShape = addGearToShape(entityShape, item, "default", shapePathForLogging, ref shapeIsCloned, ref willDeleteElements);
				}
			}
			if (shapeIsCloned && Api is ICoreClientAPI coreClientAPI)
			{
				EntityProperties entityType = Api.World.GetEntityType(entity.Code);
				if (entityType != null)
				{
					foreach (KeyValuePair<string, CompositeTexture> texture in entityType.Client.Textures)
					{
						CompositeTexture value = texture.Value;
						value.Bake(Api.Assets);
						coreClientAPI.EntityTextureAtlas.GetOrInsertTexture(value.Baked.TextureFilenames[0], out var textureSubId, out var _);
						value.Baked.TextureSubId = textureSubId;
						entity.Properties.Client.Textures[texture.Key] = texture.Value;
					}
				}
			}
			return entityShape;
		}

		protected virtual bool ShouldAddGearToShape(ItemSlot slot)
		{
			return true;
		}

		protected virtual Shape addGearToShape(Shape entityShape, ItemSlot gearslot, string slotCode, string shapePathForLogging, ref bool shapeIsCloned, ref string[] willDeleteElements, Dictionary<string, StepParentElementTo> overrideStepParent = null)
		{
			if (gearslot.Empty || entityShape == null)
			{
				return entityShape;
			}
			IAttachableToEntity attachableToEntity = IAttachableToEntity.FromCollectible(gearslot.Itemstack.Collectible);
			if (attachableToEntity == null || !attachableToEntity.IsAttachable(entity, gearslot.Itemstack))
			{
				return entityShape;
			}
			if (!shapeIsCloned)
			{
				entityShape = entityShape.Clone();
				shapeIsCloned = true;
			}
			return addGearToShape(entityShape, gearslot.Itemstack, attachableToEntity, slotCode, shapePathForLogging, ref willDeleteElements, overrideStepParent);
		}

		protected virtual Shape addGearToShape(Shape entityShape, ItemStack stack, IAttachableToEntity iatta, string slotCode, string shapePathForLogging, ref string[] willDeleteElements, Dictionary<string, StepParentElementTo> overrideStepParent = null)
		{
			if (stack == null || iatta == null)
			{
				return entityShape;
			}
			float damageEffect = 0f;
			JsonObject itemAttributes = stack.ItemAttributes;
			if (itemAttributes != null && itemAttributes["visibleDamageEffect"].AsBool())
			{
				damageEffect = Math.Max(0f, 1f - (float)stack.Collectible.GetRemainingDurability(stack) / (float)stack.Collectible.GetMaxDurability(stack) * 1.1f);
			}
			entityShape.RemoveElements(iatta.GetDisableElements(stack));
			string[] keepElements = iatta.GetKeepElements(stack);
			if (keepElements != null && willDeleteElements != null)
			{
				string[] array = keepElements;
				foreach (string value in array)
				{
					willDeleteElements = willDeleteElements.Remove(value);
				}
			}
			IDictionary<string, CompositeTexture> textures = entity.Properties.Client.Textures;
			string texturePrefixCode = iatta.GetTexturePrefixCode(stack);
			Shape shape = null;
			AssetLocation assetLocation = null;
			CompositeShape compositeShape = null;
			if (stack.Collectible is IWearableShapeSupplier wearableShapeSupplier)
			{
				shape = wearableShapeSupplier.GetShape(stack, entity, texturePrefixCode);
			}
			if (shape == null)
			{
				compositeShape = iatta.GetAttachedShape(stack, slotCode);
				assetLocation = compositeShape.Base.CopyWithPathPrefixAndAppendixOnce("shapes/", ".json");
				shape = Shape.TryGet(Api, assetLocation);
				if (shape == null)
				{
					Api.World.Logger.Warning("Entity attachable shape {0} defined in {1} {2} not found or errored, was supposed to be at {3}. Shape will be invisible.", compositeShape.Base, stack.Class, stack.Collectible.Code, assetLocation);
					return entityShape;
				}
				shape.SubclassForStepParenting(texturePrefixCode, damageEffect);
				shape.ResolveReferences(entity.World.Logger, assetLocation);
			}
			ICoreClientAPI capi = Api as ICoreClientAPI;
			Dictionary<string, CompositeTexture> dictionary = null;
			if (capi != null)
			{
				dictionary = new Dictionary<string, CompositeTexture>();
				iatta.CollectTextures(stack, shape, texturePrefixCode, dictionary);
			}
			applyStepParentOverrides(overrideStepParent, shape);
			entityShape.StepParentShape(shape, (compositeShape?.Base.ToString() ?? "Custom texture from ItemWearableShapeSupplier") + $" defined in {stack.Class} {stack.Collectible.Code}", shapePathForLogging, Api.World.Logger, delegate(string texcode, AssetLocation tloc)
			{
				addTexture(texcode, tloc, textures, texturePrefixCode, capi);
			});
			if (compositeShape?.Overlays != null)
			{
				CompositeShape[] overlays = compositeShape.Overlays;
				foreach (CompositeShape compositeShape2 in overlays)
				{
					Shape shape2 = Shape.TryGet(Api, compositeShape2.Base.CopyWithPathPrefixAndAppendixOnce("shapes/", ".json"));
					if (shape2 == null)
					{
						Api.World.Logger.Warning("Entity attachable shape {0} overlay {4} defined in {1} {2} not found or errored, was supposed to be at {3}. Shape will be invisible.", compositeShape.Base, stack.Class, stack.Collectible.Code, assetLocation, compositeShape2.Base);
						continue;
					}
					shape2.SubclassForStepParenting(texturePrefixCode, damageEffect);
					if (capi != null)
					{
						iatta.CollectTextures(stack, shape2, texturePrefixCode, dictionary);
					}
					applyStepParentOverrides(overrideStepParent, shape2);
					entityShape.StepParentShape(shape2, compositeShape2.Base.ToShortString(), shapePathForLogging, Api.Logger, delegate(string texcode, AssetLocation tloc)
					{
						addTexture(texcode, tloc, textures, texturePrefixCode, capi);
					});
				}
			}
			if (capi != null)
			{
				foreach (KeyValuePair<string, CompositeTexture> item in dictionary)
				{
					CompositeTexture compositeTexture = (textures[item.Key] = item.Value.Clone());
					CompositeTexture compositeTexture3 = compositeTexture;
					capi.EntityTextureAtlas.GetOrInsertTexture(compositeTexture3, out var textureSubId, out var _);
					compositeTexture3.Baked.TextureSubId = textureSubId;
				}
			}
			return entityShape;
		}

		private static void applyStepParentOverrides(Dictionary<string, StepParentElementTo> overrideStepParent, Shape gearShape)
		{
			if (overrideStepParent == null)
			{
				return;
			}
			overrideStepParent.TryGetValue("", out var value);
			ShapeElement[] elements = gearShape.Elements;
			foreach (ShapeElement shapeElement in elements)
			{
				StepParentElementTo value2;
				if (shapeElement.StepParentName == null || shapeElement.StepParentName.Length == 0)
				{
					shapeElement.StepParentName = value.ElementName;
				}
				else if (overrideStepParent.TryGetValue(shapeElement.StepParentName, out value2))
				{
					shapeElement.StepParentName = value2.ElementName;
				}
			}
		}

		private void addTexture(string texcode, AssetLocation tloc, IDictionary<string, CompositeTexture> textures, string texturePrefixCode, ICoreClientAPI capi)
		{
			if (capi != null)
			{
				CompositeTexture compositeTexture = (textures[texturePrefixCode + texcode] = new CompositeTexture(tloc));
				CompositeTexture compositeTexture3 = compositeTexture;
				compositeTexture3.Bake(Api.Assets);
				capi.EntityTextureAtlas.GetOrInsertTexture(compositeTexture3.Baked.TextureFilenames[0], out var textureSubId, out var _);
				compositeTexture3.Baked.TextureSubId = textureSubId;
			}
		}

		public override void OnLoadCollectibleMappings(IWorldAccessor worldForNewMappings, Dictionary<int, AssetLocation> oldBlockIdMapping, Dictionary<int, AssetLocation> oldItemIdMapping, bool resolveImports)
		{
			container.OnLoadCollectibleMappings(worldForNewMappings, oldBlockIdMapping, oldItemIdMapping, 0, resolveImports);
		}

		public override void OnStoreCollectibleMappings(Dictionary<int, AssetLocation> blockIdMapping, Dictionary<int, AssetLocation> itemIdMapping)
		{
			container.OnStoreCollectibleMappings(blockIdMapping, itemIdMapping);
		}

		public override void FromBytes(bool isSync)
		{
			loadInv();
		}

		protected virtual void loadInv()
		{
			if (Inventory != null)
			{
				container.FromTreeAttributes(entity.WatchedAttributes, entity.World);
				entity.MarkShapeModified();
			}
		}

		public override void ToBytes(bool forClient)
		{
			storeInv();
		}

		public virtual void storeInv()
		{
			container.ToTreeAttributes(entity.WatchedAttributes);
			entity.WatchedAttributes.MarkPathDirty(InventoryClassName);
			entity.World.BlockAccessor.GetChunkAtBlockPos(entity.ServerPos.AsBlockPos)?.MarkModified();
		}

		public override bool TryGiveItemStack(ItemStack itemstack, ref EnumHandling handling)
		{
			ItemSlot itemSlot = new DummySlot(null);
			itemSlot.Itemstack = itemstack.Clone();
			ItemStackMoveOperation op = new ItemStackMoveOperation(entity.World, EnumMouseButton.Left, (EnumModifierKey)0, EnumMergePriority.AutoMerge, itemstack.StackSize);
			if (Inventory != null)
			{
				WeightedSlot bestSuitedSlot = Inventory.GetBestSuitedSlot(itemSlot, null, new List<ItemSlot>());
				if (bestSuitedSlot.weight > 0f)
				{
					itemSlot.TryPutInto(bestSuitedSlot.slot, ref op);
					itemstack.StackSize -= op.MovedQuantity;
					entity.WatchedAttributes.MarkAllDirty();
					return op.MovedQuantity > 0;
				}
			}
			if ((entity as EntityAgent)?.LeftHandItemSlot?.Inventory != null)
			{
				WeightedSlot weightedSlot = (entity as EntityAgent)?.LeftHandItemSlot.Inventory.GetBestSuitedSlot(itemSlot, null, new List<ItemSlot>());
				if (weightedSlot.weight > 0f)
				{
					itemSlot.TryPutInto(weightedSlot.slot, ref op);
					itemstack.StackSize -= op.MovedQuantity;
					entity.WatchedAttributes.MarkAllDirty();
					return op.MovedQuantity > 0;
				}
			}
			return false;
		}

		public override void OnEntityDeath(DamageSource damageSourceForDeath)
		{
			base.OnEntityDeath(damageSourceForDeath);
			if (dropContentsOnDeath)
			{
				Inventory.DropAll(entity.ServerPos.XYZ);
			}
		}
	}
	public class EntityBehaviorControlledPhysics : PhysicsBehaviorBase, IPhysicsTickable, IRemotePhysics
