		public virtual void OnPhysicsTick(float dt)
		{
			Entity entity = base.entity;
			if (entity.State != EnumEntityState.Active)
			{
				return;
			}
			EntityPos sidedPos = entity.SidedPos;
			PhysicsBehaviorBase.collisionTester.AssignToEntity(this, sidedPos.Dimension);
			EntityControls controls = ((EntityAgent)entity).Controls;
			EntityAgent entityAgent = entity as EntityAgent;
			if (entityAgent?.MountedOn != null)
			{
				AdjustMountedPositionFor(entityAgent);
				return;
			}
			SetState(sidedPos, dt);
			MotionAndCollision(sidedPos, controls, dt);
			ApplyTests(sidedPos, controls, dt, remote: false);
			if (entity.World.Side == EnumAppSide.Server)
			{
				entity.Pos.SetFrom(entity.ServerPos);
			}
			IMountable mountable = mountableSupplier;
			if (mountable == null)
			{
				return;
			}
			IMountableSeat[] seats = mountable.Seats;
			for (int i = 0; i < seats.Length; i++)
			{
				if (seats[i]?.Passenger is EntityAgent { MountedOn: not null } entityAgent2)
				{
					AdjustMountedPositionFor(entityAgent2);
				}
			}
		}

		private void AdjustMountedPositionFor(EntityAgent entity)
		{
			entity.Swimming = false;
			entity.OnGround = false;
			EntityPos sidedPos = entity.SidedPos;
			if (!(entity is EntityPlayer))
			{
				sidedPos.SetFrom(entity.MountedOn.SeatPosition);
			}
			else
			{
				sidedPos.SetPos(entity.MountedOn.SeatPosition);
			}
			sidedPos.Motion.X = 0.0;
			sidedPos.Motion.Y = 0.0;
			sidedPos.Motion.Z = 0.0;
		}

		public virtual void AfterPhysicsTick(float dt)
		{
			Entity entity = base.entity;
			if (entity.State == EnumEntityState.Active && (mountableSupplier == null || capi != null || !mountableSupplier.IsBeingControlled()))
			{
				BlockPos blockPos = tmpPos;
				List<Block> list = traversedBlocks;
				List<FastVec3i> list2 = traversed;
				for (int i = 0; i < list.Count; i++)
				{
					blockPos.Set(list2[i]);
					list[i].OnEntityInside(entity.World, entity, blockPos);
				}
				entity.AfterPhysicsTick?.Invoke();
			}
		}

		public void HandleSneaking(EntityPos pos, EntityControls controls, float dt)
		{
			if (!controls.Sneak || !entity.OnGround || pos.Motion.Y > 0.0)
			{
				return;
			}
			Vec3d vec3d = new Vec3d();
			vec3d.Set(pos.X, pos.InternalY - (double)(GlobalConstants.GravityPerSecond * dt), pos.Z);
			if (!PhysicsBehaviorBase.collisionTester.IsColliding(entity.World.BlockAccessor, sneakTestCollisionbox, vec3d))
			{
				return;
			}
			tmpPos.Set((int)pos.X, (int)pos.Y - 1, (int)pos.Z);
			Block block = entity.World.BlockAccessor.GetBlock(tmpPos);
			vec3d.Set(newPos.X, newPos.Y - (double)(GlobalConstants.GravityPerSecond * dt) + (double)pos.DimensionYAdjustment, pos.Z);
			if (!PhysicsBehaviorBase.collisionTester.IsColliding(entity.World.BlockAccessor, sneakTestCollisionbox, vec3d))
			{
				if (block.IsClimbable(tmpPos))
				{
					newPos.X += (pos.X - newPos.X) / 10.0;
				}
				else
				{
					newPos.X = pos.X;
				}
			}
			vec3d.Set(pos.X, newPos.Y - (double)(GlobalConstants.GravityPerSecond * dt) + (double)pos.DimensionYAdjustment, newPos.Z);
			if (!PhysicsBehaviorBase.collisionTester.IsColliding(entity.World.BlockAccessor, sneakTestCollisionbox, vec3d))
			{
				if (block.IsClimbable(tmpPos))
				{
					newPos.Z += (pos.Z - newPos.Z) / 10.0;
				}
				else
				{
					newPos.Z = pos.Z;
				}
			}
		}

		protected virtual bool HandleSteppingOnBlocks(EntityPos pos, Vec3d moveDelta, float dtFac, EntityControls controls)
		{
			if (controls.WalkVector.X == 0.0 && controls.WalkVector.Z == 0.0)
			{
				return false;
			}
			if ((!entity.OnGround && !entity.Swimming) || entity.Properties.Habitat == EnumHabitat.Underwater)
			{
				return false;
			}
			steppingCollisionBox.SetAndTranslate(entity.CollisionBox, pos.X, pos.Y, pos.Z);
			steppingCollisionBox.Y2 = Math.Max(steppingCollisionBox.Y1 + (double)StepHeight, steppingCollisionBox.Y2);
			Vec3d walkVector = controls.WalkVector;
			Cuboidd cuboidd = FindSteppableCollisionBox(steppingCollisionBox, moveDelta.Y, walkVector);
			if (cuboidd != null)
			{
				Vec3d vec3d = steppingTestMotion;
				vec3d.Set(moveDelta.X, moveDelta.Y, moveDelta.Z);
				if (TryStep(pos, vec3d, dtFac, cuboidd, steppingCollisionBox))
				{
					return true;
				}
				Vec3d vec3d2 = steppingTestVec;
				vec3d.Z = 0.0;
				if (TryStep(pos, vec3d, dtFac, FindSteppableCollisionBox(steppingCollisionBox, moveDelta.Y, vec3d2.Set(walkVector.X, walkVector.Y, 0.0)), steppingCollisionBox))
				{
					return true;
				}
				vec3d.Set(0.0, moveDelta.Y, moveDelta.Z);
				if (TryStep(pos, vec3d, dtFac, FindSteppableCollisionBox(steppingCollisionBox, moveDelta.Y, vec3d2.Set(0.0, walkVector.Y, walkVector.Z)), steppingCollisionBox))
				{
					return true;
				}
				return false;
			}
			return false;
		}

		public bool TryStep(EntityPos pos, Vec3d moveDelta, float dtFac, Cuboidd steppableBox, Cuboidd entityCollisionBox)
		{
			if (steppableBox == null)
			{
				return false;
			}
			double y = steppableBox.Y2 - entityCollisionBox.Y1 + 0.03;
			Vec3d pos2 = newPos.OffsetCopy(moveDelta.X, y, moveDelta.Z);
			if (!PhysicsBehaviorBase.collisionTester.IsColliding(entity.World.BlockAccessor, entity.CollisionBox, pos2, alsoCheckTouch: false))
			{
				pos.Y += stepUpSpeed * dtFac;
				PhysicsBehaviorBase.collisionTester.ApplyTerrainCollision(entity, pos, dtFac, ref newPos);
				return true;
			}
			return false;
		}

		public static bool GetCollidingCollisionBox(IBlockAccessor blockAccessor, Cuboidf entityBoxRel, Vec3d pos, out CachedCuboidList blocks, BlockPos tmpPos, bool alsoCheckTouch = true)
		{
			blocks = new CachedCuboidList();
			Vec3d vec3d = new Vec3d();
			Cuboidd cuboidd = entityBoxRel.ToDouble().Translate(pos);
			int num = (int)((double)entityBoxRel.MinX + pos.X);
			int num2 = (int)((double)entityBoxRel.MinY + pos.Y - 1.0);
			int num3 = (int)((double)entityBoxRel.MinZ + pos.Z);
			int num4 = (int)Math.Ceiling((double)entityBoxRel.MaxX + pos.X);
			int num5 = (int)Math.Ceiling((double)entityBoxRel.MaxY + pos.Y);
			int num6 = (int)Math.Ceiling((double)entityBoxRel.MaxZ + pos.Z);
			for (int i = num2; i <= num5; i++)
			{
				for (int j = num; j <= num4; j++)
				{
					for (int k = num3; k <= num6; k++)
					{
						tmpPos.Set(j, i, k);
						Block block = blockAccessor.GetBlock(tmpPos);
						vec3d.Set(j, i, k);
						Cuboidf[] collisionBoxes = block.GetCollisionBoxes(blockAccessor, tmpPos);
						if (collisionBoxes == null)
						{
							continue;
						}
						foreach (Cuboidf cuboidf in collisionBoxes)
						{
							if (cuboidf != null && (alsoCheckTouch ? cuboidd.IntersectsOrTouches(cuboidf, vec3d) : cuboidd.Intersects(cuboidf, vec3d)))
							{
								blocks.Add(cuboidf, j, tmpPos.InternalY, k, block);
							}
						}
					}
				}
			}
			return blocks.Count > 0;
		}

		public Cuboidd FindSteppableCollisionBox(Cuboidd entityCollisionBox, double motionY, Vec3d walkVector)
		{
			Cuboidd cuboidd = null;
			CachedCuboidListFaster collisionBoxList = PhysicsBehaviorBase.collisionTester.CollisionBoxList;
			int count = collisionBoxList.Count;
			BlockPos blockPos = new BlockPos(entity.ServerPos.Dimension);
			for (int i = 0; i < count; i++)
			{
				Block block = collisionBoxList.blocks[i];
				if (block.CollisionBoxes != null && !block.CanStep && entity.CollisionBox.Height < 5f * block.CollisionBoxes[0].Height)
				{
					continue;
				}
				blockPos.Set(collisionBoxList.positions[i]);
				if (!block.SideIsSolid(blockPos, 4))
				{
					blockPos.Down();
					Block mostSolidBlock = entity.World.BlockAccessor.GetMostSolidBlock(blockPos);
					blockPos.Up();
					if (mostSolidBlock.CollisionBoxes != null && !mostSolidBlock.CanStep && entity.CollisionBox.Height < 5f * mostSolidBlock.CollisionBoxes[0].Height)
					{
						continue;
					}
				}
				Cuboidd cuboidd2 = collisionBoxList.cuboids[i];
				EnumIntersect enumIntersect = CollisionTester.AabbIntersect(cuboidd2, entityCollisionBox, walkVector);
				if (enumIntersect != EnumIntersect.NoIntersect)
				{
					if ((enumIntersect == EnumIntersect.Stuck && !block.AllowStepWhenStuck) || (enumIntersect == EnumIntersect.IntersectY && motionY > 0.0))
					{
						return null;
					}
					double num = cuboidd2.Y2 - entityCollisionBox.Y1;
					if (!(num <= 0.0) && num <= (double)StepHeight && (cuboidd == null || cuboidd.Y2 < cuboidd2.Y2))
					{
						cuboidd = cuboidd2;
					}
				}
			}
			return cuboidd;
		}

		public List<Cuboidd> FindSteppableCollisionboxSmooth(Cuboidd entityCollisionBox, Cuboidd entitySensorBox, double motionY, Vec3d walkVector)
		{
			List<Cuboidd> list = new List<Cuboidd>();
			GetCollidingCollisionBox(entity.World.BlockAccessor, entitySensorBox.ToFloat(), new Vec3d(), out var blocks, tmpPos);
			for (int i = 0; i < blocks.Count; i++)
			{
				Cuboidd cuboidd = blocks.cuboids[i];
				Block block = blocks.blocks[i];
				if (!block.CanStep && block.CollisionBoxes != null && entity.CollisionBox.Height < 5f * block.CollisionBoxes[0].Height)
				{
					continue;
				}
				BlockPos blockPos = blocks.positions[i];
				if (!block.SideIsSolid(blockPos, 4))
				{
					blockPos.Down();
					Block mostSolidBlock = entity.World.BlockAccessor.GetMostSolidBlock(blockPos);
					blockPos.Up();
					if (!mostSolidBlock.CanStep && mostSolidBlock.CollisionBoxes != null && entity.CollisionBox.Height < 5f * mostSolidBlock.CollisionBoxes[0].Height)
					{
						continue;
					}
				}
				EnumIntersect enumIntersect = CollisionTester.AabbIntersect(cuboidd, entityCollisionBox, walkVector);
				if ((enumIntersect == EnumIntersect.Stuck && !block.AllowStepWhenStuck) || (enumIntersect == EnumIntersect.IntersectY && motionY > 0.0))
				{
					return null;
				}
				double num = cuboidd.Y2 - entityCollisionBox.Y1;
				if (!(num <= (entity.CollidedVertically ? 0.0 : (-0.05))) && num <= (double)StepHeight)
				{
					list.Add(cuboidd);
				}
			}
			return list;
		}

		public void AdjustCollisionBoxToAnimation(float dtFac)
		{
			AttachmentPointAndPose attachmentPointAndPose = entity.AnimManager.Animator?.GetAttachmentPointPose("Center");
			if (attachmentPointAndPose != null)
			{
				float[] vec = new float[4] { 0f, 0f, 0f, 1f };
				AttachmentPoint attachPoint = attachmentPointAndPose.AttachPoint;
				CompositeShape shape = entity.Properties.Client.Shape;
				float num = shape?.rotateX ?? 0f;
				float num2 = shape?.rotateY ?? 0f;
				float num3 = shape?.rotateZ ?? 0f;
				float[] array = Mat4f.Create();
				Mat4f.Identity(array);
				Mat4f.Translate(array, array, 0f, entity.CollisionBox.Y2 / 2f, 0f);
				double[] array2 = Quaterniond.Create();
				Quaterniond.RotateX(array2, array2, entity.SidedPos.Pitch + num * ((float)Math.PI / 180f));
				Quaterniond.RotateY(array2, array2, entity.SidedPos.Yaw + (num2 + 90f) * ((float)Math.PI / 180f));
				Quaterniond.RotateZ(array2, array2, entity.SidedPos.Roll + num3 * ((float)Math.PI / 180f));
				float[] array3 = new float[array2.Length];
				for (int i = 0; i < array2.Length; i++)
				{
					array3[i] = (float)array2[i];
				}
				Mat4f.Mul(array, array, Mat4f.FromQuat(Mat4f.Create(), array3));
				float size = entity.Properties.Client.Size;
				Mat4f.Translate(array, array, 0f, (0f - entity.CollisionBox.Y2) / 2f, 0f);
				Mat4f.Scale(array, array, new float[3] { size, size, size });
				Mat4f.Translate(array, array, -0.5f, 0f, -0.5f);
				tmpModelMat.Set(array).Mul(attachmentPointAndPose.AnimModelMatrix).Translate(attachPoint.PosX / 16.0, attachPoint.PosY / 16.0, attachPoint.PosZ / 16.0);
				EntityPos sidedPos = entity.SidedPos;
				float[] array4 = Mat4f.MulWithVec4(tmpModelMat.Values, vec);
				float num4 = array4[0] - (entity.CollisionBox.X1 - entity.OriginCollisionBox.X1);
				float num5 = array4[2] - (entity.CollisionBox.Z1 - entity.OriginCollisionBox.Z1);
				if ((double)Math.Abs(num4) > 1E-05 || (double)Math.Abs(num5) > 1E-05)
				{
					EntityPos entityPos = sidedPos.Copy();
					entityPos.Motion.X = num4;
					entityPos.Motion.Z = num5;
					moveDelta.Set(entityPos.Motion.X, entityPos.Motion.Y, entityPos.Motion.Z);
					PhysicsBehaviorBase.collisionTester.ApplyTerrainCollision(entity, entityPos, dtFac, ref newPos);
					double x = (newPos.X - sidedPos.X) / (double)dtFac - (double)num4;
					double z = (newPos.Z - sidedPos.Z) / (double)dtFac - (double)num5;
					sidedPos.Motion.X = x;
					sidedPos.Motion.Z = z;
					entity.CollisionBox.Set(entity.OriginCollisionBox);
					entity.CollisionBox.Translate(array4[0], 0f, array4[2]);
					entity.SelectionBox.Set(entity.OriginSelectionBox);
					entity.SelectionBox.Translate(array4[0], 0f, array4[2]);
				}
			}
		}

		protected void callOnEntityInside()
		{
			EntityPos serverPos = entity.ServerPos;
			IWorldAccessor world = entity.World;
			Cuboidd cuboidd = PhysicsBehaviorBase.collisionTester.entityBox;
			cuboidd.SetAndTranslate(entity.CollisionBox, serverPos.X, serverPos.Y, serverPos.Z);
			cuboidd.RemoveRoundingErrors();
			BlockPos minPos = new BlockPos((int)cuboidd.X1, (int)cuboidd.Y1, (int)cuboidd.Z1, serverPos.Dimension);
			BlockPos maxPos = new BlockPos((int)cuboidd.X2, (int)cuboidd.Y2, (int)cuboidd.Z2, serverPos.Dimension);
			world.BlockAccessor.WalkBlocks(minPos, maxPos, delegate(Block block, int x, int y, int z)
			{
				if (block.Id != 0)
				{
					minPos.Set(x, y, z);
					block.OnEntityInside(world, entity, minPos);
				}
			});
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			if (sapi != null)
			{
				sapi.Server.RemovePhysicsTickable(this);
			}
		}

		public override string PropertyName()
		{
			return "entitycontrolledphysics";
		}
	}
	public class EntityBehaviorDeadDecay : EntityBehavior
	{
		private ITreeAttribute decayTree;

		private JsonObject typeAttributes;

		public float HoursToDecay { get; set; }

		public double TotalHoursDead
		{
			get
			{
				return decayTree.GetDouble("totalHoursDead");
			}
			set
			{
				decayTree.SetDouble("totalHoursDead", value);
			}
		}

		public EntityBehaviorDeadDecay(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			base.Initialize(properties, typeAttributes);
			(entity as EntityAgent).AllowDespawn = false;
			this.typeAttributes = typeAttributes;
			HoursToDecay = typeAttributes["hoursToDecay"].AsFloat(96f);
			decayTree = entity.WatchedAttributes.GetTreeAttribute("decay");
			if (decayTree == null)
			{
				entity.WatchedAttributes.SetAttribute("decay", decayTree = new TreeAttribute());
				TotalHoursDead = entity.World.Calendar.TotalHours;
			}
		}

		public override void OnGameTick(float deltaTime)
		{
			if (!entity.Alive && TotalHoursDead + (double)HoursToDecay < entity.World.Calendar.TotalHours)
			{
				DecayNow();
			}
			base.OnGameTick(deltaTime);
		}

		public void DecayNow()
		{
			if ((entity as EntityAgent).AllowDespawn)
			{
				return;
			}
			(entity as EntityAgent).AllowDespawn = true;
			if (entity.DespawnReason == null)
			{
				entity.DespawnReason = new EntityDespawnData
				{
					DamageSourceForDeath = null,
					Reason = EnumDespawnReason.Death
				};
			}
			if (typeAttributes["decayedBlock"].Exists)
			{
				AssetLocation blockCode = new AssetLocation(typeAttributes["decayedBlock"].AsString());
				Block block = entity.World.GetBlock(blockCode);
				double num = entity.ServerPos.X + (double)entity.SelectionBox.X1 - (double)entity.OriginSelectionBox.X1;
				double num2 = entity.ServerPos.Y + (double)entity.SelectionBox.Y1 - (double)entity.OriginSelectionBox.Y1;
				double num3 = entity.ServerPos.Z + (double)entity.SelectionBox.Z1 - (double)entity.OriginSelectionBox.Z1;
				BlockPos pos = new BlockPos((int)num, (int)num2, (int)num3);
				IBlockAccessor blockAccessor = entity.World.BlockAccessor;
				if (blockAccessor.GetBlock(pos).IsReplacableBy(block))
				{
					blockAccessor.SetBlock(block.BlockId, pos);
					blockAccessor.MarkBlockDirty(pos);
				}
				else
				{
					BlockFacing[] hORIZONTALS = BlockFacing.HORIZONTALS;
					for (int i = 0; i < hORIZONTALS.Length; i++)
					{
						hORIZONTALS[i].IterateThruFacingOffsets(pos);
						if (entity.World.BlockAccessor.GetBlock(pos).IsReplacableBy(block))
						{
							entity.World.BlockAccessor.SetBlock(block.BlockId, pos);
							break;
						}
					}
				}
			}
			Vec3d vec3d = entity.SidedPos.XYZ + entity.CollisionBox.Center - entity.OriginCollisionBox.Center;
			vec3d.Y += entity.Properties.DeadCollisionBoxSize.Y / 2f;
			entity.World.SpawnParticles(new EntityCubeParticles(entity.World, entity.EntityId, vec3d, 0.15f, (int)(40f + entity.Properties.DeadCollisionBoxSize.X * 60f), 0.4f, 1f));
		}

		public override void OnEntityDeath(DamageSource damageSourceForDeath)
		{
			base.OnEntityDeath(damageSourceForDeath);
			TotalHoursDead = entity.World.Calendar.TotalHours;
			if (damageSourceForDeath != null && damageSourceForDeath.Source == EnumDamageSource.Void)
			{
				(entity as EntityAgent).AllowDespawn = true;
			}
		}

		public override string PropertyName()
		{
			return "deaddecay";
		}
	}
	public class EntityBehaviorDespawn : EntityBehavior, ITimedDespawn
	{
		private float minPlayerDistance = -1f;

		private float belowLightLevel = -1f;

		private float minSeconds = 30f;

		private float accumSeconds;

		private float accumOffset = 2.5f;

		private EnumDespawnMode despawnMode;

		private float deathTimeLocal;

		public float DeathTime
		{
			get
			{
				float? num = entity.Attributes.TryGetFloat("deathTime");
				return deathTimeLocal = ((!num.HasValue) ? 0f : num.Value);
			}
			set
			{
				if (value != deathTimeLocal)
				{
					entity.Attributes.SetFloat("deathTime", value);
					deathTimeLocal = value;
				}
			}
		}

		public float DespawnSeconds
		{
			get
			{
				return minSeconds;
			}
			set
			{
				minSeconds = value;
			}
		}

		public EntityBehaviorDespawn(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			JsonObject jsonObject = typeAttributes["minPlayerDistance"];
			minPlayerDistance = (jsonObject.Exists ? jsonObject.AsFloat() : (-1f));
			JsonObject jsonObject2 = typeAttributes["belowLightLevel"];
			belowLightLevel = (jsonObject2.Exists ? jsonObject2.AsFloat() : (-1f));
			int num = entity.Attributes.GetInt("minsecondsToDespawn");
			if (num > 0)
			{
				minSeconds = num;
			}
			else
			{
				minSeconds = typeAttributes["minSeconds"].AsFloat(30f);
				minSeconds += (float)((double)entity.EntityId / 5.0 % (double)(minSeconds / 20f));
			}
			JsonObject jsonObject3 = typeAttributes["afterDays"];
			if (entity.WatchedAttributes.HasAttribute("despawnTotalDays"))
			{
				despawnMode = (jsonObject3.Exists ? EnumDespawnMode.AfterSecondsOrAfterDays : EnumDespawnMode.AfterSecondsOrAfterDaysIgnorePlayer);
			}
			else if (jsonObject3.Exists)
			{
				despawnMode = EnumDespawnMode.AfterSecondsOrAfterDays;
				entity.WatchedAttributes.SetDouble("despawnTotalDays", entity.World.Calendar.TotalDays + (double)jsonObject3.AsFloat(14f));
			}
			accumOffset += (float)((double)entity.EntityId / 200.0 % 1.0);
			deathTimeLocal = DeathTime;
		}

		public override void OnGameTick(float deltaTime)
		{
			if (!entity.Alive || entity.World.Side == EnumAppSide.Client)
			{
				return;
			}
			deltaTime = (float)Math.Min(deltaTime, 0.2);
			if (!((accumSeconds += deltaTime) > accumOffset))
			{
				return;
			}
			if (despawnMode == EnumDespawnMode.AfterSecondsOrAfterDaysIgnorePlayer && entity.World.Calendar.TotalDays > entity.WatchedAttributes.GetDouble("despawnTotalDays"))
			{
				entity.Die(EnumDespawnReason.Expire);
				accumSeconds = 0f;
				return;
			}
			bool flag = PlayerInRange();
			if (flag || LightLevelOk())
			{
				accumSeconds = 0f;
				DeathTime = 0f;
			}
			else if (despawnMode == EnumDespawnMode.AfterSecondsOrAfterDays && !flag && entity.World.Calendar.TotalDays > entity.WatchedAttributes.GetDouble("despawnTotalDays"))
			{
				entity.Die(EnumDespawnReason.Expire);
				accumSeconds = 0f;
			}
			else if ((DeathTime += accumSeconds) > minSeconds)
			{
				entity.Die(EnumDespawnReason.Expire);
				accumSeconds = 0f;
			}
			else
			{
				accumSeconds = 0f;
			}
		}

		public bool PlayerInRange()
		{
			if (minPlayerDistance < 0f)
			{
				return false;
			}
			return entity.NearestPlayerDistance < minPlayerDistance;
		}

		public bool LightLevelOk()
		{
			if (belowLightLevel < 0f)
			{
				return false;
			}
			EntityPos serverPos = entity.ServerPos;
			return (float)entity.World.BlockAccessor.GetLightLevel((int)serverPos.X, (int)serverPos.Y, (int)serverPos.Z, EnumLightLevelType.MaxLight) >= belowLightLevel;
		}

		public override string PropertyName()
		{
			return "timeddespawn";
		}

		public override void GetInfoText(StringBuilder infotext)
		{
			if (belowLightLevel >= 0f && !LightLevelOk() && entity.Alive)
			{
				infotext.AppendLine(Lang.Get("Deprived of light, might die soon"));
			}
			base.GetInfoText(infotext);
		}

		public void SetDespawnByCalendarDate(double totaldays)
		{
			entity.WatchedAttributes.SetDouble("despawnTotalDays", totaldays);
			despawnMode = EnumDespawnMode.AfterSecondsOrAfterDaysIgnorePlayer;
		}
	}
	internal enum EnumDespawnMode
	{
		AfterSeconds,
		AfterSecondsOrAfterDays,
		AfterSecondsOrAfterDaysIgnorePlayer
	}
	public class EntityBehaviorDrunkTyping : EntityBehavior
	{
		private ICoreAPI api;

		private bool isCommand;

		public EntityBehaviorDrunkTyping(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			api = entity.World.Api;
		}

		public override void OnEntityLoaded()
		{
			if (entity.Api is ICoreClientAPI coreClientAPI && (entity as EntityPlayer)?.PlayerUID == coreClientAPI.Settings.String["playeruid"])
			{
				coreClientAPI.Event.RegisterEventBusListener(onChatKeyDownPre, 1.0, "chatkeydownpre");
				coreClientAPI.Event.RegisterEventBusListener(onChatKeyDownPost, 1.0, "chatkeydownpost");
			}
		}

		public override string PropertyName()
		{
			return "drunktyping";
		}

		private void onChatKeyDownPre(string eventName, ref EnumHandling handling, IAttribute data)
		{
			string value = ((data as TreeAttribute)["text"] as StringAttribute).value;
			isCommand = value.Length > 0 && (value[0] == '.' || value[0] == '/');
		}

		private void onChatKeyDownPost(string eventName, ref EnumHandling handling, IAttribute data)
		{
			TreeAttribute treeAttribute = data as TreeAttribute;
			int value = (treeAttribute["key"] as IntAttribute).value;
			string value2 = (treeAttribute["text"] as StringAttribute).value;
			int caretPos = 0;
			if (isCommand && value2.Length > 0 && value2[0] != '.' && value2[0] != '/')
			{
				string text = value2[0].ToString() ?? "";
				for (int i = 1; i < value2.Length; i++)
				{
					text = slurText(text, ref caretPos);
					text += value2[i];
				}
				value2 = text;
				(treeAttribute["text"] as StringAttribute).value = value2;
			}
			else if (value != 53 && value != 47 && value != 48 && value != 55 && value != 5 && value != 3 && value2.Length > 0 && value2[0] != '.' && value2[0] != '/')
			{
				value2 = slurText(value2, ref caretPos);
				(treeAttribute["text"] as StringAttribute).value = value2;
			}
			treeAttribute.SetInt("deltacaretpos", caretPos);
		}

		private string slurText(string text, ref int caretPos)
		{
			Random rand = api.World.Rand;
			float num = entity.WatchedAttributes.GetFloat("intoxication");
			if (rand.NextDouble() < (double)num)
			{
				switch (rand.Next(9))
				{
				case 0:
				case 1:
					if (text.Length > 1)
					{
						text = text.Substring(0, text.Length - 2) + text[text.Length - 1] + text[text.Length - 2];
					}
					break;
				case 2:
				case 3:
				case 4:
					if (text.Length > 0)
					{
						text += text[text.Length - 1];
						caretPos++;
					}
					break;
				case 5:
				case 6:
				{
					if (text.Length <= 0)
					{
						break;
					}
					string[] array = new string[4] { "1234567890-", "qwertyuiop[", "asdfghjkl;", "zxcvbnm,." };
					char value = text[text.Length - 1];
					for (int i = 0; i < 3; i++)
					{
						int num2 = array[i].IndexOf(value);
						if (num2 >= 0)
						{
							int num3 = rand.Next(2) * 2 - 1;
							text += array[i][GameMath.Clamp(num2 + num3, 0, array[i].Length - 1)];
							caretPos++;
						}
					}
					break;
				}
				}
			}
			return text;
		}
	}
	public enum EnumAccumType
	{
		Sum,
		Max,
		NoAccum
	}
	public class EmotionState
	{
		public string Code = "";

		public float Duration;

		public float Chance;

		public int Slot;

		public float Priority;

		public float StressLevel;

		public int MaxGeneration = int.MaxValue;

		public EnumAccumType AccumType = EnumAccumType.Max;

		public float whenHealthRelBelow = 999f;

		public bool whenSourceUntargetable;

		public string[] NotifyEntityCodes = Array.Empty<string>();

		public string[] EntityCodes;

		public AssetLocation[] EntityCodeLocs;

		public float NotifyChances;

		public float NotifyRange = 12f;

		public float BelowTempDuration;

		public float BelowTempThreshold = -9999f;
	}
	public class ActiveEmoState
	{
		public int StateId;

		public float Duration;

		public long SourceEntityId;
	}
	public class EntityBehaviorEmotionStates : EntityBehavior
	{
		private EmotionState[] availableStates;

		public Dictionary<string, ActiveEmoState> ActiveStatesByCode = new Dictionary<string, ActiveEmoState>();

		private TreeAttribute entityAttr;

		private float healthRel;

		private float tickAccum;

		private EntityPartitioning epartSys;

		private EnumCreatureHostility _enumCreatureHostility;

		private PathfinderTask pathtask;

		private int nopathEmoStateid;

		private long sourceEntityId;

		public EntityBehaviorEmotionStates(Entity entity)
			: base(entity)
		{
			if (entity.Attributes.HasAttribute("emotionstates"))
			{
				entityAttr = entity.Attributes["emotionstates"] as TreeAttribute;
			}
			else
			{
				entity.Attributes["emotionstates"] = (entityAttr = new TreeAttribute());
			}
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			base.Initialize(properties, typeAttributes);
			JsonObject[] array = typeAttributes["states"].AsArray();
			availableStates = new EmotionState[array.Length];
			int num = 0;
			JsonObject[] array2 = array;
			for (int i = 0; i < array2.Length; i++)
			{
				EmotionState emotionState = array2[i].AsObject<EmotionState>();
				availableStates[num++] = emotionState;
				if (emotionState.EntityCodes != null)
				{
					emotionState.EntityCodeLocs = emotionState.EntityCodes.Select((string str) => new AssetLocation(str)).ToArray();
				}
			}
			tickAccum = (float)(entity.World.Rand.NextDouble() * 0.33);
			epartSys = entity.Api.ModLoader.GetModSystem<EntityPartitioning>();
			_enumCreatureHostility = entity.World.Config.GetString("creatureHostility") switch
			{
				"aggressive" => EnumCreatureHostility.Aggressive, 
				"passive" => EnumCreatureHostility.Passive, 
				"off" => EnumCreatureHostility.NeverHostile, 
				_ => EnumCreatureHostility.Aggressive, 
			};
		}

		public override void OnEntityReceiveDamage(DamageSource damageSource, ref float damage)
		{
			EntityBehaviorHealth behavior = entity.GetBehavior<EntityBehaviorHealth>();
			healthRel = ((behavior == null) ? 1f : (behavior.Health / behavior.MaxHealth));
			EnumDamageSource source = damageSource.Source;
			bool flag = (uint)(source - 2) <= 1u;
			if (flag || _enumCreatureHostility == EnumCreatureHostility.NeverHostile)
			{
				return;
			}
			Entity causeEntity = damageSource.GetCauseEntity();
			long sourceEntityId = causeEntity?.EntityId ?? 0;
			long herdId = (entity as EntityAgent).HerdId;
			if (TryTriggerState("alarmherdondamage", sourceEntityId) && causeEntity != null && herdId > 0)
			{
				EmotionState emotionState = availableStates.First((EmotionState s) => s.Code == "alarmherdondamage");
				entity.World.GetNearestEntity(entity.ServerPos.XYZ, emotionState.NotifyRange, emotionState.NotifyRange, delegate(Entity e)
				{
					EntityAgent entityAgent = e as EntityAgent;
					if (e.EntityId != entity.EntityId && entityAgent != null && entityAgent.Alive && entityAgent.HerdId == herdId)
					{
						entityAgent.GetBehavior<EntityBehaviorEmotionStates>()?.TryTriggerState("aggressiveondamage", sourceEntityId);
					}
					return false;
				});
			}
			if (TryTriggerState("aggressiveondamage", sourceEntityId))
			{
				TryTriggerState("aggressivealarmondamage", sourceEntityId);
			}
			if (TryTriggerState("fleeondamage", sourceEntityId))
			{
				TryTriggerState("fleealarmondamage", sourceEntityId);
			}
		}

		public bool IsInEmotionState(string statecode)
		{
			return ActiveStatesByCode.ContainsKey(statecode);
		}

		public void ClearStates()
		{
			ActiveStatesByCode.Clear();
		}

		public ActiveEmoState GetActiveEmotionState(string statecode)
		{
			ActiveStatesByCode.TryGetValue(statecode, out var value);
			return value;
		}

		public bool TryTriggerState(string statecode, long sourceEntityId)
		{
			return TryTriggerState(statecode, entity.World.Rand.NextDouble(), sourceEntityId);
		}

		public bool TryTriggerState(string statecode, double rndValue, long sourceEntityId)
		{
			bool result = false;
			for (int i = 0; i < availableStates.Length; i++)
			{
				EmotionState emotionState = availableStates[i];
				if (!(emotionState.Code != statecode) && !(rndValue > (double)emotionState.Chance))
				{
					if (emotionState.whenSourceUntargetable)
					{
						TryTarget(i, sourceEntityId);
					}
					else if (tryActivateState(i, sourceEntityId))
					{
						result = true;
					}
				}
			}
			return result;
		}

		private void TryTarget(int emostateid, long sourceEntityId)
		{
			if (pathtask == null)
			{
				ICoreAPI api = entity.World.Api;
				PathfindingAsync modSystem = api.ModLoader.GetModSystem<PathfindingAsync>();
				WaypointsTraverser waypointsTraverser = entity.GetBehavior<EntityBehaviorTaskAI>()?.PathTraverser;
				if (waypointsTraverser != null)
				{
					pathtask = waypointsTraverser.PreparePathfinderTask(entity.ServerPos.AsBlockPos, api.World.GetEntityById(sourceEntityId).ServerPos.AsBlockPos);
					modSystem.EnqueuePathfinderTask(pathtask);
					nopathEmoStateid = emostateid;
					this.sourceEntityId = sourceEntityId;
				}
			}
		}

		private bool tryActivateState(int stateid, long sourceEntityId)
		{
			EmotionState emotionState = availableStates[stateid];
			string code = emotionState.Code;
			ActiveEmoState activeEmoState = null;
			if (emotionState.whenHealthRelBelow < healthRel)
			{
				return false;
			}
			foreach (KeyValuePair<string, ActiveEmoState> item in ActiveStatesByCode)
			{
				if (item.Key == emotionState.Code)
				{
					activeEmoState = item.Value;
					continue;
				}
				int stateId = item.Value.StateId;
				EmotionState emotionState2 = availableStates[stateId];
				if (emotionState2.Slot != emotionState.Slot)
				{
					continue;
				}
				if (emotionState2.Priority > emotionState.Priority)
				{
					return false;
				}
				ActiveStatesByCode.Remove(item.Key);
				entityAttr.RemoveAttribute(emotionState.Code);
				break;
			}
			if (emotionState.MaxGeneration < entity.WatchedAttributes.GetInt("generation"))
			{
				return false;
			}
			if (code == "aggressivearoundentities" && (activeEmoState != null || !entitiesNearby(emotionState)))
			{
				return false;
			}
			float num = emotionState.Duration;
			if (emotionState.BelowTempThreshold > -99f && entity.World.BlockAccessor.GetClimateAt(entity.Pos.AsBlockPos, EnumGetClimateMode.ForSuppliedDate_TemperatureOnly, entity.World.Calendar.TotalDays).Temperature < emotionState.BelowTempThreshold)
			{
				num = emotionState.BelowTempDuration;
			}
			float num2 = 0f;
			if (emotionState.AccumType == EnumAccumType.Sum)
			{
				num2 = activeEmoState?.Duration ?? (0f + num);
			}
			if (emotionState.AccumType == EnumAccumType.Max)
			{
				num2 = Math.Max(activeEmoState?.Duration ?? 0f, num);
			}
			if (emotionState.AccumType == EnumAccumType.NoAccum)
			{
				num2 = ((activeEmoState == null || !(activeEmoState.Duration > 0f)) ? num : (activeEmoState?.Duration ?? 0f));
			}
			if (activeEmoState == null)
			{
				ActiveStatesByCode[emotionState.Code] = new ActiveEmoState
				{
					Duration = num2,
					SourceEntityId = sourceEntityId,
					StateId = stateid
				};
			}
			else
			{
				activeEmoState.SourceEntityId = sourceEntityId;
			}
			entityAttr.SetFloat(emotionState.Code, num2);
			return true;
		}

		public override void OnGameTick(float deltaTime)
		{
			if (pathtask != null && pathtask.Finished)
			{
				if (pathtask.waypoints == null)
				{
					tryActivateState(nopathEmoStateid, sourceEntityId);
				}
				pathtask = null;
				nopathEmoStateid = 0;
				sourceEntityId = 0L;
			}
			if ((tickAccum += deltaTime) < 0.33f)
			{
				return;
			}
			tickAccum = 0f;
			if (_enumCreatureHostility == EnumCreatureHostility.Aggressive)
			{
				TryTriggerState("aggressivearoundentities", 0L);
			}
			float num = 0f;
			List<string> list = null;
			foreach (KeyValuePair<string, ActiveEmoState> item in ActiveStatesByCode)
			{
				string key = item.Key;
				ActiveEmoState value = item.Value;
				if ((value.Duration -= 10f * deltaTime) <= 0f)
				{
					if (list == null)
					{
						list = new List<string>();
					}
					list.Add(key);
					entityAttr.RemoveAttribute(key);
				}
				else
				{
					num += availableStates[value.StateId].StressLevel;
				}
			}
			if (list != null)
			{
				foreach (string item2 in list)
				{
					ActiveStatesByCode.Remove(item2);
				}
			}
			float num2 = entity.WatchedAttributes.GetFloat("stressLevel");
			if (num > 0f)
			{
				entity.WatchedAttributes.SetFloat("stressLevel", Math.Max(num2, num));
			}
			else if (num2 > 0f)
			{
				num2 = Math.Max(0f, num2 - deltaTime * 1.25f);
				entity.WatchedAttributes.SetFloat("stressLevel", num2);
			}
			if (entity.World.EntityDebugMode)
			{
				entity.DebugAttributes.SetString("emotionstates", string.Join(", ", ActiveStatesByCode.Keys.ToList()));
			}
		}

		private bool entitiesNearby(EmotionState newstate)
		{
			return epartSys.GetNearestEntity(entity.ServerPos.XYZ, newstate.NotifyRange, delegate(Entity e)
			{
				if (newstate.EntityCodeLocs == null)
				{
					return false;
				}
				for (int i = 0; i < newstate.EntityCodeLocs.Length; i++)
				{
					if (newstate.EntityCodeLocs[i].Equals(e.Code))
					{
						return e.IsInteractable;
					}
				}
				return false;
			}, EnumEntitySearchType.Creatures) != null;
		}

		public override string PropertyName()
		{
			return "emotionstates";
		}
	}
	public class EntityBehaviorEntityStateTags : EntityBehavior
	{
		protected bool Swimming;

		protected bool FeetInLiquid;

		protected bool OnGround;

		protected bool Flying;

		protected bool Aiming;

		protected bool Moving;

		protected bool Alive;

		protected bool Sprinting;

		protected bool Sneaking;

		protected bool Armed;

		protected bool ArmedMelee;

		protected bool ArmedRanged;

		protected bool HoldingOpenFire;

		protected static EntityTagArray TagSwimming = EntityTagArray.Empty;

		protected static EntityTagArray TagFeetInLiquid = EntityTagArray.Empty;

		protected static EntityTagArray TagFlying = EntityTagArray.Empty;

		protected static EntityTagArray TagOnGround = EntityTagArray.Empty;

		protected static EntityTagArray TagMoving = EntityTagArray.Empty;

		protected static EntityTagArray TagAlive = EntityTagArray.Empty;

		protected static EntityTagArray TagAiming = EntityTagArray.Empty;

		protected static EntityTagArray TagSprinting = EntityTagArray.Empty;

		protected static EntityTagArray TagSneaking = EntityTagArray.Empty;

		protected static EntityTagArray TagArmed = EntityTagArray.Empty;

		protected static EntityTagArray TagArmedMelee = EntityTagArray.Empty;

		protected static EntityTagArray TagArmedRanged = EntityTagArray.Empty;

		protected static EntityTagArray TagHoldingOpenFire = EntityTagArray.Empty;

		protected static ItemTagArray ItemTagWeapon = ItemTagArray.Empty;

		protected static ItemTagArray ItemTagWeaponMelee = ItemTagArray.Empty;

		protected static ItemTagArray ItemTagWeaponRanged = ItemTagArray.Empty;

		protected static ItemTagArray ItemTagHasOpenFire = ItemTagArray.Empty;

		protected static BlockTagArray BlockTagHasOpenFire = BlockTagArray.Empty;

		protected float TimeSinceUpdateSec;

		protected float UpdatePeriodSec = 1f;

		public EntityBehaviorEntityStateTags(Entity entity)
			: base(entity)
		{
		}

		public override string PropertyName()
		{
			return "entityStateTags";
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			if (attributes.KeyExists("updatePeriodSec"))
			{
				UpdatePeriodSec = attributes["updatePeriodSec"].AsFloat(UpdatePeriodSec);
			}
			EntityTagArray tags = entity.Tags;
			TagsInitialUpdate(ref tags);
			if (entity.Tags != tags)
			{
				entity.Tags = tags;
				entity.MarkTagsDirty();
			}
			TimeSinceUpdateSec = (float)entity.World.Rand.NextDouble() * UpdatePeriodSec;
		}

		public override void OnGameTick(float deltaTime)
		{
			if (entity.Api.Side != EnumAppSide.Server)
			{
				return;
			}
			TimeSinceUpdateSec += deltaTime;
			if (!(TimeSinceUpdateSec < UpdatePeriodSec))
			{
				TimeSinceUpdateSec = 0f;
				EntityTagArray tags = entity.Tags;
				TagsUpdate(ref tags);
				if (entity.Tags != tags)
				{
					entity.Tags = tags;
					entity.MarkTagsDirty();
				}
				entity.World.FrameProfiler.Mark("statetagsupdate");
			}
		}

		public static void GetTagsIds(ITagRegistry registry)
		{
			TagSwimming = new EntityTagArray(registry.EntityTagToTagId("state-swimming"));
			TagFeetInLiquid = new EntityTagArray(registry.EntityTagToTagId("state-feet-in-liquid"));
			TagFlying = new EntityTagArray(registry.EntityTagToTagId("state-flying"));
			TagOnGround = new EntityTagArray(registry.EntityTagToTagId("state-on-ground"));
			TagMoving = new EntityTagArray(registry.EntityTagToTagId("state-moving"));
			TagAlive = new EntityTagArray(registry.EntityTagToTagId("state-alive"));
			TagAiming = new EntityTagArray(registry.EntityTagToTagId("state-aiming"));
			TagSprinting = new EntityTagArray(registry.EntityTagToTagId("state-sprinting"));
			TagSneaking = new EntityTagArray(registry.EntityTagToTagId("state-sneaking"));
			TagArmed = new EntityTagArray(registry.EntityTagToTagId("state-armed"));
			TagArmedMelee = new EntityTagArray(registry.EntityTagToTagId("state-armed-melee"));
			TagArmedRanged = new EntityTagArray(registry.EntityTagToTagId("state-armed-ranged"));
			ItemTagWeapon = new ItemTagArray(registry.ItemTagToTagId("weapon"));
			ItemTagWeaponMelee = new ItemTagArray(registry.ItemTagToTagId("weapon-melee"));
			ItemTagWeaponRanged = new ItemTagArray(registry.ItemTagToTagId("weapon-ranged"));
			ItemTagHasOpenFire = new ItemTagArray(registry.ItemTagToTagId("has-open-fire"));
			BlockTagHasOpenFire = new BlockTagArray(registry.BlockTagToTagId("has-open-fire"));
		}

		protected virtual void TagsInitialUpdate(ref EntityTagArray tags)
		{
			EntityTagsInitialUpdate(ref tags);
			if (entity is EntityAgent entityAgent)
			{
				EntityAgentTagsInitialUpdate(entityAgent, ref tags);
				EntityAgentHandItemsTagsInitialUpdate(entityAgent, ref tags);
			}
		}

		protected virtual void TagsUpdate(ref EntityTagArray tags)
		{
			EntityTagsUpdate(ref tags);
			if (entity is EntityAgent entityAgent)
			{
				EntityAgentTagsUpdate(entityAgent, ref tags);
				EntityAgentHandItemsTagsUpdate(entityAgent, ref tags);
			}
		}

		protected virtual void EntityTagsInitialUpdate(ref EntityTagArray tags)
		{
			tags = tags.Remove(TagSwimming);
			tags = tags.Remove(TagFeetInLiquid);
			tags = tags.Remove(TagOnGround);
			tags = tags.Remove(TagAlive);
			EntityTagsUpdate(ref tags);
		}

		protected virtual void EntityAgentTagsInitialUpdate(EntityAgent entityAgent, ref EntityTagArray tags)
		{
			tags = tags.Remove(TagMoving);
			tags = tags.Remove(TagAiming);
			tags = tags.Remove(TagFlying);
			tags = tags.Remove(TagSneaking);
			tags = tags.Remove(TagSprinting);
			EntityAgentTagsUpdate(entityAgent, ref tags);
		}

		protected virtual void EntityAgentHandItemsTagsInitialUpdate(EntityAgent entityAgent, ref EntityTagArray tags)
		{
			ItemStack itemStack = entityAgent.RightHandItemSlot?.Itemstack;
			ItemTagArray itemTagArray = itemStack?.Item?.Tags ?? ItemTagArray.Empty;
			BlockTagArray blockTagArray = itemStack?.Block?.Tags ?? BlockTagArray.Empty;
			itemStack = entityAgent.LeftHandItemSlot?.Itemstack;
			if (itemStack?.Item != null)
			{
				itemTagArray |= itemStack.Item.Tags;
			}
			if (itemStack?.Block != null)
			{
				blockTagArray |= itemStack.Block.Tags;
			}
			InitializeTag(ref tags, Armed = itemTagArray.ContainsAll(ItemTagWeapon), TagArmed);
			InitializeTag(ref tags, ArmedMelee = itemTagArray.ContainsAll(ItemTagWeaponMelee), TagArmedMelee);
			InitializeTag(ref tags, ArmedRanged = itemTagArray.ContainsAll(ItemTagWeaponRanged), TagArmedRanged);
			InitializeTag(ref tags, HoldingOpenFire = itemTagArray.ContainsAll(ItemTagHasOpenFire) || blockTagArray.ContainsAll(BlockTagHasOpenFire), TagHoldingOpenFire);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		protected virtual void UpdateTag(ref EntityTagArray tags, ref bool storedValue, EntityTagArray mask, bool newValue)
		{
			if (storedValue != newValue)
			{
				storedValue = newValue;
				if (newValue)
				{
					tags |= mask;
				}
				else
				{
					tags &= ~mask;
				}
			}
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		protected virtual void InitializeTag(ref EntityTagArray tags, bool newValue, EntityTagArray mask)
		{
			if (newValue)
			{
				tags |= mask;
			}
			else
			{
				tags &= ~mask;
			}
		}

		protected virtual void EntityTagsUpdate(ref EntityTagArray tags)
		{
			UpdateTag(ref tags, ref Swimming, TagSwimming, entity.Swimming);
			UpdateTag(ref tags, ref FeetInLiquid, TagFeetInLiquid, entity.FeetInLiquid && !Swimming);
			UpdateTag(ref tags, ref OnGround, TagOnGround, entity.OnGround);
			UpdateTag(ref tags, ref Alive, TagAlive, entity.Alive);
		}

		protected virtual void EntityAgentTagsUpdate(EntityAgent entityAgent, ref EntityTagArray tags)
		{
			EntityControls controls = entityAgent.Controls;
			UpdateTag(ref tags, ref Moving, TagMoving, controls.Forward || controls.Backward || controls.Right || controls.Left || controls.Jump || controls.Gliding);
			UpdateTag(ref tags, ref Aiming, TagAiming, controls.IsAiming);
			UpdateTag(ref tags, ref Flying, TagFlying, controls.IsFlying);
			UpdateTag(ref tags, ref Sneaking, TagSneaking, controls.Sneak);
			UpdateTag(ref tags, ref Sprinting, TagSprinting, controls.Sprint);
		}

		protected virtual void EntityAgentHandItemsTagsUpdate(EntityAgent entityAgent, ref EntityTagArray tags)
		{
			ItemStack obj = entityAgent.ActiveHandItemSlot?.Itemstack;
			Item item = obj?.Item;
			if (item == null)
			{
				UpdateTag(ref tags, ref Armed, TagArmed, newValue: false);
				UpdateTag(ref tags, ref ArmedMelee, TagArmedMelee, newValue: false);
				UpdateTag(ref tags, ref ArmedRanged, TagArmedRanged, newValue: false);
			}
			else
			{
				UpdateTag(ref tags, ref Armed, TagArmed, ItemTagWeapon.isPresentIn(ref item.Tags));
				UpdateTag(ref tags, ref ArmedMelee, TagArmedMelee, ItemTagWeaponMelee.isPresentIn(ref item.Tags));
				UpdateTag(ref tags, ref ArmedRanged, TagArmedRanged, ItemTagWeaponRanged.isPresentIn(ref item.Tags));
			}
			Block block = obj?.Block;
			UpdateTag(ref tags, ref HoldingOpenFire, TagHoldingOpenFire, (item != null && ItemTagHasOpenFire.isPresentIn(ref item.Tags)) || (block != null && BlockTagHasOpenFire.isPresentIn(ref block.Tags)));
		}
	}
	public class EntityBehaviorFloatUpWhenStuck : EntityBehavior
	{
		private bool onlyWhenDead;

		private int counter;

		private bool stuckInBlock;

		private float pushVelocityMul = 1f;

		private Vec3d tmpPos = new Vec3d();

		public EntityBehaviorFloatUpWhenStuck(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
			onlyWhenDead = attributes["onlyWhenDead"].AsBool();
			pushVelocityMul = attributes["pushVelocityMul"].AsFloat(1f);
			counter = (int)entity.EntityId / 10 % 10;
		}

		public override void OnTesselated()
		{
			base.OnTesselated();
			ensureCenterAPExists();
		}

		private void ensureCenterAPExists()
		{
			if (entity.AnimManager != null && entity.World.Side == EnumAppSide.Client && entity.AnimManager.Animator?.GetAttachmentPointPose("Center") == null)
			{
				HashSet<AssetLocation> orCreate = ObjectCacheUtil.GetOrCreate(entity.Api, "missingCenterApEntityCodes", () => new HashSet<AssetLocation>());
				if (!orCreate.Contains(entity.Code))
				{
					orCreate.Add(entity.Code);
					entity.World.Logger.Warning(string.Concat("Entity ", entity.Code, " with shape ", entity.Properties.Client.Shape?.ToString(), " seems to be missing attachment point center but also has the FloatUpWhenStuck behavior - it might not work correctly with the center point lacking"));
				}
			}
		}

		public override void OnGameTick(float deltaTime)
		{
			if (entity.World.ElapsedMilliseconds < 2000 || entity.World.Side == EnumAppSide.Client || (counter++ <= 10 && (!stuckInBlock || counter <= 1)))
			{
				return;
			}
			counter = 0;
			if ((onlyWhenDead && entity.Alive) || entity.Properties.CanClimbAnywhere)
			{
				return;
			}
			stuckInBlock = false;
			entity.Properties.Habitat = EnumHabitat.Land;
			if (!entity.Swimming)
			{
				tmpPos.Set(entity.SidedPos.X, entity.SidedPos.Y, entity.SidedPos.Z);
				Cuboidd collidingCollisionBox = entity.World.CollisionTester.GetCollidingCollisionBox(entity.World.BlockAccessor, entity.CollisionBox.Clone().ShrinkBy(0.01f), tmpPos, alsoCheckTouch: false);
				if (collidingCollisionBox != null)
				{
					PushoutOfCollisionbox(deltaTime, collidingCollisionBox);
					stuckInBlock = true;
				}
			}
		}

		private void PushoutOfCollisionbox(float dt, Cuboidd collBox)
		{
			double x = entity.SidedPos.X;
			double y = entity.SidedPos.Y;
			double z = entity.SidedPos.Z;
			IBlockAccessor blockAccessor = entity.World.BlockAccessor;
			Vec3i vec3i = null;
			double num = 99.0;
			for (int i = 0; i < Cardinal.ALL.Length; i++)
			{
				if (num <= 0.25)
				{
					break;
				}
				Cardinal cardinal = Cardinal.ALL[i];
				for (int j = 1; j <= 4; j++)
				{
					float num2 = (float)j / 4f;
					if (!entity.World.CollisionTester.IsColliding(blockAccessor, entity.CollisionBox, tmpPos.Set(x + (double)((float)cardinal.Normali.X * num2), y, z + (double)((float)cardinal.Normali.Z * num2)), alsoCheckTouch: false) && (double)num2 < num)
					{
						num = num2 + (cardinal.IsDiagnoal ? 0.1f : 0f);
						vec3i = cardinal.Normali;
						break;
					}
				}
			}
			if (vec3i == null)
			{
				vec3i = BlockFacing.UP.Normali;
			}
			dt = Math.Min(dt, 0.1f);
			float num3 = ((float)entity.World.Rand.NextDouble() - 0.5f) / 600f;
			float num4 = ((float)entity.World.Rand.NextDouble() - 0.5f) / 600f;
			entity.SidedPos.X += (float)vec3i.X * dt * 0.4f;
			entity.SidedPos.Y += (float)vec3i.Y * dt * 0.4f;
			entity.SidedPos.Z += (float)vec3i.Z * dt * 0.4f;
			entity.SidedPos.Motion.X = pushVelocityMul * (float)vec3i.X * dt + num3;
			entity.SidedPos.Motion.Y = pushVelocityMul * (float)vec3i.Y * dt * 2f;
			entity.SidedPos.Motion.Z = pushVelocityMul * (float)vec3i.Z * dt + num4;
			entity.Properties.Habitat = EnumHabitat.Air;
		}

		public override string PropertyName()
		{
			return "floatupwhenstuck";
		}
	}
	public record GaitMeta
	{
		public required string Code { get; set; }

		public float YawMultiplier { get; set; } = 3.5f;

		public float MoveSpeed { get; set; }

		public bool Backwards { get; set; }

		public float StaminaCost { get; set; }

		public string? FallbackGaitCode { get; set; }

		public bool IsSprint { get; set; }

		public required AssetLocation Sound { get; set; }

		[CompilerGenerated]
		[SetsRequiredMembers]
		protected GaitMeta(GaitMeta original)
		{
			Code = original.Code;
			YawMultiplier = original.YawMultiplier;
			MoveSpeed = original.MoveSpeed;
			Backwards = original.Backwards;
			StaminaCost = original.StaminaCost;
			FallbackGaitCode = original.FallbackGaitCode;
			IsSprint = original.IsSprint;
			Sound = original.Sound;
		}

		public GaitMeta()
		{
		}
	}
	public class EntityBehaviorGait : EntityBehavior
	{
		public readonly FastSmallDictionary<string, GaitMeta> Gaits = new FastSmallDictionary<string, GaitMeta>(1);

		public GaitMeta IdleGait;

		protected ICoreAPI? api;

		public GaitMeta CurrentGait
		{
			get
			{
				return Gaits[entity.WatchedAttributes.GetString("currentgait")];
			}
			set
			{
				entity.WatchedAttributes.SetString("currentgait", value.Code);
			}
		}

		public GaitMeta FallbackGait
		{
			get
			{
				if (CurrentGait.FallbackGaitCode != null)
				{
					return Gaits[CurrentGait.FallbackGaitCode];
				}
				return IdleGait;
			}
		}

		public bool IsIdle => IsIdleGait(CurrentGait);

		public bool IsBackward => IsBackwards(CurrentGait);

		public bool IsForward => IsForwards(CurrentGait);

		public override string PropertyName()
		{
			return "gait";
		}

		public float GetYawMultiplier()
		{
			return CurrentGait?.YawMultiplier ?? 3.5f;
		}

		public virtual void SetIdle()
		{
			CurrentGait = IdleGait;
		}

		public virtual bool IsIdleGait(GaitMeta gait)
		{
			return gait == IdleGait;
		}

		public bool IsBackwards(GaitMeta gait)
		{
			return gait.Backwards;
		}

		public bool IsForwards(GaitMeta gait)
		{
			if (!gait.Backwards)
			{
				return gait != IdleGait;
			}
			return false;
		}

		public GaitMeta CascadingFallbackGait(int n)
		{
			GaitMeta gaitMeta = CurrentGait;
			while (n > 0)
			{
				if (gaitMeta.FallbackGaitCode == null)
				{
					return IdleGait;
				}
				gaitMeta = Gaits[gaitMeta.FallbackGaitCode];
				n--;
			}
			return gaitMeta;
		}

		public EntityBehaviorGait(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
			api = entity.Api;
			GaitMeta[] array = attributes["gaits"].AsArray<GaitMeta>();
			foreach (GaitMeta gaitMeta in array)
			{
				Gaits[gaitMeta.Code] = gaitMeta;
			}
			string key = attributes["idleGait"].AsString("idle");
			if (!Gaits.TryGetValue(key, out IdleGait))
			{
				throw new ArgumentException("JSON error. No idle gait for {0}", entity.Code);
			}
			CurrentGait = IdleGait;
		}
	}
	public class EntityBehaviorGrow : EntityBehavior
	{
		private ITreeAttribute growTree;

		private long callbackId;

		public AssetLocation[] AdultEntityCodes;

		public AssetLocation[] FedAdultEntityCodes;

		public float HoursToGrow { get; set; }

		public float OrPortionsEatenForGrowing { get; set; }

		protected double SpawnedTotalHours
		{
			get
			{
				return growTree.GetDouble("timeSpawned");
			}
			set
			{
				growTree.SetDouble("timeSpawned", value);
			}
		}

		public EntityBehaviorGrow(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			base.Initialize(properties, typeAttributes);
			AdultEntityCodes = AssetLocation.toLocations(typeAttributes["adultEntityCodes"].AsArray(Array.Empty<string>()));
			FedAdultEntityCodes = AssetLocation.toLocations(typeAttributes["fedAdultEntityCodes"].AsArray(Array.Empty<string>()));
			HoursToGrow = typeAttributes["hoursToGrow"].AsFloat(96f);
			OrPortionsEatenForGrowing = typeAttributes["orPortionsEatenForGrowing"].AsFloat(12f);
			growTree = entity.WatchedAttributes.GetTreeAttribute("grow");
			if (growTree == null && entity.Api.Side == EnumAppSide.Server)
			{
				entity.WatchedAttributes.SetAttribute("grow", growTree = new TreeAttribute());
				SpawnedTotalHours = entity.World.Calendar.TotalHours;
			}
			if (FedAdultEntityCodes.Length != 0)
			{
				double? num2;
				double? num = (num2 = entity.Attributes.TryGetDouble("totalDaysReleased"));
				if (num.HasValue)
				{
					double num3 = 216f * (OrPortionsEatenForGrowing - (entity.WatchedAttributes.GetTreeAttribute("hunger")?.TryGetFloat("saturation")).GetValueOrDefault());
					double num4 = num2.Value * (double)entity.World.Calendar.HoursPerDay + num3 - (double)HoursToGrow;
					if (SpawnedTotalHours < num4)
					{
						SpawnedTotalHours = num4;
					}
				}
			}
			callbackId = entity.World.RegisterCallback(CheckGrowth, 3000);
		}

		private void CheckGrowth(float dt)
		{
			callbackId = 0L;
			if (!base.entity.Alive)
			{
				return;
			}
			ITreeAttribute treeAttribute = base.entity.WatchedAttributes.GetTreeAttribute("hunger");
			bool flag = FedAdultEntityCodes.Length != 0 && treeAttribute != null && treeAttribute.GetFloat("saturation") >= OrPortionsEatenForGrowing;
			if (base.entity.World.Calendar.TotalHours >= SpawnedTotalHours + (double)HoursToGrow || flag)
			{
				AssetLocation[] array = (flag ? FedAdultEntityCodes : AdultEntityCodes);
				if (array.Length == 0)
				{
					return;
				}
				AssetLocation assetLocation = array[base.entity.World.Rand.Next(array.Length)];
				EntityProperties entityType = base.entity.World.GetEntityType(assetLocation);
				if (entityType == null)
				{
					base.entity.World.Logger.Error("Misconfigured entity. Entity with code '{0}' is configured (via Grow behavior) to grow into '{1}', but no such entity type was registered.", base.entity.Code, assetLocation);
					return;
				}
				Cuboidf spawnCollisionBox = entityType.SpawnCollisionBox;
				if (base.entity.World.CollisionTester.IsColliding(base.entity.World.BlockAccessor, spawnCollisionBox, base.entity.ServerPos.XYZ, alsoCheckTouch: false))
				{
					callbackId = base.entity.World.RegisterCallback(CheckGrowth, 3000);
					return;
				}
				Entity entity = base.entity.World.ClassRegistry.CreateEntity(entityType);
				entity.ServerPos.SetFrom(base.entity.ServerPos);
				entity.Pos.SetFrom(entity.ServerPos);
				bool keepTextureIndex = base.entity.Properties.Client != null && base.entity.Properties.Client.TexturesAlternatesCount > 0 && entityType.Client != null && base.entity.Properties.Client.TexturesAlternatesCount == entityType.Client.TexturesAlternatesCount;
				entity.Attributes.SetBool("wasFedToAdulthood", flag);
				BecomeAdult(entity, keepTextureIndex);
			}
			else
			{
				callbackId = base.entity.World.RegisterCallback(CheckGrowth, 3000);
				double num = base.entity.World.Calendar.TotalHours - SpawnedTotalHours;
				if (num >= 0.1 * (double)HoursToGrow)
				{
					float num2 = (float)(num / (double)HoursToGrow - 0.1);
					if (num2 >= 1.01f * growTree.GetFloat("age"))
					{
						growTree.SetFloat("age", num2);
						base.entity.WatchedAttributes.MarkPathDirty("grow");
					}
				}
			}
			base.entity.World.FrameProfiler.Mark("checkgrowth");
		}

		protected virtual void BecomeAdult(Entity adult, bool keepTextureIndex)
		{
			adult.WatchedAttributes.SetInt("generation", entity.WatchedAttributes.GetInt("generation"));
			adult.WatchedAttributes.SetDouble("birthTotalDays", entity.World.Calendar.TotalDays);
			if (keepTextureIndex && entity.WatchedAttributes.HasAttribute("textureIndex"))
			{
				adult.WatchedAttributes.SetAttribute("textureIndex", entity.WatchedAttributes.GetAttribute("textureIndex"));
			}
			entity.Die(EnumDespawnReason.Expire);
			entity.World.SpawnEntity(adult);
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			entity.World.UnregisterCallback(callbackId);
		}

		public override string PropertyName()
		{
			return "grow";
		}
	}
	public class ModSystemSyncHarvestableDropsToClient : ModSystem
	{
		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Server;
		}

		public override void AssetsFinalize(ICoreAPI api)
		{
			base.AssetsFinalize(api);
			foreach (EntityProperties entityType in api.World.EntityTypes)
			{
				JsonObject[] behaviorsAsJsonObj = entityType.Server.BehaviorsAsJsonObj;
				foreach (JsonObject jsonObject in behaviorsAsJsonObj)
				{
					if (jsonObject["code"].AsString() == "harvestable")
					{
						if (entityType.Attributes == null)
						{
							entityType.Attributes = new JsonObject(JToken.Parse("{}"));
						}
						entityType.Attributes.Token[(object)"harvestableDrops"] = jsonObject["drops"].Token;
					}
				}
			}
		}
	}
