		public EntityBehaviorHunger(Entity entity)
			: base(entity)
		{
			entityAgent = entity as EntityAgent;
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			hungerTree = entity.WatchedAttributes.GetTreeAttribute("hunger");
			api = entity.World.Api;
			if (hungerTree == null)
			{
				entity.WatchedAttributes.SetAttribute("hunger", hungerTree = new TreeAttribute());
				Saturation = typeAttributes["currentsaturation"].AsFloat(1500f);
				MaxSaturation = typeAttributes["maxsaturation"].AsFloat(1500f);
				SaturationLossDelayFruit = 0f;
				SaturationLossDelayVegetable = 0f;
				SaturationLossDelayGrain = 0f;
				SaturationLossDelayProtein = 0f;
				SaturationLossDelayDairy = 0f;
				FruitLevel = 0f;
				VegetableLevel = 0f;
				GrainLevel = 0f;
				ProteinLevel = 0f;
				DairyLevel = 0f;
			}
			listenerId = entity.World.RegisterGameTickListener(SlowTick, 6000);
			UpdateNutrientHealthBoost();
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			base.OnEntityDespawn(despawn);
			entity.World.UnregisterGameTickListener(listenerId);
		}

		public override void DidAttack(DamageSource source, EntityAgent targetEntity, ref EnumHandling handled)
		{
			ConsumeSaturation(3f);
		}

		public virtual void ConsumeSaturation(float amount)
		{
			ReduceSaturation(amount / 10f);
		}

		public override void OnEntityReceiveSaturation(float saturation, EnumFoodCategory foodCat = EnumFoodCategory.Unknown, float saturationLossDelay = 10f, float nutritionGainMultiplier = 1f)
		{
			float maxSaturation = MaxSaturation;
			bool flag = Saturation >= maxSaturation;
			Saturation = Math.Min(maxSaturation, Saturation + saturation);
			switch (foodCat)
			{
			case EnumFoodCategory.Fruit:
				if (!flag)
				{
					FruitLevel = Math.Min(maxSaturation, FruitLevel + saturation / 2.5f * nutritionGainMultiplier);
				}
				SaturationLossDelayFruit = Math.Max(SaturationLossDelayFruit, saturationLossDelay);
				break;
			case EnumFoodCategory.Vegetable:
				if (!flag)
				{
					VegetableLevel = Math.Min(maxSaturation, VegetableLevel + saturation / 2.5f * nutritionGainMultiplier);
				}
				SaturationLossDelayVegetable = Math.Max(SaturationLossDelayVegetable, saturationLossDelay);
				break;
			case EnumFoodCategory.Protein:
				if (!flag)
				{
					ProteinLevel = Math.Min(maxSaturation, ProteinLevel + saturation / 2.5f * nutritionGainMultiplier);
				}
				SaturationLossDelayProtein = Math.Max(SaturationLossDelayProtein, saturationLossDelay);
				break;
			case EnumFoodCategory.Grain:
				if (!flag)
				{
					GrainLevel = Math.Min(maxSaturation, GrainLevel + saturation / 2.5f * nutritionGainMultiplier);
				}
				SaturationLossDelayGrain = Math.Max(SaturationLossDelayGrain, saturationLossDelay);
				break;
			case EnumFoodCategory.Dairy:
				if (!flag)
				{
					DairyLevel = Math.Min(maxSaturation, DairyLevel + saturation / 2.5f * nutritionGainMultiplier);
				}
				SaturationLossDelayDairy = Math.Max(SaturationLossDelayDairy, saturationLossDelay);
				break;
			}
			UpdateNutrientHealthBoost();
		}

		public override void OnGameTick(float deltaTime)
		{
			if (entity is EntityPlayer)
			{
				EntityPlayer entityPlayer = (EntityPlayer)entity;
				EnumGameMode currentGameMode = entity.World.PlayerByUid(entityPlayer.PlayerUID).WorldData.CurrentGameMode;
				detox(deltaTime);
				if (currentGameMode == EnumGameMode.Creative || currentGameMode == EnumGameMode.Spectator)
				{
					return;
				}
				if (entityPlayer.Controls.TriesToMove || entityPlayer.Controls.Jump || entityPlayer.Controls.LeftMouseDown || entityPlayer.Controls.RightMouseDown)
				{
					lastMoveMs = entity.World.ElapsedMilliseconds;
				}
			}
			if (entityAgent != null && entityAgent.Controls.Sprint)
			{
				sprintCounter++;
			}
			if (hungerCounter < 0f)
			{
				hungerCounter = 0f;
			}
			hungerCounter += deltaTime;
			if (hungerCounter > 10f)
			{
				bool num = entity.World.ElapsedMilliseconds - lastMoveMs > 3000;
				float num2 = entity.Api.World.Calendar.SpeedOfTime * entity.Api.World.Calendar.CalendarSpeedMul;
				float num3 = GlobalConstants.HungerSpeedModifier / 30f;
				if (num)
				{
					num3 /= 4f;
				}
				num3 *= 1.2f * (8f + (float)sprintCounter / 15f) / 10f;
				num3 *= entity.Stats.GetBlended("hungerrate");
				ReduceSaturation(num3 * num2);
				hungerCounter = 0f;
				sprintCounter = 0;
				detox(deltaTime);
			}
		}

		private void detox(float dt)
		{
			detoxCounter += dt;
			if (detoxCounter > 1f)
			{
				float num = entity.WatchedAttributes.GetFloat("intoxication");
				if (num > 0f)
				{
					entity.WatchedAttributes.SetFloat("intoxication", Math.Max(0f, num - 0.005f));
				}
				detoxCounter = 0f;
			}
		}

		private bool ReduceSaturation(float satLossMultiplier)
		{
			bool flag = false;
			satLossMultiplier *= GlobalConstants.HungerSpeedModifier;
			if (SaturationLossDelayFruit > 0f)
			{
				SaturationLossDelayFruit -= 10f * satLossMultiplier;
				flag = true;
			}
			else
			{
				FruitLevel = Math.Max(0f, FruitLevel - Math.Max(0.5f, 0.001f * FruitLevel) * satLossMultiplier * 0.25f);
			}
			if (SaturationLossDelayVegetable > 0f)
			{
				SaturationLossDelayVegetable -= 10f * satLossMultiplier;
				flag = true;
			}
			else
			{
				VegetableLevel = Math.Max(0f, VegetableLevel - Math.Max(0.5f, 0.001f * VegetableLevel) * satLossMultiplier * 0.25f);
			}
			if (SaturationLossDelayProtein > 0f)
			{
				SaturationLossDelayProtein -= 10f * satLossMultiplier;
				flag = true;
			}
			else
			{
				ProteinLevel = Math.Max(0f, ProteinLevel - Math.Max(0.5f, 0.001f * ProteinLevel) * satLossMultiplier * 0.25f);
			}
			if (SaturationLossDelayGrain > 0f)
			{
				SaturationLossDelayGrain -= 10f * satLossMultiplier;
				flag = true;
			}
			else
			{
				GrainLevel = Math.Max(0f, GrainLevel - Math.Max(0.5f, 0.001f * GrainLevel) * satLossMultiplier * 0.25f);
			}
			if (SaturationLossDelayDairy > 0f)
			{
				SaturationLossDelayDairy -= 10f * satLossMultiplier;
				flag = true;
			}
			else
			{
				DairyLevel = Math.Max(0f, DairyLevel - Math.Max(0.5f, 0.001f * DairyLevel) * satLossMultiplier * 0.25f / 2f);
			}
			UpdateNutrientHealthBoost();
			if (flag)
			{
				hungerCounter = 0f;
				return true;
			}
			float saturation = Saturation;
			if (saturation > 0f)
			{
				Saturation = Math.Max(0f, saturation - satLossMultiplier * 10f);
				sprintCounter = 0;
			}
			return false;
		}

		public void UpdateNutrientHealthBoost()
		{
			float num = FruitLevel / MaxSaturation;
			float num2 = GrainLevel / MaxSaturation;
			float num3 = VegetableLevel / MaxSaturation;
			float num4 = ProteinLevel / MaxSaturation;
			float num5 = DairyLevel / MaxSaturation;
			EntityBehaviorHealth? behavior = entity.GetBehavior<EntityBehaviorHealth>();
			float value = 2.5f * (num + num2 + num3 + num4 + num5);
			behavior.SetMaxHealthModifiers("nutrientHealthMod", value);
		}

		private void SlowTick(float dt)
		{
			if (entity is EntityPlayer)
			{
				EntityPlayer entityPlayer = (EntityPlayer)entity;
				if (entity.World.PlayerByUid(entityPlayer.PlayerUID).WorldData.CurrentGameMode == EnumGameMode.Creative)
				{
					return;
				}
			}
			bool flag = entity.World.Config.GetString("harshWinters").ToBool(defaultValue: true);
			float temperature = entity.World.BlockAccessor.GetClimateAt(entity.Pos.AsBlockPos, EnumGetClimateMode.ForSuppliedDate_TemperatureOnly, entity.World.Calendar.TotalDays).Temperature;
			if (temperature >= 2f || !flag)
			{
				entity.Stats.Remove("hungerrate", "resistcold");
			}
			else
			{
				float num = GameMath.Clamp(2f - temperature, 0f, 10f);
				Room roomForPosition = entity.World.Api.ModLoader.GetModSystem<RoomRegistry>().GetRoomForPosition(entity.Pos.AsBlockPos);
				entity.Stats.Set("hungerrate", "resistcold", (roomForPosition.ExitCount == 0) ? 0f : (num / 40f), persistent: true);
			}
			if (Saturation <= 0f)
			{
				entity.ReceiveDamage(new DamageSource
				{
					Source = EnumDamageSource.Internal,
					Type = EnumDamageType.Hunger
				}, 0.125f);
				sprintCounter = 0;
			}
		}

		public override string PropertyName()
		{
			return "hunger";
		}

		public override void OnEntityReceiveDamage(DamageSource damageSource, ref float damage)
		{
			if (damageSource.Type == EnumDamageType.Heal && damageSource.Source == EnumDamageSource.Revive)
			{
				SaturationLossDelayFruit = 60f;
				SaturationLossDelayVegetable = 60f;
				SaturationLossDelayProtein = 60f;
				SaturationLossDelayGrain = 60f;
				SaturationLossDelayDairy = 60f;
				Saturation = MaxSaturation / 2f;
				VegetableLevel /= 2f;
				ProteinLevel /= 2f;
				FruitLevel /= 2f;
				DairyLevel /= 2f;
				GrainLevel /= 2f;
			}
		}
	}
	public class EntityBehaviorMouthInventory : EntityBehavior
	{
		private EntityAgent entityAgent;

		private InventoryGeneric mouthInv;

		public List<ItemStack> acceptStacks = new List<ItemStack>();

		public long PickupCoolDownUntilMs;

		public EntityBehaviorMouthInventory(Entity entity)
			: base(entity)
		{
			entityAgent = entity as EntityAgent;
			mouthInv = new InventoryGeneric(1, "mouthslot-" + entity.EntityId, entity.Api, (int id, InventoryGeneric inv) => new ItemSlotMouth(this, inv));
			mouthInv.SlotModified += MouthInv_SlotModified;
			entityAgent.LeftHandItemSlot = mouthInv[0];
		}

		private void MouthInv_SlotModified(int slotid)
		{
			ITreeAttribute tree = new TreeAttribute();
			entity.WatchedAttributes["mouthInv"] = tree;
			entity.WatchedAttributes.MarkPathDirty("mouthInv");
			mouthInv.ToTreeAttributes(tree);
			if (entityAgent.Api is ICoreServerAPI coreServerAPI)
			{
				coreServerAPI.Network.BroadcastEntityPacket(entity.EntityId, 1235, SerializerUtil.ToBytes(delegate(BinaryWriter w)
				{
					tree.ToBytes(w);
				}));
			}
		}

		public override void OnReceivedServerPacket(int packetid, byte[] data, ref EnumHandling handled)
		{
			if (packetid == 1235)
			{
				TreeAttribute tree = new TreeAttribute();
				SerializerUtil.FromBytes(data, delegate(BinaryReader r)
				{
					tree.FromBytes(r);
				});
				mouthInv.FromTreeAttributes(tree);
			}
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			JsonItemStack[] array = typeAttributes["acceptStacks"].AsObject<JsonItemStack[]>();
			foreach (JsonItemStack jsonItemStack in array)
			{
				if (jsonItemStack.Resolve(entity.World, "mouth inventory accept stacks"))
				{
					acceptStacks.Add(jsonItemStack.ResolvedItemstack);
				}
			}
			if (entity.WatchedAttributes["mouthInv"] is ITreeAttribute tree)
			{
				mouthInv.FromTreeAttributes(tree);
			}
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			base.OnEntityDespawn(despawn);
		}

		public override void OnEntityDeath(DamageSource damageSourceForDeath)
		{
			if (entity.World.Side == EnumAppSide.Server)
			{
				mouthInv.DropAll(entity.ServerPos.XYZ);
			}
			base.OnEntityDeath(damageSourceForDeath);
		}

		public override void OnEntityReceiveDamage(DamageSource damageSource, ref float damage)
		{
			if (entity.World.Side == EnumAppSide.Server && entity.World.Rand.NextDouble() < 0.25)
			{
				mouthInv.DropAll(entity.ServerPos.XYZ);
				PickupCoolDownUntilMs = entity.World.ElapsedMilliseconds + 10000;
			}
			base.OnEntityReceiveDamage(damageSource, ref damage);
		}

		public override string PropertyName()
		{
			return "mouthslot";
		}
	}
	public class EntityBehaviorMultiply : EntityBehaviorMultiplyBase
	{
		private JsonObject typeAttributes;

		private long callbackId;

		private AssetLocation[] spawnEntityCodes;

		internal float PregnancyDays => typeAttributes["pregnancyDays"].AsFloat(3f);

		internal string RequiresNearbyEntityCode => typeAttributes["requiresNearbyEntityCode"].AsString("");

		internal float RequiresNearbyEntityRange => typeAttributes["requiresNearbyEntityRange"].AsFloat(5f);

		public float SpawnQuantityMin => typeAttributes["spawnQuantityMin"].AsFloat(1f);

		public float SpawnQuantityMax => typeAttributes["spawnQuantityMax"].AsFloat(2f);

		public double TotalDaysLastBirth
		{
			get
			{
				return multiplyTree.GetDouble("totalDaysLastBirth", -9999.0);
			}
			set
			{
				multiplyTree.SetDouble("totalDaysLastBirth", value);
				entity.WatchedAttributes.MarkPathDirty("multiply");
			}
		}

		public double TotalDaysPregnancyStart
		{
			get
			{
				return multiplyTree.GetDouble("totalDaysPregnancyStart");
			}
			set
			{
				multiplyTree.SetDouble("totalDaysPregnancyStart", value);
				entity.WatchedAttributes.MarkPathDirty("multiply");
			}
		}

		public bool IsPregnant
		{
			get
			{
				return multiplyTree.GetBool("isPregnant");
			}
			set
			{
				multiplyTree.SetBool("isPregnant", value);
				entity.WatchedAttributes.MarkPathDirty("multiply");
			}
		}

		public override bool ShouldEat
		{
			get
			{
				if (!eatAnyway)
				{
					if (!IsPregnant && GetSaturation() < base.PortionsEatenForMultiply)
					{
						return base.TotalDaysCooldownUntil <= entity.World.Calendar.TotalDays;
					}
					return false;
				}
				return true;
			}
		}

		public EntityBehaviorMultiply(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
			typeAttributes = attributes;
			if (entity.World.Side == EnumAppSide.Server)
			{
				if (!multiplyTree.HasAttribute("totalDaysLastBirth"))
				{
					TotalDaysLastBirth = -9999.0;
				}
				callbackId = entity.World.RegisterCallback(CheckMultiply, 3000);
			}
		}

		protected virtual void CheckMultiply(float dt)
		{
			if (!entity.Alive)
			{
				callbackId = 0L;
				return;
			}
			callbackId = entity.World.RegisterCallback(CheckMultiply, 3000);
			if (entity.World.Calendar == null)
			{
				return;
			}
			double totalDays = entity.World.Calendar.TotalDays;
			if (!IsPregnant)
			{
				if (TryGetPregnant())
				{
					IsPregnant = true;
					TotalDaysPregnancyStart = totalDays;
				}
				return;
			}
			if (totalDays - TotalDaysPregnancyStart > (double)PregnancyDays)
			{
				Random rand = entity.World.Rand;
				float q = SpawnQuantityMin + (float)rand.NextDouble() * (SpawnQuantityMax - SpawnQuantityMin);
				TotalDaysLastBirth = totalDays;
				base.TotalDaysCooldownUntil = totalDays + (base.MultiplyCooldownDaysMin + rand.NextDouble() * (base.MultiplyCooldownDaysMax - base.MultiplyCooldownDaysMin));
				IsPregnant = false;
				entity.WatchedAttributes.MarkPathDirty("multiply");
				GiveBirth(q);
			}
			entity.World.FrameProfiler.Mark("multiply");
		}

		protected virtual void GiveBirth(float q)
		{
			Random rand = base.entity.World.Rand;
			int num = base.entity.WatchedAttributes.GetInt("generation");
			if (spawnEntityCodes == null)
			{
				PopulateSpawnEntityCodes();
			}
			if (spawnEntityCodes == null)
			{
				return;
			}
			while (q > 1f || rand.NextDouble() < (double)q)
			{
				q -= 1f;
				AssetLocation entityCode = spawnEntityCodes[rand.Next(spawnEntityCodes.Length)];
				EntityProperties entityType = base.entity.World.GetEntityType(entityCode);
				if (entityType != null)
				{
					Entity entity = base.entity.World.ClassRegistry.CreateEntity(entityType);
					entity.ServerPos.SetFrom(base.entity.ServerPos);
					entity.ServerPos.Motion.X += (rand.NextDouble() - 0.5) / 20.0;
					entity.ServerPos.Motion.Z += (rand.NextDouble() - 0.5) / 20.0;
					entity.Pos.SetFrom(entity.ServerPos);
					entity.Attributes.SetString("origin", "reproduction");
					entity.WatchedAttributes.SetInt("generation", num + 1);
					base.entity.World.SpawnEntity(entity);
				}
			}
		}

		protected virtual void PopulateSpawnEntityCodes()
		{
			JsonObject jsonObject = typeAttributes["spawnEntityCodes"];
			if (!jsonObject.Exists)
			{
				jsonObject = typeAttributes["spawnEntityCode"];
				if (jsonObject.Exists)
				{
					spawnEntityCodes = new AssetLocation[1]
					{
						new AssetLocation(jsonObject.AsString(""))
					};
				}
			}
			else if (jsonObject.IsArray())
			{
				SpawnEntityProperties[] array = jsonObject.AsArray<SpawnEntityProperties>();
				spawnEntityCodes = new AssetLocation[array.Length];
				for (int i = 0; i < array.Length; i++)
				{
					spawnEntityCodes[i] = new AssetLocation(array[i].Code ?? "");
				}
			}
			else
			{
				spawnEntityCodes = new AssetLocation[1]
				{
					new AssetLocation(jsonObject.AsString(""))
				};
			}
		}

		public override void TestCommand(object arg)
		{
			GiveBirth((int)arg);
		}

		protected virtual bool TryGetPregnant()
		{
			if (base.entity.World.Rand.NextDouble() > 0.06)
			{
				return false;
			}
			if (base.TotalDaysCooldownUntil > base.entity.World.Calendar.TotalDays)
			{
				return false;
			}
			ITreeAttribute treeAttribute = base.entity.WatchedAttributes.GetTreeAttribute("hunger");
			if (treeAttribute == null)
			{
				return false;
			}
			float num = treeAttribute.GetFloat("saturation");
			if (num >= base.PortionsEatenForMultiply)
			{
				Entity entity = null;
				if (RequiresNearbyEntityCode != null && (entity = GetRequiredEntityNearby()) == null)
				{
					return false;
				}
				if (base.entity.World.Rand.NextDouble() < 0.2)
				{
					treeAttribute.SetFloat("saturation", num - 1f);
					return false;
				}
				treeAttribute.SetFloat("saturation", num - base.PortionsEatenForMultiply);
				if (entity != null)
				{
					ITreeAttribute treeAttribute2 = entity.WatchedAttributes.GetTreeAttribute("hunger");
					if (treeAttribute2 != null)
					{
						num = treeAttribute2.GetFloat("saturation");
						treeAttribute2.SetFloat("saturation", Math.Max(0f, num - 1f));
					}
				}
				IsPregnant = true;
				TotalDaysPregnancyStart = base.entity.World.Calendar.TotalDays;
				base.entity.WatchedAttributes.MarkPathDirty("multiply");
				return true;
			}
			return false;
		}

		protected virtual Entity GetRequiredEntityNearby()
		{
			if (RequiresNearbyEntityCode == null)
			{
				return null;
			}
			return entity.World.GetNearestEntity(entity.ServerPos.XYZ, RequiresNearbyEntityRange, RequiresNearbyEntityRange, delegate(Entity e)
			{
				if (e.WildCardMatch(new AssetLocation(RequiresNearbyEntityCode)))
				{
					if (e.WatchedAttributes.GetBool("doesEat"))
					{
						ITreeAttribute obj = e.WatchedAttributes["hunger"] as ITreeAttribute;
						if (obj == null || !(obj.GetFloat("saturation") >= 1f))
						{
							goto IL_005c;
						}
					}
					return true;
				}
				goto IL_005c;
				IL_005c:
				return false;
			});
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			entity.World.UnregisterCallback(callbackId);
		}

		public override string PropertyName()
		{
			return "multiply";
		}

		public override void GetInfoText(StringBuilder infotext)
		{
			multiplyTree = entity.WatchedAttributes.GetTreeAttribute("multiply");
			if (IsPregnant)
			{
				infotext.AppendLine(Lang.Get("Is pregnant"));
			}
			else
			{
				if (!entity.Alive)
				{
					return;
				}
				ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("hunger");
				if (treeAttribute != null)
				{
					float num = treeAttribute.GetFloat("saturation");
					infotext.AppendLine(Lang.Get("Portions eaten: {0}", num));
				}
				double num2 = base.TotalDaysCooldownUntil - entity.World.Calendar.TotalDays;
				if (num2 > 0.0)
				{
					if (num2 > 3.0)
					{
						infotext.AppendLine(Lang.Get("Several days left before ready to mate"));
					}
					else
					{
						infotext.AppendLine(Lang.Get("Less than 3 days before ready to mate"));
					}
				}
				else
				{
					infotext.AppendLine(Lang.Get("Ready to mate"));
				}
			}
		}
