		{
			if (packetid < 1000)
			{
				inv.InvNetworkUtil.HandleClientPacket(player, packetid, data);
				handled = EnumHandling.PreventSubsequent;
			}
			else if (packetid == 1012)
			{
				player.InventoryManager.OpenInventory(inv);
			}
		}

