				if (capi != null)
				{
					entity.Pos.SetPos(entityAgent.MountedOn.SeatPosition);
				}
				entity.ServerPos.Motion.X = 0.0;
				entity.ServerPos.Motion.Y = 0.0;
				entity.ServerPos.Motion.Z = 0.0;
				if (sapi != null)
