				return;
			}
			entity.Pos.SetFrom(entity.ServerPos);
			SetState(entityPos, dt);
			EntityControls controls = entityAgent.Controls;
			if (!controls.NoClip)
			{
				if (sapi != null)
				{
					PhysicsBehaviorBase.collisionTester.ApplyTerrainCollision(entity, entityPos, num, ref newPos, 0f, 0f);
				}
				RemoteMotionAndCollision(entityPos, num);
				ApplyTests(entityPos, entityAgent.Controls, dt, remote: true);
			}
			else
			{
				EntityPos serverPos = entity.ServerPos;
				serverPos.X += serverPos.Motion.X * (double)dt * 60.0;
				serverPos.Y += serverPos.Motion.Y * (double)dt * 60.0;
				serverPos.Z += serverPos.Motion.Z * (double)dt * 60.0;
				entity.Swimming = false;
				entity.FeetInLiquid = false;
				entity.OnGround = false;
				controls.Gliding = false;
			}
		}

		public override void OnPhysicsTick(float dt)
		{
			SimPhysics(dt, entity.SidedPos);
		}

		public override void OnGameTick(float deltaTime)
		{
			if (entity.World is IServerWorldAccessor)
			{
				callOnEntityInside();
				entity.AfterPhysicsTick?.Invoke();
			}
		}

		public void SimPhysics(float dt, EntityPos pos)
		{
			Entity entity = base.entity;
			if (entity.State != EnumEntityState.Active)
			{
				return;
			}
			if (player == null)
			{
				player = entityPlayer.Player;
			}
			if (player == null)
			{
				return;
			}
			EntityAgent entityAgent = entity as EntityAgent;
			EntityControls controls = entityAgent.Controls;
			prevPos.Set(pos);
			tmpPos.dimension = pos.Dimension;
			SetState(pos, dt);
			SetPlayerControls(pos, controls, dt);
			if (entityAgent.MountedOn != null)
			{
				entity.Swimming = false;
				entity.OnGround = false;
				pos.SetPos(entityAgent.MountedOn.SeatPosition);
				pos.Motion.X = 0.0;
				pos.Motion.Y = 0.0;
				pos.Motion.Z = 0.0;
				return;
			}
			MotionAndCollision(pos, controls, dt);
			if (!controls.NoClip)
			{
				PhysicsBehaviorBase.collisionTester.NewTick(pos);
				if (prevDimension != pos.Dimension)
				{
					prevDimension = pos.Dimension;
					PhysicsBehaviorBase.collisionTester.PushOutFromBlocks(entity.World.BlockAccessor, entity, pos.XYZ, 0.075f);
				}
				ApplyTests(pos, controls, dt, remote: false);
				if (controls.Gliding)
				{
					if (entity.Collided || entity.FeetInLiquid || !entity.Alive || player.WorldData.FreeMove || controls.IsClimbing)
					{
						controls.GlideSpeed = 0.0;
						controls.Gliding = false;
						controls.IsFlying = false;
						entityPlayer.WalkPitch = 0f;
					}
				}
				else
				{
					controls.GlideSpeed = 0.0;
				}
			}
			else
			{
				pos.X += pos.Motion.X * (double)dt * 60.0;
				pos.Y += pos.Motion.Y * (double)dt * 60.0;
				pos.Z += pos.Motion.Z * (double)dt * 60.0;
				entity.Swimming = false;
				entity.FeetInLiquid = false;
				entity.OnGround = false;
				controls.Gliding = false;
				prevDimension = pos.Dimension;
			}
		}

		public void SetPlayerControls(EntityPos pos, EntityControls controls, float dt)
		{
			IClientWorldAccessor clientWorldAccessor = entity.World as IClientWorldAccessor;
			controls.IsFlying = player.WorldData.FreeMove || (clientWorldAccessor != null && clientWorldAccessor.Player.ClientId != player.ClientId && !controls.IsClimbing);
			controls.NoClip = player.WorldData.NoClip;
			controls.MovespeedMultiplier = player.WorldData.MoveSpeedMultiplier;
			if (controls.Gliding && !controls.IsClimbing)
			{
				controls.IsFlying = true;
			}
			if ((controls.TriesToMove || controls.Gliding) && player is IClientPlayer clientPlayer)
			{
				float yaw = pos.Yaw;
				pos.Yaw = (entity.Api as ICoreClientAPI).Input.MouseYaw;
				if (entity.Swimming || controls.Gliding)
				{
					float pitch = pos.Pitch;
					pos.Pitch = clientPlayer.CameraPitch;
					controls.CalcMovementVectors(pos, dt);
					pos.Yaw = yaw;
					pos.Pitch = pitch;
				}
				else
				{
					controls.CalcMovementVectors(pos, dt);
					pos.Yaw = yaw;
				}
				float end = (float)Math.Atan2(controls.WalkVector.X, controls.WalkVector.Z);
				float val = GameMath.AngleRadDistance(entityPlayer.WalkYaw, end);
				entityPlayer.WalkYaw += GameMath.Clamp(val, -6f * dt * GlobalConstants.OverallSpeedMultiplier, 6f * dt * GlobalConstants.OverallSpeedMultiplier);
				entityPlayer.WalkYaw = GameMath.Mod(entityPlayer.WalkYaw, (float)Math.PI * 2f);
				if (entity.Swimming || controls.Gliding)
				{
					float end2 = 0f - (float)Math.Sin(pos.Pitch);
					float val2 = GameMath.AngleRadDistance(entityPlayer.WalkPitch, end2);
					entityPlayer.WalkPitch += GameMath.Clamp(val2, -2f * dt * GlobalConstants.OverallSpeedMultiplier, 2f * dt * GlobalConstants.OverallSpeedMultiplier);
					entityPlayer.WalkPitch = GameMath.Mod(entityPlayer.WalkPitch, (float)Math.PI * 2f);
				}
				else
				{
					entityPlayer.WalkPitch = 0f;
				}
				return;
			}
			if (!entity.Swimming && !controls.Gliding)
			{
				entityPlayer.WalkPitch = 0f;
			}
			else if (entity.OnGround && entityPlayer.WalkPitch != 0f)
			{
				entityPlayer.WalkPitch = GameMath.Mod(entityPlayer.WalkPitch, (float)Math.PI * 2f);
				if (entityPlayer.WalkPitch < 0.01f || entityPlayer.WalkPitch > 3.1315928f)
				{
					entityPlayer.WalkPitch = 0f;
				}
				else
				{
					entityPlayer.WalkPitch -= GameMath.Clamp(entityPlayer.WalkPitch, 0f, 1.2f * dt * GlobalConstants.OverallSpeedMultiplier);
					if (entityPlayer.WalkPitch < 0f)
					{
						entityPlayer.WalkPitch = 0f;
					}
				}
			}
			float yaw2 = pos.Yaw;
			controls.CalcMovementVectors(pos, dt);
			pos.Yaw = yaw2;
		}

		public void OnRenderFrame(float dt, EnumRenderStage stage)
		{
			if (capi.IsGamePaused)
			{
				return;
			}
			if (capi.World.Player.Entity != base.entity)
			{
				smoothStepping = false;
				capi.Event.UnregisterRenderer(this, EnumRenderStage.Before);
				return;
			}
			accum += dt;
			if (accum > 0.5f)
			{
				accum = 0.5f;
			}
			Entity entity = entityPlayer.MountedOn?.Entity;
			IPhysicsTickable physicsTickable = null;
			if (entityPlayer.MountedOn?.MountSupplier.Controller == entityPlayer)
			{
				physicsTickable = entity?.SidedProperties.Behaviors.Find((EntityBehavior b) => b is IPhysicsTickable) as IPhysicsTickable;
			}
			while (accum >= 1f / 60f)
			{
				OnPhysicsTick(1f / 60f);
				physicsTickable?.OnPhysicsTick(1f / 60f);
				accum -= 1f / 60f;
				currentTick++;
				if (currentTick % 4 == 0 && entityPlayer.EntityId != 0L && entityPlayer.Alive)
				{
					capi.Network.SendPlayerPositionPacket();
					if (physicsTickable != null)
					{
						capi.Network.SendPlayerMountPositionPacket(entity);
					}
				}
				AfterPhysicsTick(1f / 60f);
				physicsTickable?.AfterPhysicsTick(1f / 60f);
			}
			base.entity.PhysicsUpdateWatcher?.Invoke(accum, prevPos);
			entity?.PhysicsUpdateWatcher?.Invoke(accum, prevPos);
		}

		protected override bool HandleSteppingOnBlocks(EntityPos pos, Vec3d moveDelta, float dtFac, EntityControls controls)
		{
			if (!controls.TriesToMove || (!entity.OnGround && !entity.Swimming) || entity.Properties.Habitat == EnumHabitat.Underwater)
			{
				return false;
			}
			Cuboidd cuboidd = entity.CollisionBox.ToDouble();
			double num = 0.5 + (controls.Sprint ? 0.25 : (controls.Sneak ? 0.05 : 0.2));
			double num2 = (cuboidd.X1 + cuboidd.X2) / 2.0;
			double num3 = (cuboidd.Z1 + cuboidd.Z2) / 2.0;
			double y = Math.Max(cuboidd.Y1 + (double)StepHeight, cuboidd.Y2);
			Vec3d vec3d = controls.WalkVector.Clone();
			Vec3d vec3d2 = vec3d.Clone().Normalize();
			double num4 = vec3d2.X * num;
			double num5 = vec3d2.Z * num;
			double num6 = cuboidd.Width / 2.0;
			double num7 = cuboidd.Length / 2.0;
			num4 += (double)Math.Sign(num4) * num6;
			num5 += (double)Math.Sign(num5) * num7;
			Cuboidd cuboidd2 = new Cuboidd
			{
				X1 = Math.Min(0.0 - num6, num4),
				X2 = Math.Max(num6, num4),
				Z1 = Math.Min(0.0 - num7, num5),
				Z2 = Math.Max(num7, num5),
				Y1 = (double)entity.CollisionBox.Y1 + 0.01 - ((!entity.CollidedVertically && !controls.Jump) ? 0.05 : 0.0),
				Y2 = y
			};
			cuboidd2.Translate(num2, 0.0, num3);
			cuboidd2.Translate(pos.X, pos.Y, pos.Z);
			cuboidd.Translate(pos.X, pos.Y, pos.Z);
			List<Cuboidd> list = FindSteppableCollisionboxSmooth(cuboidd, cuboidd2, moveDelta.Y, vec3d);
			if (list != null && list.Count > 0)
			{
				Vec3d vec3d3 = new Vec3d();
				Vec2d vec2d = new Vec2d();
				if (TryStepSmooth(controls, pos, vec2d.Set(vec3d.X, vec3d.Z), dtFac, list, cuboidd))
				{
					return true;
				}
				Cuboidd cuboidd3 = cuboidd2.Clone();
				if (cuboidd3.Z1 == pos.Z + num3)
				{
					cuboidd3.Z2 = cuboidd3.Z1;
				}
				else
				{
					cuboidd3.Z1 = cuboidd3.Z2;
				}
				if (TryStepSmooth(controls, pos, vec2d.Set(vec3d.X, 0.0), dtFac, FindSteppableCollisionboxSmooth(cuboidd, cuboidd3, moveDelta.Y, vec3d3.Set(vec3d.X, vec3d.Y, 0.0)), cuboidd))
				{
					return true;
				}
				cuboidd3.Set(cuboidd2);
				if (cuboidd3.X1 == pos.X + num2)
				{
					cuboidd3.X2 = cuboidd3.X1;
				}
				else
				{
					cuboidd3.X1 = cuboidd3.X2;
				}
				if (TryStepSmooth(controls, pos, vec2d.Set(0.0, vec3d.Z), dtFac, FindSteppableCollisionboxSmooth(cuboidd, cuboidd3, moveDelta.Y, vec3d3.Set(0.0, vec3d.Y, vec3d.Z)), cuboidd))
				{
					return true;
				}
			}
			return false;
		}

		public bool TryStepSmooth(EntityControls controls, EntityPos pos, Vec2d walkVec, float dtFac, List<Cuboidd> steppableBoxes, Cuboidd entityCollisionBox)
		{
			if (steppableBoxes == null || steppableBoxes.Count == 0)
			{
				return false;
			}
			double num = 0.03;
			Vec2d vec2d = new Vec2d(walkVec.Y, 0.0 - walkVec.X).Normalize();
			double num2 = Math.Abs(vec2d.X * 0.3) + 0.001;
			double num3 = 0.0 - num2;
			double num4 = Math.Abs(vec2d.Y * 0.3) + 0.001;
			double num5 = 0.0 - num4;
			Cuboidf entityBoxRel = new Cuboidf((float)num3, entity.CollisionBox.Y1, (float)num5, (float)num2, entity.CollisionBox.Y2, (float)num4);
			double num6 = pos.Y;
			bool flag = false;
			foreach (Cuboidd steppableBox in steppableBoxes)
			{
				double num7 = steppableBox.Y2 - entityCollisionBox.Y1 + num;
				Vec3d pos2 = new Vec3d(GameMath.Clamp(newPos.X, steppableBox.MinX, steppableBox.MaxX), newPos.Y + num7 + (double)pos.DimensionYAdjustment, GameMath.Clamp(newPos.Z, steppableBox.MinZ, steppableBox.MaxZ));
				if (!PhysicsBehaviorBase.collisionTester.IsColliding(entity.World.BlockAccessor, entityBoxRel, pos2, alsoCheckTouch: false))
				{
					double num8 = (controls.Sprint ? 0.1 : (controls.Sneak ? 0.025 : 0.05));
					num6 = (steppableBox.IntersectsOrTouches(entityCollisionBox) ? Math.Max(num6, pos.Y + num8 * (double)dtFac) : Math.Max(num6, Math.Min(pos.Y + num8 * (double)dtFac, steppableBox.Y2 - (double)entity.CollisionBox.Y1 + num)));
					flag = true;
				}
			}
			if (flag)
			{
				pos.Y = num6;
				PhysicsBehaviorBase.collisionTester.ApplyTerrainCollision(entity, pos, dtFac, ref newPos);
			}
			return flag;
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			capi?.Event.UnregisterRenderer(this, EnumRenderStage.Before);
		}

		public void Dispose()
		{
		}
	}
	public interface ICustomRepulseBehavior
	{
		bool Repulse(Entity entity, Vec3d pushVector);
	}
	public class EntityBehaviorEllipsoidalRepulseAgents : EntityBehaviorRepulseAgents, ICustomRepulseBehavior
	{
		protected Vec3d offset;

		protected Vec3d radius;

		public EntityBehaviorEllipsoidalRepulseAgents(Entity entity)
			: base(entity)
		{
			entity.customRepulseBehavior = true;
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
			offset = attributes["offset"].AsObject(new Vec3d());
			radius = attributes["radius"].AsObject<Vec3d>();
		}

		public override void AfterInitialized(bool onFirstSpawn)
		{
			touchdist = Math.Max(radius.X, radius.Z);
			entity.BHRepulseAgents = this;
			entity.AfterPhysicsTick = base.AfterPhysicsTick;
		}

		public override void UpdateColSelBoxes()
		{
			touchdist = Math.Max(radius.X, radius.Z);
		}

		public override float GetTouchDistance(ref EnumHandling handling)
		{
			handling = EnumHandling.PreventDefault;
			return (float)Math.Max(radius.X, radius.Z) + 0.5f;
		}

		public bool Repulse(Entity e, Vec3d pushVector)
		{
			if (!(e.BHRepulseAgents is EntityBehaviorRepulseAgents entityBehaviorRepulseAgents))
			{
				return true;
			}
			Entity entity = base.entity;
			Vec3d vec3d = radius;
			double num = entityBehaviorRepulseAgents.ownPosRepulseY;
			if (num > ownPosRepulseY + vec3d.Y || ownPosRepulseY > num + (double)e.SelectionBox.Height)
			{
				return true;
			}
			double num2 = ownPosRepulseX - entityBehaviorRepulseAgents.ownPosRepulseX;
			double num3 = ownPosRepulseZ - entityBehaviorRepulseAgents.ownPosRepulseZ;
			float yaw = entity.ServerPos.Yaw;
			double num4 = RelDistanceToEllipsoid(num2, num3, vec3d.X, vec3d.Z, yaw);
			if (num4 >= 1.0)
			{
				return true;
			}
			double num5 = -1.0 * (1.0 - num4);
			double num6 = num2 * num5;
			double num7 = 0.0;
			double num8 = num3 * num5;
			float num9 = entity.SelectionBox.Length * entity.SelectionBox.Height;
			float num10 = GameMath.Clamp(e.SelectionBox.Length * e.SelectionBox.Height / num9, 0f, 1f) / 1.5f;
			if (e.OnGround)
			{
				num10 *= 10f;
			}
			pushVector.Add(num6 * (double)num10, num7 * (double)num10 * 0.75, num8 * (double)num10);
			return true;
		}

		public double RelDistanceToEllipsoid(double x, double z, double wdt, double len, double yaw)
		{
			double num = x * Math.Cos(yaw) - z * Math.Sin(yaw);
			double num2 = x * Math.Sin(yaw) + z * Math.Cos(yaw);
			double num3 = num + offset.X;
			num2 += offset.Z;
			return num3 * num3 / (wdt * wdt) + num2 * num2 / (len * len);
		}
	}
	public class EntityBehaviorRepulseAgents : EntityBehavior
	{
		protected Vec3d pushVector = new Vec3d();

		protected EntityPartitioning partitionUtil;

		protected bool movable = true;

		protected bool ignorePlayers;

		protected double touchdist;

		private IClientWorldAccessor cworld;

		public double ownPosRepulseX;

		public double ownPosRepulseY;

		public double ownPosRepulseZ;

		public float mySize;

		protected int dimension;

		public override bool ThreadSafe => true;

		public EntityBehaviorRepulseAgents(Entity entity)
			: base(entity)
		{
			entity.hasRepulseBehavior = true;
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
			movable = attributes["movable"].AsBool(defaultValue: true);
			partitionUtil = entity.Api.ModLoader.GetModSystem<EntityPartitioning>();
			ignorePlayers = entity is EntityPlayer && entity.World.Config.GetAsBool("player2PlayerCollisions", defaultValue: true);
			cworld = entity.World as IClientWorldAccessor;
		}

		public override void AfterInitialized(bool onFirstSpawn)
		{
			touchdist = entity.touchDistance;
			entity.BHRepulseAgents = this;
			entity.AfterPhysicsTick = AfterPhysicsTick;
		}

		public override void UpdateColSelBoxes()
		{
			touchdist = entity.touchDistance;
		}

		public void AfterPhysicsTick()
		{
			Entity obj = entity;
			EntityPos sidedPos = obj.SidedPos;
			Cuboidf collisionBox = obj.CollisionBox;
			Cuboidf originCollisionBox = obj.OriginCollisionBox;
			ownPosRepulseX = sidedPos.X + (double)(collisionBox.X2 - originCollisionBox.X2);
			ownPosRepulseY = sidedPos.Y + (double)(collisionBox.Y2 - originCollisionBox.Y2);
			ownPosRepulseZ = sidedPos.Z + (double)(collisionBox.Z2 - originCollisionBox.Z2);
		}

		public override void OnGameTick(float deltaTime)
		{
			Entity entity = base.entity;
			if (entity.State == EnumEntityState.Inactive || !entity.IsInteractable || !movable)
			{
				return;
			}
			EntityAgent entityAgent = entity as EntityAgent;
			if (entityAgent?.MountedOn != null || entity.World.ElapsedMilliseconds < 2000)
			{
				return;
			}
			Vec3d vec3d = pushVector;
			vec3d.Set(0.0, 0.0, 0.0);
			mySize = entity.SelectionBox.Length * entity.SelectionBox.Height * (float)((entityAgent == null || !entityAgent.Controls.Sneak) ? 1 : 2);
			dimension = entity.ServerPos.Dimension;
			if (cworld != null && entity != cworld.Player.Entity)
			{
				WalkEntity(cworld.Player.Entity);
			}
			else
			{
				partitionUtil.WalkEntities(ownPosRepulseX, ownPosRepulseY, ownPosRepulseZ, touchdist + partitionUtil.LargestTouchDistance + 0.1, WalkEntity, IsInRangePartition, EnumEntitySearchType.Creatures);
			}
			if (vec3d.X != 0.0 || vec3d.Z != 0.0 || vec3d.Y != 0.0)
			{
				vec3d.X = GameMath.Clamp(vec3d.X, -3.0, 3.0) / 30.0;
				vec3d.Y = GameMath.Clamp(vec3d.Y, -3.0, 0.5) / 30.0;
				vec3d.Z = GameMath.Clamp(vec3d.Z, -3.0, 3.0) / 30.0;
				if (cworld != null && entity == cworld.Player.Entity)
				{
					entity.SidedPos.Motion.Add(vec3d);
				}
				else
				{
					entity.ServerPos.Motion.Add(vec3d);
				}
			}
		}

		private bool WalkEntity(Entity e)
		{
			Entity entity = base.entity;
			if (e == entity || !(e.BHRepulseAgents is EntityBehaviorRepulseAgents entityBehaviorRepulseAgents) || !e.IsInteractable || (ignorePlayers && e is EntityPlayer))
			{
				return true;
			}
			if (e is EntityAgent entityAgent && entityAgent.MountedOn?.Entity == entity)
			{
				return true;
			}
			if (e.ServerPos.Dimension != dimension)
			{
				return true;
			}
			if (entityBehaviorRepulseAgents is ICustomRepulseBehavior customRepulseBehavior)
			{
				return customRepulseBehavior.Repulse(entity, pushVector);
			}
			double num = ownPosRepulseX - entityBehaviorRepulseAgents.ownPosRepulseX;
			double num2 = ownPosRepulseY - entityBehaviorRepulseAgents.ownPosRepulseY;
			double num3 = ownPosRepulseZ - entityBehaviorRepulseAgents.ownPosRepulseZ;
			double num4 = num * num + num2 * num2 + num3 * num3;
			double num5 = entity.touchDistanceSq + e.touchDistanceSq;
			if (num4 >= num5)
			{
				return true;
			}
			double num6 = (1.0 - num4 / num5) / (double)Math.Max(0.001f, GameMath.Sqrt(num4));
			double num7 = num * num6;
			double num8 = num2 * num6;
			double num9 = num3 * num6;
			float num10 = GameMath.Clamp(e.SelectionBox.Length * e.SelectionBox.Height / mySize, 0f, 1f);
			if (entity.OnGround)
			{
				num10 *= 3f;
			}
			pushVector.Add(num7 * (double)num10, num8 * (double)num10 * 0.75, num9 * (double)num10);
			return true;
		}

		public override string PropertyName()
		{
			return "repulseagents";
		}

		private bool IsInRangePartition(Entity e, double posX, double posY, double posZ, double radiusSq)
		{
			return true;
		}
	}
	public class EntityBehaviorReviveOnDeath : EntityBehavior
	{
		private float minHours;

		private float maxHours;

		public double DiedTotalHours
		{
			get
			{
				return entity.Attributes.GetDouble("diedTotalHours");
			}
			set
			{
				entity.Attributes.SetDouble("diedTotalHours", value);
			}
		}

		public double ReviveWaitHours
		{
			get
			{
				return entity.Attributes.GetDouble("reviveWaitHours");
			}
			set
			{
				entity.Attributes.SetDouble("reviveWaitHours", value);
			}
		}

		public EntityBehaviorReviveOnDeath(Entity entity)
			: base(entity)
		{
			if (!(entity is EntityAgent))
			{
				throw new InvalidOperationException("Reive on death behavior is only possible on entities deriving from EntityAgent");
			}
			(entity as EntityAgent).AllowDespawn = false;
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			minHours = typeAttributes["minHours"].AsFloat(24f);
			maxHours = typeAttributes["maxHours"].AsFloat(48f);
		}

		public override void OnGameTick(float deltaTime)
		{
			if (!entity.Alive && !entity.ShouldDespawn && entity.World.Calendar.TotalHours > DiedTotalHours + ReviveWaitHours)
			{
				entity.Revive();
			}
		}

		public override void OnEntityDeath(DamageSource damageSourceForDeath)
		{
			DiedTotalHours = entity.World.Calendar.TotalHours;
			ReviveWaitHours = (double)minHours + entity.World.Rand.NextDouble() * (double)(maxHours - minHours);
			base.OnEntityDeath(damageSourceForDeath);
		}

		public override string PropertyName()
		{
			return "timeddespawn";
		}
	}
	public class EntityBehaviorSelectionBoxes : EntityBehavior, IRenderer, IDisposable
	{
		private ICoreClientAPI capi;

		private Matrixf mvmat = new Matrixf();

		private bool debug;

		private bool rendererRegistered;

		public AttachmentPointAndPose[] selectionBoxes = Array.Empty<AttachmentPointAndPose>();

		private string[] selectionBoxCodes;

		public WireframeCube BoxWireframe;

		private float accum;

		private static Cuboidd standardbox = new Cuboidd(0.0, 0.0, 0.0, 1.0, 1.0, 1.0);

		private Vec3d hitPositionOBBSpace;

		private Vec3d hitPositionAABBSpace;

		public double RenderOrder => 1.0;

		public int RenderRange => 24;

		public EntityBehaviorSelectionBoxes(Entity entity)
			: base(entity)
		{
		}

		public void Dispose()
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
			capi = entity.Api as ICoreClientAPI;
			if (capi != null)
			{
				debug = capi.Settings.Bool["debugEntitySelectionBoxes"];
			}
			setupWireframe();
			entity.trickleDownRayIntersects = true;
			entity.requirePosesOnServer = true;
			selectionBoxCodes = attributes["selectionBoxes"].AsArray(Array.Empty<string>());
			if (selectionBoxCodes.Length == 0)
			{
				capi.World.Logger.Warning("EntityBehaviorSelectionBoxes, missing selectionBoxes property. Will ignore.");
			}
		}

		public override void OnTesselated()
		{
			loadSelectionBoxes();
		}

		private void loadSelectionBoxes()
		{
			List<AttachmentPointAndPose> list = new List<AttachmentPointAndPose>();
			string[] array = selectionBoxCodes;
			foreach (string code in array)
			{
				AttachmentPointAndPose attachmentPointAndPose = entity.AnimManager?.Animator?.GetAttachmentPointPose(code);
				if (attachmentPointAndPose != null)
				{
					AttachmentPointAndPose item = new AttachmentPointAndPose
					{
						AnimModelMatrix = attachmentPointAndPose.AnimModelMatrix,
						AttachPoint = attachmentPointAndPose.AttachPoint,
						CachedPose = attachmentPointAndPose.CachedPose
					};
					list.Add(item);
				}
			}
			selectionBoxes = list.ToArray();
		}

		public override void OnGameTick(float deltaTime)
		{
			if (capi != null && (accum += deltaTime) >= 1f)
			{
				accum = 0f;
				debug = capi.Settings.Bool["debugEntitySelectionBoxes"];
				setupWireframe();
			}
			base.OnGameTick(deltaTime);
		}

		private void setupWireframe()
		{
			if (!rendererRegistered)
			{
				if (capi != null)
				{
					capi.Event.RegisterRenderer(this, EnumRenderStage.AfterFinalComposition, "selectionboxesbhdebug");
					BoxWireframe = WireframeCube.CreateUnitCube(capi, -1);
				}
				rendererRegistered = true;
			}
		}

		public void OnRenderFrame(float deltaTime, EnumRenderStage stage)
		{
			if (capi.HideGuis)
			{
				return;
			}
			int hitIndex = getHitIndex();
			if (hitIndex < 0 && capi.World.Player.CurrentEntitySelection?.Entity != entity)
			{
				return;
			}
			EntityPlayer eplr = capi.World.Player.Entity;
			if (debug)
			{
				for (int i = 0; i < selectionBoxes.Length; i++)
				{
					if (hitIndex != i)
					{
						Render(eplr, i, ColorUtil.WhiteArgbVec);
					}
				}
				if (hitIndex >= 0)
				{
					Render(eplr, hitIndex, new Vec4f(1f, 0f, 0f, 1f));
				}
			}
			else if (hitIndex >= 0)
			{
				Render(eplr, hitIndex, new Vec4f(0f, 0f, 0f, 0.5f));
			}
		}

		private void Render(EntityPlayer eplr, int i, Vec4f color)
		{
			AttachmentPointAndPose apap = selectionBoxes[i];
			EntityPos pos = entity.Pos;
			mvmat.Identity();
			mvmat.Set(capi.Render.CameraMatrixOrigin);
			IMountable mountable = entity.GetInterface<IMountable>();
			IMountableSeat seatOfMountedEntity;
			if (mountable != null && (seatOfMountedEntity = mountable.GetSeatOfMountedEntity(eplr)) != null)
			{
				Vec3d vec3d = seatOfMountedEntity.SeatPosition.XYZ - seatOfMountedEntity.MountSupplier.Position.XYZ;
				mvmat.Translate(0f - (float)vec3d.X, 0f - (float)vec3d.Y, 0f - (float)vec3d.Z);
			}
			else
			{
				mvmat.Translate(pos.X - eplr.CameraPos.X, pos.InternalY - eplr.CameraPos.Y, pos.Z - eplr.CameraPos.Z);
			}
			applyBoxTransform(mvmat, apap);
			BoxWireframe.Render(capi, mvmat, 1.6f, color);
		}

		private int getHitIndex()
		{
			EntityPlayer entityPlayer = capi.World.Player.Entity;
			Ray pickingray = Ray.FromAngles(entityPlayer.SidedPos.XYZ + entityPlayer.LocalEyePos - entity.SidedPos.XYZ, entityPlayer.SidedPos.Pitch, entityPlayer.SidedPos.Yaw, capi.World.Player.WorldData.PickingRange);
			return getHitIndex(pickingray);
		}

		private void applyBoxTransform(Matrixf mvmat, AttachmentPointAndPose apap)
		{
			EntityShapeRenderer entityShapeRenderer = entity.Properties.Client.Renderer as EntityShapeRenderer;
			mvmat.RotateY((float)Math.PI / 2f + entity.SidedPos.Yaw);
			if (entityShapeRenderer != null)
			{
				mvmat.Translate(0f, entity.SelectionBox.Y2 / 2f, 0f);
				mvmat.RotateX(entityShapeRenderer.xangle);
				mvmat.RotateY(entityShapeRenderer.yangle);
				mvmat.RotateZ(entityShapeRenderer.zangle);
				mvmat.Translate(0f, (0f - entity.SelectionBox.Y2) / 2f, 0f);
			}
			mvmat.Translate(0f, 0.7f, 0f);
			mvmat.RotateX(entityShapeRenderer?.nowSwivelRad ?? 0f);
			mvmat.Translate(0f, -0.7f, 0f);
			float size = entity.Properties.Client.Size;
			mvmat.Scale(size, size, size);
			mvmat.Translate(-0.5f, 0f, -0.5f);
			mvmat.Mul(apap.AnimModelMatrix);
			ShapeElement parentElement = apap.AttachPoint.ParentElement;
			float x = (float)(parentElement.To[0] - parentElement.From[0]) / 16f;
			float y = (float)(parentElement.To[1] - parentElement.From[1]) / 16f;
			float z = (float)(parentElement.To[2] - parentElement.From[2]) / 16f;
			mvmat.Scale(x, y, z);
		}

		public override bool IntersectsRay(Ray ray, AABBIntersectionTest intersectionTester, out double intersectionDistance, ref int selectionBoxIndex, ref EnumHandling handled)
		{
			Ray pickingray = new Ray(ray.origin - entity.SidedPos.XYZ, ray.dir);
			int hitIndex = getHitIndex(pickingray);
			if (hitIndex >= 0)
			{
				intersectionDistance = hitPositionAABBSpace.Length();
				intersectionTester.hitPosition = hitPositionAABBSpace.AddCopy(entity.SidedPos.XYZ);
				selectionBoxIndex = 1 + hitIndex;
				handled = EnumHandling.PreventDefault;
				return true;
			}
			intersectionDistance = double.MaxValue;
			return false;
		}

		private int getHitIndex(Ray pickingray)
		{
			int num = -1;
			double num2 = double.MaxValue;
			double num3 = pickingray.Length * pickingray.Length;
			for (int i = 0; i < selectionBoxes.Length; i++)
			{
				AttachmentPointAndPose apap = selectionBoxes[i];
				mvmat.Identity();
				applyBoxTransform(mvmat, apap);
				Matrixf matrixf = mvmat.Clone().Invert();
				Vec4d vec4d = matrixf.TransformVector(new Vec4d(pickingray.origin.X, pickingray.origin.Y, pickingray.origin.Z, 1.0));
				Vec4d vec4d2 = matrixf.TransformVector(new Vec4d(pickingray.dir.X, pickingray.dir.Y, pickingray.dir.Z, 0.0));
				Ray r = new Ray(vec4d.XYZ, vec4d2.XYZ);
				if (Testintersection(standardbox, r))
				{
					Vec4d vec4d3 = mvmat.TransformVector(new Vec4d(hitPositionOBBSpace.X, hitPositionOBBSpace.Y, hitPositionOBBSpace.Z, 1.0));
					double num4 = (vec4d3.XYZ - pickingray.origin).LengthSq();
					if ((num < 0 || !(num2 < num4)) && !(num3 < num4))
					{
						hitPositionAABBSpace = vec4d3.XYZ;
						num2 = num4;
						num = i;
					}
				}
			}
			return num;
		}

		public Vec3d GetCenterPosOfBox(int selectionBoxIndex)
		{
			if (selectionBoxIndex >= selectionBoxes.Length)
			{
				return null;
			}
			AttachmentPointAndPose attachmentPointAndPose = selectionBoxes[selectionBoxIndex];
			mvmat.Identity();
			applyBoxTransform(mvmat, attachmentPointAndPose);
			ShapeElement parentElement = attachmentPointAndPose.AttachPoint.ParentElement;
			Vec4d vec = new Vec4d((parentElement.To[0] - parentElement.From[0]) / 2.0 / 16.0, (parentElement.To[1] - parentElement.From[1]) / 2.0 / 16.0, (parentElement.To[2] - parentElement.From[2]) / 2.0 / 16.0, 1.0);
			Vec3d a = entity.Pos.XYZ;
			EntityPlayer entityPlayer = capi.World.Player.Entity;
			if (entityPlayer?.MountedOn?.Entity == entity)
			{
				Vec3d vec3d = entityPlayer.MountedOn.SeatPosition.XYZ - entity.Pos.XYZ;
				a = new Vec3d(entityPlayer.CameraPos.X - vec3d.X, entityPlayer.CameraPos.Y - vec3d.Y, entityPlayer.CameraPos.Z - vec3d.Z);
			}
			return mvmat.TransformVector(vec).XYZ.Add(a);
		}

		public bool Testintersection(Cuboidd b, Ray r)
		{
			double num = b.X2 - b.X1;
			double num2 = b.Y2 - b.Y1;
			double num3 = b.Z2 - b.Z1;
			for (int i = 0; i < 6; i++)
			{
				BlockFacing blockFacing = BlockFacing.ALLFACES[i];
				Vec3i normali = blockFacing.Normali;
				double num4 = (double)normali.X * r.dir.X + (double)normali.Y * r.dir.Y + (double)normali.Z * r.dir.Z;
				if (!(num4 < -1E-05))
				{
					continue;
				}
				Vec3d vec3d = blockFacing.PlaneCenter.ToVec3d().Mul(num, num2, num3).Add(b.X1, b.Y1, b.Z1);
				Vec3d vec3d2 = Vec3d.Sub(vec3d, r.origin);
				double num5 = (vec3d2.X * (double)normali.X + vec3d2.Y * (double)normali.Y + vec3d2.Z * (double)normali.Z) / num4;
				if (num5 >= 0.0)
				{
					hitPositionOBBSpace = new Vec3d(r.origin.X + r.dir.X * num5, r.origin.Y + r.dir.Y * num5, r.origin.Z + r.dir.Z * num5);
					Vec3d vec3d3 = Vec3d.Sub(hitPositionOBBSpace, vec3d);
					if (Math.Abs(vec3d3.X) <= num / 2.0 && Math.Abs(vec3d3.Y) <= num2 / 2.0 && Math.Abs(vec3d3.Z) <= num3 / 2.0)
					{
						return true;
					}
				}
			}
			return false;
		}

		public bool IsAPCode(EntitySelection es, string apcode)
		{
			EntityBehaviorSelectionBoxes behavior = entity.GetBehavior<EntityBehaviorSelectionBoxes>();
			if (behavior != null)
			{
				int num = ((es != null) ? (es.SelectionBoxIndex - 1) : (-1));
				AttachmentPointAndPose[] array = behavior.selectionBoxes;
				if (num > 0 && array.Length >= num)
				{
					return array[num].AttachPoint.Code == apcode;
				}
			}
			return false;
		}

		public override void GetInfoText(StringBuilder infotext)
		{
			int hitIndex = getHitIndex();
			if (hitIndex >= 0)
			{
				if (capi.Settings.Bool["extendedDebugInfo"])
				{
					infotext.AppendLine("<font color=\"#bbbbbb\">looking at AP " + selectionBoxes[hitIndex].AttachPoint.Code + "</font>");
				}
				infotext.AppendLine(Lang.GetMatching("creature-" + entity.Code.ToShortString() + "-selectionbox-" + selectionBoxes[hitIndex].AttachPoint.Code));
			}
			base.GetInfoText(infotext);
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			base.OnEntityDespawn(despawn);
			capi?.Event.UnregisterRenderer(this, EnumRenderStage.AfterFinalComposition);
			BoxWireframe?.Dispose();
		}

		public override string PropertyName()
		{
			return "selectionboxes";
		}
	}
	public class EntityBehaviorTiredness : EntityBehavior
	{
		public Random Rand;

		private double hoursTotal;

		private long listenerId;

		public float Tiredness
		{
			get
			{
				return entity.WatchedAttributes.GetTreeAttribute("tiredness").GetFloat("tiredness");
			}
			set
			{
				entity.WatchedAttributes.GetTreeAttribute("tiredness").SetFloat("tiredness", value);
				entity.WatchedAttributes.MarkPathDirty("tiredness");
			}
		}

		public bool IsSleeping
		{
			get
			{
				ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("tiredness");
				if (treeAttribute != null)
				{
					return treeAttribute.GetInt("isSleeping") > 0;
				}
				return false;
			}
			set
			{
				entity.WatchedAttributes.GetTreeAttribute("tiredness").SetInt("isSleeping", value ? 1 : 0);
				entity.WatchedAttributes.MarkPathDirty("tiredness");
			}
		}

		public EntityBehaviorTiredness(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject typeAttributes)
		{
			ITreeAttribute treeAttribute = entity.WatchedAttributes.GetTreeAttribute("tiredness");
			if (treeAttribute == null)
			{
				entity.WatchedAttributes.SetAttribute("tiredness", treeAttribute = new TreeAttribute());
				Tiredness = typeAttributes["currenttiredness"].AsFloat();
			}
			listenerId = entity.World.RegisterGameTickListener(SlowTick, 3000);
			hoursTotal = entity.World.Calendar.TotalHours;
		}

		private void SlowTick(float dt)
		{
			bool flag = IsSleeping;
			if (flag && (entity as EntityAgent)?.MountedOn == null)
			{
				flag = (IsSleeping = false);
			}
			if (!flag && entity.World.Side != EnumAppSide.Client)
			{
				float num = (float)(entity.World.Calendar.TotalHours - hoursTotal);
				Tiredness = GameMath.Clamp(Tiredness + num * 0.75f, 0f, entity.World.Calendar.HoursPerDay / 2f);
				hoursTotal = entity.World.Calendar.TotalHours;
			}
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			base.OnEntityDespawn(despawn);
			entity.World.UnregisterGameTickListener(listenerId);
		}

		public override string PropertyName()
		{
			return "tiredness";
		}
	}
	public class EntityBehaviorPlayerInventory : EntityBehaviorTexturedClothing
	{
		private bool slotModifiedRegistered;

		private float accum;

		private IPlayer Player => (entity as EntityPlayer).Player;

		public override InventoryBase Inventory => Player?.InventoryManager.GetOwnInventory("character") as InventoryBase;

		public override string InventoryClassName => "gear";

		public override string PropertyName()
		{
			return "playerinventory";
		}

		public EntityBehaviorPlayerInventory(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			base.OnEntityDespawn(despawn);
			IInventory inventory = Player?.InventoryManager.GetOwnInventory("backpack");
			if (inventory != null)
			{
				inventory.SlotModified -= base.Inventory_SlotModifiedBackpack;
			}
		}

		protected override void loadInv()
		{
		}

		public override void storeInv()
		{
		}

		public override void OnGameTick(float deltaTime)
		{
			if (!slotModifiedRegistered)
			{
				slotModifiedRegistered = true;
				IInventory inventory = Player?.InventoryManager.GetOwnInventory("backpack");
				if (inventory != null)
				{
					inventory.SlotModified += base.Inventory_SlotModifiedBackpack;
				}
			}
			base.OnGameTick(deltaTime);
			accum += deltaTime;
			if (accum > 1f)
			{
				entity.Attributes.SetBool("hasProtectiveEyeGear", Inventory != null && Inventory.FirstOrDefault((ItemSlot slot) => !slot.Empty && (slot.Itemstack.Collectible.Attributes?.IsTrue("eyeprotective") ?? false)) != null);
			}
		}

		public override void OnTesselation(ref Shape entityShape, string shapePathForLogging, ref bool shapeIsCloned, ref string[] willDeleteElements)
		{
			IInventory inventory = Player?.InventoryManager.GetOwnInventory("backpack");
			Dictionary<string, ItemSlot> dictionary = new Dictionary<string, ItemSlot>();
			int num = 0;
			while (inventory != null && num < 4)
			{
				ItemSlot itemSlot = inventory[num];
				if (!itemSlot.Empty)
				{
					dictionary[itemSlot.Itemstack.ItemAttributes?["attachableToEntity"]?["categoryCode"]?.AsString() ?? (itemSlot.Itemstack.Class.ToString() + itemSlot.Itemstack.Collectible.Id)] = itemSlot;
				}
				num++;
			}
			foreach (KeyValuePair<string, ItemSlot> item in dictionary)
			{
				entityShape = addGearToShape(entityShape, item.Value, "default", shapePathForLogging, ref shapeIsCloned, ref willDeleteElements);
			}
			base.OnTesselation(ref entityShape, shapePathForLogging, ref shapeIsCloned, ref willDeleteElements);
		}

		public override void OnEntityDeath(DamageSource damageSourceForDeath)
		{
			Api.Event.EnqueueMainThreadTask(delegate
			{
				EntityServerProperties server = entity.Properties.Server;
				if (server == null || server.Attributes?.GetBool("keepContents") != true)
				{
					Player.InventoryManager.OnDeath();
				}
				EntityServerProperties server2 = entity.Properties.Server;
				if (server2 != null && server2.Attributes?.GetBool("dropArmorOnDeath") == true)
				{
					foreach (ItemSlot item in Inventory)
					{
						if (!item.Empty)
						{
							JsonObject itemAttributes = item.Itemstack.ItemAttributes;
							if (itemAttributes != null && itemAttributes["protectionModifiers"].Exists)
							{
								Api.World.SpawnItemEntity(item.Itemstack, entity.ServerPos.XYZ);
								item.Itemstack = null;
								item.MarkDirty();
							}
						}
					}
				}
			}, "dropinventoryondeath");
		}
	}
	public class EntityBehaviorSemiTamed : EntityBehavior
	{
		public EntityBehaviorSemiTamed(Entity entity)
			: base(entity)
		{
		}

		public override void AfterInitialized(bool onFirstSpawn)
		{
			base.AfterInitialized(onFirstSpawn);
			entity.GetBehavior<EntityBehaviorTaskAI>().TaskManager.OnShouldExecuteTask += TaskManager_OnShouldExecuteTask;
		}

		private bool TaskManager_OnShouldExecuteTask(IAiTask t)
		{
			if (t is AiTaskFleeEntity aiTaskFleeEntity)
			{
				if (aiTaskFleeEntity.WhenInEmotionState == null)
				{
					return !(aiTaskFleeEntity.targetEntity is EntityPlayer);
				}
				return false;
			}
			return true;
		}

		public override string PropertyName()
		{
			return "semitamed";
		}
	}
	public abstract class EntityBehaviorTexturedClothing : EntityBehaviorContainer
	{
		protected int skinTextureSubId;

		private ICoreClientAPI capi;

		private bool textureSpaceAllocated;

		public bool doReloadShapeAndSkin = true;

		protected TextureAtlasPosition skinTexPos
		{
			get
			{
				return (entity.Properties.Client.Renderer as EntityShapeRenderer).skinTexPos;
			}
			set
			{
				(entity.Properties.Client.Renderer as EntityShapeRenderer).skinTexPos = value;
			}
		}

		public Size2i AtlasSize => capi.EntityTextureAtlas.Size;

		public event Action<LoadedTexture, TextureAtlasPosition, int> OnReloadSkin;

		public EntityBehaviorTexturedClothing(Entity entity)
			: base(entity)
		{
		}

		public override void Initialize(EntityProperties properties, JsonObject attributes)
		{
			base.Initialize(properties, attributes);
			capi = Api as ICoreClientAPI;
		}

		public override void OnTesselation(ref Shape entityShape, string shapePathForLogging, ref bool shapeIsCloned, ref string[] willDeleteElements)
		{
			base.OnTesselation(ref entityShape, shapePathForLogging, ref shapeIsCloned, ref willDeleteElements);
			reloadSkin();
		}

		public override ITexPositionSource GetTextureSource(ref EnumHandling handling)
		{
			if (Environment.CurrentManagedThreadId != RuntimeEnv.MainThreadId)
			{
				throw new InvalidOperationException("Potentially attempting to insert a texture into the atlas outside of the main thread (if this allocation causes a new atlas to be created).");
			}
			handling = EnumHandling.PassThrough;
			if (!textureSpaceAllocated)
			{
				TextureAtlasPosition textureAtlasPosition = capi.EntityTextureAtlas.Positions[entity.Properties.Client.FirstTexture.Baked.TextureSubId];
				string text = entity.Properties.Attributes?["skinBaseTextureKey"].AsString();
				if (text != null)
				{
					textureAtlasPosition = capi.EntityTextureAtlas.Positions[entity.Properties.Client.Textures[text].Baked.TextureSubId];
				}
				int width = (int)((textureAtlasPosition.x2 - textureAtlasPosition.x1) * (float)AtlasSize.Width);
				int height = (int)((textureAtlasPosition.y2 - textureAtlasPosition.y1) * (float)AtlasSize.Height);
				capi.EntityTextureAtlas.AllocateTextureSpace(width, height, out skinTextureSubId, out var texPos);
				skinTexPos = texPos;
				textureSpaceAllocated = true;
			}
			return null;
		}

		public void reloadSkin()
		{
			if (capi == null || !doReloadShapeAndSkin || skinTexPos == null)
			{
				return;
			}
			TextureAtlasPosition textureAtlasPosition = capi.EntityTextureAtlas.Positions[entity.Properties.Client.FirstTexture.Baked.TextureSubId];
			string text = entity.Properties.Attributes?["skinBaseTextureKey"].AsString();
			if (text != null)
			{
				textureAtlasPosition = capi.EntityTextureAtlas.Positions[entity.Properties.Client.Textures[text].Baked.TextureSubId];
			}
			LoadedTexture loadedTexture = new LoadedTexture(null)
			{
				TextureId = textureAtlasPosition.atlasTextureId,
				Width = capi.EntityTextureAtlas.Size.Width,
				Height = capi.EntityTextureAtlas.Size.Height
			};
			capi.Render.GlToggleBlend(blend: false);
			capi.EntityTextureAtlas.RenderTextureIntoAtlas(skinTexPos.atlasTextureId, loadedTexture, (int)(textureAtlasPosition.x1 * (float)AtlasSize.Width), (int)(textureAtlasPosition.y1 * (float)AtlasSize.Height), (int)((textureAtlasPosition.x2 - textureAtlasPosition.x1) * (float)AtlasSize.Width), (int)((textureAtlasPosition.y2 - textureAtlasPosition.y1) * (float)AtlasSize.Height), skinTexPos.x1 * (float)capi.EntityTextureAtlas.Size.Width, skinTexPos.y1 * (float)capi.EntityTextureAtlas.Size.Height, -1f);
			capi.Render.GlToggleBlend(blend: true, EnumBlendMode.Overlay);
			this.OnReloadSkin?.Invoke(loadedTexture, skinTexPos, skinTextureSubId);
			int[] array = new int[12]
			{
				3, 4, 2, 11, 9, 1, 7, 6, 0, 5,
				10, 8
			};
			foreach (int slotId in array)
			{
				ItemStack itemStack = Inventory[slotId]?.Itemstack;
				if (itemStack != null && !hideClothing && itemStack.Item.FirstTexture != null)
				{
					int textureSubId = itemStack.Item.FirstTexture.Baked.TextureSubId;
					TextureAtlasPosition textureAtlasPosition2 = capi.ItemTextureAtlas.Positions[textureSubId];
					LoadedTexture fromTexture = new LoadedTexture(null)
					{
						TextureId = textureAtlasPosition2.atlasTextureId,
						Width = capi.ItemTextureAtlas.Size.Width,
						Height = capi.ItemTextureAtlas.Size.Height
					};
					capi.EntityTextureAtlas.RenderTextureIntoAtlas(skinTexPos.atlasTextureId, fromTexture, textureAtlasPosition2.x1 * (float)capi.ItemTextureAtlas.Size.Width, textureAtlasPosition2.y1 * (float)capi.ItemTextureAtlas.Size.Height, (textureAtlasPosition2.x2 - textureAtlasPosition2.x1) * (float)capi.ItemTextureAtlas.Size.Width, (textureAtlasPosition2.y2 - textureAtlasPosition2.y1) * (float)capi.ItemTextureAtlas.Size.Height, skinTexPos.x1 * (float)capi.EntityTextureAtlas.Size.Width, skinTexPos.y1 * (float)capi.EntityTextureAtlas.Size.Height);
				}
			}
			capi.Render.GlToggleBlend(blend: true);
			capi.Render.BindTexture2d(skinTexPos.atlasTextureId);
			capi.Render.GlGenerateTex2DMipmaps();
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			base.OnEntityDespawn(despawn);
			capi?.EntityTextureAtlas.FreeTextureSpace(skinTextureSubId);
		}

		public override string PropertyName()
		{
			return "clothing";
		}
	}
	public class FallingBlockParticlesModSystem : ModSystem
	{
		private static SimpleParticleProperties dustParticles;

		private static SimpleParticleProperties bitsParticles;

		private ICoreClientAPI capi;

		private HashSet<EntityBlockFalling> fallingBlocks = new HashSet<EntityBlockFalling>();

		private ConcurrentQueue<EntityBlockFalling> toRegister = new ConcurrentQueue<EntityBlockFalling>();

		private ConcurrentQueue<EntityBlockFalling> toRemove = new ConcurrentQueue<EntityBlockFalling>();

		public int ActiveFallingBlocks => fallingBlocks.Count;

		static FallingBlockParticlesModSystem()
		{
			dustParticles = new SimpleParticleProperties(1f, 3f, ColorUtil.ToRgba(40, 220, 220, 220), new Vec3d(), new Vec3d(), new Vec3f(-0.25f, -0.25f, -0.25f), new Vec3f(0.25f, 0.25f, 0.25f), 1f, 1f, 0.3f, 0.3f, EnumParticleModel.Quad);
			dustParticles.AddQuantity = 5f;
			dustParticles.MinVelocity.Set(-0.05f, -0.4f, -0.05f);
			dustParticles.AddVelocity.Set(0.1f, 0.2f, 0.1f);
			dustParticles.WithTerrainCollision = true;
			dustParticles.ParticleModel = EnumParticleModel.Quad;
			dustParticles.OpacityEvolve = EvolvingNatFloat.create(EnumTransformFunction.QUADRATIC, -16f);
			dustParticles.SizeEvolve = EvolvingNatFloat.create(EnumTransformFunction.QUADRATIC, 3f);
			dustParticles.GravityEffect = 0f;
			dustParticles.MaxSize = 1.3f;
			dustParticles.LifeLength = 3f;
			dustParticles.SelfPropelled = true;
			dustParticles.AddPos.Set(1.4, 1.4, 1.4);
			bitsParticles = new SimpleParticleProperties(1f, 3f, ColorUtil.ToRgba(40, 220, 220, 220), new Vec3d(), new Vec3d(), new Vec3f(-0.25f, -0.25f, -0.25f), new Vec3f(0.25f, 0.25f, 0.25f), 1f, 1f, 0.1f, 0.3f, EnumParticleModel.Quad);
			bitsParticles.AddPos.Set(1.4, 1.4, 1.4);
			bitsParticles.AddQuantity = 20f;
			bitsParticles.MinVelocity.Set(-0.25f, 0f, -0.25f);
			bitsParticles.AddVelocity.Set(0.5f, 1f, 0.5f);
			bitsParticles.WithTerrainCollision = true;
			bitsParticles.ParticleModel = EnumParticleModel.Cube;
			bitsParticles.LifeLength = 1.5f;
			bitsParticles.SizeEvolve = EvolvingNatFloat.create(EnumTransformFunction.QUADRATIC, -0.5f);
			bitsParticles.GravityEffect = 2.5f;
			bitsParticles.MinSize = 0.5f;
			bitsParticles.MaxSize = 1.5f;
		}

		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Client;
		}

		public override void StartClientSide(ICoreClientAPI api)
		{
			capi = api;
			api.Event.RegisterAsyncParticleSpawner(asyncParticleSpawn);
		}

		public void Register(EntityBlockFalling entity)
		{
			toRegister.Enqueue(entity);
		}

		public void Unregister(EntityBlockFalling entity)
		{
			toRemove.Enqueue(entity);
		}

		private bool asyncParticleSpawn(float dt, IAsyncParticleManager manager)
		{
			int num = manager.ParticlesAlive(EnumParticleModel.Quad);
			float num2 = Math.Max(0.05f, (float)Math.Pow(0.949999988079071, (float)num / 200f));
			foreach (EntityBlockFalling fallingBlock in fallingBlocks)
			{
				float num3 = 0f;
				if (fallingBlock.nowImpacted)
				{
					if (capi.World.BlockAccessor.GetBlock(fallingBlock.Pos.AsBlockPos, 2).Id == 0)
					{
						num3 = 20f;
					}
					fallingBlock.nowImpacted = false;
				}
				if (fallingBlock.Block.Id != 0)
				{
					dustParticles.Color = fallingBlock.stackForParticleColor.Collectible.GetRandomColor(capi, fallingBlock.stackForParticleColor);
					dustParticles.Color &= 16777215;
					dustParticles.Color |= -1778384896;
					dustParticles.MinPos.Set(fallingBlock.Pos.X - 0.2 - 0.5, fallingBlock.Pos.Y, fallingBlock.Pos.Z - 0.2 - 0.5);
					dustParticles.MinSize = 1f;
					float num4 = num3 / 20f;
					dustParticles.AddPos.Y = fallingBlock.maxSpawnHeightForParticles;
					dustParticles.MinVelocity.Set(-0.2f * num4, 1f * (float)fallingBlock.Pos.Motion.Y, -0.2f * num4);
					dustParticles.AddVelocity.Set(0.4f * num4, 0.2f * (float)fallingBlock.Pos.Motion.Y + (0f - num4), 0.4f * num4);
					dustParticles.MinQuantity = num3 * fallingBlock.dustIntensity * num2 / 2f;
					dustParticles.AddQuantity = (6f * Math.Abs((float)fallingBlock.Pos.Motion.Y) + num3) * fallingBlock.dustIntensity * num2 / 2f;
					manager.Spawn(dustParticles);
				}
				bitsParticles.MinPos.Set(fallingBlock.Pos.X - 0.2 - 0.5, fallingBlock.Pos.Y - 0.5, fallingBlock.Pos.Z - 0.2 - 0.5);
				bitsParticles.MinVelocity.Set(-2f, 30f * (float)fallingBlock.Pos.Motion.Y, -2f);
				bitsParticles.AddVelocity.Set(4f, 0.2f * (float)fallingBlock.Pos.Motion.Y, 4f);
				bitsParticles.MinQuantity = num2;
				bitsParticles.AddQuantity = 6f * Math.Abs((float)fallingBlock.Pos.Motion.Y) * num2;
				bitsParticles.Color = dustParticles.Color;
				bitsParticles.AddPos.Y = fallingBlock.maxSpawnHeightForParticles;
				dustParticles.Color = fallingBlock.Block.GetRandomColor(capi, fallingBlock.stackForParticleColor);
				capi.World.SpawnParticles(bitsParticles);
			}
			int count = toRegister.Count;
			while (count-- > 0)
			{
				if (toRegister.TryDequeue(out var result))
				{
					fallingBlocks.Add(result);
				}
			}
			count = toRemove.Count;
			while (count-- > 0)
			{
				if (toRemove.TryDequeue(out var result2))
				{
					fallingBlocks.Remove(result2);
				}
			}
			return true;
		}
	}
	public class EntityBlockFalling : Entity
	{
		private const int packetIdMagicNumber = 1234;

		private static HashSet<long> fallingNow = new HashSet<long>();

		private readonly List<int> fallDirections = new List<int> { 0, 1, 2, 3 };

		private int lastFallDirection;

		private int hopUpHeight = 1;

		private FallingBlockParticlesModSystem particleSys;

		private int ticksAlive;

		private int lingerTicks;

		private AssetLocation blockCode;

		private ItemStack[] drops;

		private float impactDamageMul;

		private bool fallHandled;

		private byte[] lightHsv;

		private AssetLocation fallSound;

		private ILoadedSound sound;

		private float soundStartDelay;

		private bool canFallSideways;

		private Vec3d fallMotion = new Vec3d();

		private float pushaccum;

		internal float dustIntensity;

		internal ItemStack stackForParticleColor;

		internal bool nowImpacted;

		public bool InitialBlockRemoved;

		public BlockPos initialPos;

		public TreeAttribute blockEntityAttributes;

		public string blockEntityClass;

		public BlockEntity removedBlockentity;

		public bool DoRemoveBlock = true;

		public float maxSpawnHeightForParticles = 1.4f;

		public override float MaterialDensity => 99999f;

		public override byte[] LightHsv => lightHsv;

		public Block Block => World.BlockAccessor.GetBlock(blockCode);

		public override bool IsInteractable => false;

		public EntityBlockFalling()
		{
		}

		public EntityBlockFalling(Block block, BlockEntity blockEntity, BlockPos initialPos, AssetLocation fallSound, float impactDamageMul, bool canFallSideways, float dustIntensity)
		{
			this.impactDamageMul = impactDamageMul;
			this.fallSound = fallSound;
			this.canFallSideways = canFallSideways;
			this.dustIntensity = dustIntensity;
			WatchedAttributes.SetBool("canFallSideways", canFallSideways);
			WatchedAttributes.SetFloat("dustIntensity", dustIntensity);
			if (fallSound != null)
			{
				WatchedAttributes.SetString("fallSound", fallSound.ToShortString());
			}
			Code = new AssetLocation("blockfalling");
			blockCode = block.Code;
			removedBlockentity = blockEntity;
			this.initialPos = initialPos.Copy();
			ServerPos.SetPos(initialPos);
			ServerPos.X += 0.5;
			ServerPos.Y -= 0.01;
			ServerPos.Z += 0.5;
			Pos.SetFrom(ServerPos);
		}

		public override void Initialize(EntityProperties properties, ICoreAPI api, long InChunkIndex3d)
		{
			if (removedBlockentity != null)
			{
				blockEntityAttributes = new TreeAttribute();
				removedBlockentity.ToTreeAttributes(blockEntityAttributes);
				blockEntityClass = api.World.ClassRegistry.GetBlockEntityClass(removedBlockentity.GetType());
			}
			SimulationRange = (int)(0.75f * (float)GlobalConstants.DefaultSimulationRange);
			base.Initialize(properties, api, InChunkIndex3d);
			try
			{
				drops = Block.GetDrops(api.World, initialPos, null);
			}
			catch (Exception)
			{
				drops = null;
				api.Logger.Warning("Falling block entity could not properly initialise its drops during chunk loading, as original block is no longer at " + initialPos);
			}
			lightHsv = Block.GetLightHsv(World.BlockAccessor, initialPos);
			if (drops != null && drops.Length != 0)
			{
				stackForParticleColor = drops[0];
			}
			else
			{
				stackForParticleColor = new ItemStack(Block);
			}
			if (api.Side == EnumAppSide.Client && fallSound != null && fallingNow.Count < 100)
			{
				fallingNow.Add(EntityId);
				ICoreClientAPI coreClientAPI = api as ICoreClientAPI;
				sound = coreClientAPI.World.LoadSound(new SoundParams
				{
					Location = fallSound.WithPathPrefixOnce("sounds/").WithPathAppendixOnce(".ogg"),
					Position = new Vec3f((float)Pos.X, (float)Pos.Y, (float)Pos.Z),
					Range = 32f,
					Pitch = 0.8f + (float)coreClientAPI.World.Rand.NextDouble() * 0.3f,
					Volume = 1f,
					SoundType = EnumSoundType.Ambient
				});
				sound.Start();
				soundStartDelay = 0.05f + (float)coreClientAPI.World.Rand.NextDouble() / 3f;
			}
			canFallSideways = WatchedAttributes.GetBool("canFallSideways");
			dustIntensity = WatchedAttributes.GetFloat("dustIntensity");
			if (WatchedAttributes.HasAttribute("fallSound"))
			{
				fallSound = new AssetLocation(WatchedAttributes.GetString("fallSound"));
			}
			if (api.World.Side == EnumAppSide.Client)
			{
				particleSys = api.ModLoader.GetModSystem<FallingBlockParticlesModSystem>();
				particleSys.Register(this);
			}
			RandomizeFallingDirectionsOrder();
			if (DoRemoveBlock)
			{
				World.BlockAccessor.SetBlock(0, initialPos);
			}
		}

		public override void OnGameTick(float dt)
		{
			World.FrameProfiler.Enter("entity-tick-unsstablefalling");
			if (soundStartDelay > 0f)
			{
				soundStartDelay -= dt;
				if (soundStartDelay <= 0f)
				{
					sound.Start();
				}
			}
			if (sound != null)
			{
				sound.SetPosition((float)Pos.X, (float)Pos.Y, (float)Pos.Z);
			}
			if (lingerTicks > 0)
			{
				lingerTicks--;
				if (lingerTicks != 0)
				{
					return;
				}
				if (Api.Side == EnumAppSide.Client && sound != null)
				{
					sound.FadeOut(3f, delegate(ILoadedSound s)
					{
						s.Dispose();
					});
				}
				Die();
				return;
			}
			World.FrameProfiler.Mark("entity-tick-unsstablefalling-sound(etc)");
			ticksAlive++;
			if (ticksAlive >= 2 || Api.World.Side == EnumAppSide.Client)
			{
				if (!InitialBlockRemoved)
				{
					InitialBlockRemoved = true;
					UpdateBlock(remove: true, initialPos);
				}
				foreach (EntityBehavior behavior in base.SidedProperties.Behaviors)
				{
					behavior.OnGameTick(dt);
				}
				World.FrameProfiler.Mark("entity-tick-unsstablefalling-physics(etc)");
			}
			pushaccum += dt;
			fallMotion.X *= 0.9900000095367432;
			fallMotion.Z *= 0.9900000095367432;
			if (pushaccum > 0.2f)
			{
				pushaccum = 0f;
				if (!base.Collided)
				{
					Entity[] entitiesAround;
					if (Api.Side == EnumAppSide.Server)
					{
						entitiesAround = World.GetEntitiesAround(base.SidedPos.XYZ, 1.1f, 1.1f, (Entity e) => !(e is EntityBlockFalling));
						bool flag = false;
						Entity[] array = entitiesAround;
						foreach (Entity entity in array)
						{
							bool flag2 = entity.ReceiveDamage(new DamageSource
							{
								Source = EnumDamageSource.Block,
								Type = EnumDamageType.Crushing,
								SourceBlock = Block,
								SourcePos = base.SidedPos.XYZ
							}, 10f * (float)Math.Abs(ServerPos.Motion.Y) * impactDamageMul);
							if (flag2 && !flag)
							{
								flag = flag2;
								Api.World.PlaySoundAt(Block.Sounds.Break, entity);
							}
						}
					}
					else
					{
						entitiesAround = World.GetEntitiesAround(base.SidedPos.XYZ, 1.1f, 1.1f, (Entity e) => e is EntityPlayer);
					}
					for (int num2 = 0; num2 < entitiesAround.Length; num2++)
					{
						entitiesAround[num2].SidedPos.Motion.Add(fallMotion.X / 10.0, 0.0, fallMotion.Z / 10.0);
					}
				}
			}
			World.FrameProfiler.Mark("entity-tick-unsstablefalling-finalizemotion");
			if (Api.Side == EnumAppSide.Server && !base.Collided && World.Rand.NextDouble() < 0.01)
			{
				World.BlockAccessor.TriggerNeighbourBlockUpdate(ServerPos.AsBlockPos);
				World.FrameProfiler.Mark("entity-tick-unsstablefalling-neighborstrigger");
			}
			if (CollidedVertically && Pos.Motion.Length() < 0.0010000000474974513)
			{
				OnFallToGround(0.0);
				World.FrameProfiler.Mark("entity-tick-unsstablefalling-falltoground");
			}
			World.FrameProfiler.Leave();
		}

		public override void OnEntityDespawn(EntityDespawnData despawn)
		{
			base.OnEntityDespawn(despawn);
			if (Api.World.Side == EnumAppSide.Client)
			{
				fallingNow.Remove(EntityId);
				particleSys.Unregister(this);
			}
		}

		private void UpdateBlock(bool remove, BlockPos pos)
		{
			if (remove)
			{
				if (DoRemoveBlock)
				{
					World.BlockAccessor.MarkBlockDirty(pos, delegate
					{
						OnChunkRetesselated(on: true);
					});
				}
				else
				{
					OnChunkRetesselated(on: true);
				}
			}
			else
			{
				if (World.BlockAccessor.GetBlock(pos, 2).Id == 0 || Block.BlockMaterial != EnumBlockMaterial.Snow)
				{
					World.BlockAccessor.SetBlock(Block.BlockId, pos);
					World.BlockAccessor.MarkBlockDirty(pos, delegate
					{
						OnChunkRetesselated(on: false);
					});
				}
				else
				{
					OnChunkRetesselated(on: true);
				}
				if (blockEntityAttributes != null)
				{
					BlockEntity blockEntity = World.BlockAccessor.GetBlockEntity(pos);
					blockEntityAttributes.SetInt("posx", pos.X);
					blockEntityAttributes.SetInt("posy", pos.Y);
					blockEntityAttributes.SetInt("posz", pos.Z);
					blockEntity?.FromTreeAttributes(blockEntityAttributes, World);
				}
			}
			World.BlockAccessor.TriggerNeighbourBlockUpdate(pos);
		}

		private void OnChunkRetesselated(bool on)
		{
			if (base.Properties.Client.Renderer is EntityBlockFallingRenderer entityBlockFallingRenderer)
			{
				entityBlockFallingRenderer.DoRender = on;
			}
		}

		private void RandomizeFallingDirectionsOrder()
		{
			for (int num = fallDirections.Count - 1; num > 0; num--)
			{
				int index = GameMath.MurmurHash3Mod(EntityId.GetHashCode(), num, num, fallDirections.Count);
				int value = fallDirections[num];
				fallDirections[num] = fallDirections[index];
				fallDirections[index] = value;
			}
			lastFallDirection = fallDirections[3];
		}

		public override void OnFallToGround(double motionY)
		{
			if (fallHandled)
			{
				return;
			}
			BlockPos asBlockPos = base.SidedPos.AsBlockPos;
			BlockPos finalPos = ServerPos.AsBlockPos;
			Block block = null;
			if (Api.Side == EnumAppSide.Server)
			{
				block = World.BlockAccessor.GetMostSolidBlock(finalPos);
				if (block.CanAcceptFallOnto(World, finalPos, Block, blockEntityAttributes))
				{
					Api.Event.EnqueueMainThreadTask(delegate
					{
						block.OnFallOnto(World, finalPos, Block, blockEntityAttributes);
					}, "BlockFalling-OnFallOnto");
					lingerTicks = 3;
					fallHandled = true;
					return;
				}
			}
			if (canFallSideways)
			{
				foreach (int fallDirection in fallDirections)
				{
					BlockFacing blockFacing = BlockFacing.ALLFACES[fallDirection];
					if ((blockFacing != BlockFacing.NORTH || lastFallDirection != BlockFacing.SOUTH.Index) && (blockFacing != BlockFacing.WEST || lastFallDirection != BlockFacing.EAST.Index) && (blockFacing != BlockFacing.SOUTH || lastFallDirection != BlockFacing.NORTH.Index) && (blockFacing != BlockFacing.EAST || lastFallDirection != BlockFacing.WEST.Index) && World.BlockAccessor.GetMostSolidBlock(asBlockPos.X + blockFacing.Normali.X, asBlockPos.InternalY + blockFacing.Normali.Y, asBlockPos.Z + blockFacing.Normali.Z).Replaceable >= 6000 && World.BlockAccessor.GetMostSolidBlock(asBlockPos.X + blockFacing.Normali.X, asBlockPos.InternalY + blockFacing.Normali.Y - 1, asBlockPos.Z + blockFacing.Normali.Z).Replaceable >= 6000)
					{
						if (Api.Side == EnumAppSide.Server)
						{
							base.SidedPos.X += blockFacing.Normali.X;
							base.SidedPos.Y += blockFacing.Normali.Y;
							base.SidedPos.Z += blockFacing.Normali.Z;
						}
						fallMotion.Set(blockFacing.Normalf.X, 0.0, blockFacing.Normalf.Z);
						lastFallDirection = fallDirection;
						return;
					}
				}
			}
			nowImpacted = true;
			if (Api.Side == EnumAppSide.Server)
			{
				if ((block.Id != 0 && Block.BlockMaterial == EnumBlockMaterial.Snow) || block.IsReplacableBy(Block))
				{
					Api.Event.EnqueueMainThreadTask(delegate
					{
						if (block.Id != 0 && Block.BlockMaterial == EnumBlockMaterial.Snow)
						{
							UpdateSnowLayer(finalPos, block);
							(Api as ICoreServerAPI).Network.BroadcastEntityPacket(EntityId, 1234);
						}
						else if (block.IsReplacableBy(Block))
						{
							if (!InitialBlockRemoved)
							{
								InitialBlockRemoved = true;
								UpdateBlock(remove: true, initialPos);
							}
							UpdateBlock(remove: false, finalPos);
							(Api as ICoreServerAPI).Network.BroadcastEntityPacket(EntityId, 1234);
						}
					}, "BlockFalling-consequences");
				}
				else
				{
					if (block.Replaceable < 6000)
					{
						base.SidedPos.Y += hopUpHeight;
						hopUpHeight++;
						if (hopUpHeight > 3)
						{
							hopUpHeight = 1;
						}
						return;
					}
					DropItems(finalPos);
				}
				if (impactDamageMul > 0f)
				{
					Entity[] entitiesInsideCuboid = World.GetEntitiesInsideCuboid(finalPos, finalPos.AddCopy(1, 1, 1), (Entity e) => !(e is EntityBlockFalling));
					bool flag = false;
					Entity[] array = entitiesInsideCuboid;
					foreach (Entity entity in array)
					{
						bool flag2 = entity.ReceiveDamage(new DamageSource
						{
							Source = EnumDamageSource.Block,
							Type = EnumDamageType.Crushing,
							SourceBlock = Block,
							SourcePos = finalPos.ToVec3d()
						}, 18f * (float)Math.Abs(motionY) * impactDamageMul);
						if (flag2 && !flag)
						{
							flag = flag2;
							Api.World.PlaySoundAt(Block.Sounds.Break, entity);
						}
					}
				}
			}
			lingerTicks = 50;
			fallHandled = true;
			hopUpHeight = 1;
		}

		private void UpdateSnowLayer(BlockPos finalPos, Block block)
		{
			Block snowCoveredVariant = block.GetSnowCoveredVariant(finalPos, block.snowLevel + 1f);
			if (snowCoveredVariant != null && snowCoveredVariant != block)
			{
				World.BlockAccessor.ExchangeBlock(snowCoveredVariant.Id, finalPos);
			}
		}

		public override void OnReceivedServerPacket(int packetid, byte[] data)
		{
			base.OnReceivedServerPacket(packetid, data);
			if (packetid != 1234)
			{
				return;
			}
			if (base.Properties.Client.Renderer is EntityBlockFallingRenderer)
			{
				World.BlockAccessor.MarkBlockDirty(Pos.AsBlockPos, delegate
				{
					OnChunkRetesselated(on: false);
				});
			}
			lingerTicks = 50;
			fallHandled = true;
			nowImpacted = true;
			particleSys.Unregister(this);
		}

		private void DropItems(BlockPos pos)
		{
			Vec3d vec3d = pos.ToVec3d().Add(0.5, 0.5, 0.5);
			if (drops != null)
			{
				for (int i = 0; i < drops.Length; i++)
				{
					World.SpawnItemEntity(drops[i], vec3d);
				}
			}
			if (removedBlockentity is IBlockEntityContainer blockEntityContainer)
			{
				blockEntityContainer.DropContents(vec3d);
			}
		}

		public override void ToBytes(BinaryWriter writer, bool forClient)
		{
			WatchedAttributes.SetFloat("maxSpawnHeightForParticles", maxSpawnHeightForParticles);
			base.ToBytes(writer, forClient);
			writer.Write(initialPos.X);
			writer.Write(initialPos.Y);
			writer.Write(initialPos.Z);
			writer.Write(blockCode.ToShortString());
			writer.Write(blockEntityAttributes == null);
			if (blockEntityAttributes != null)
			{
				blockEntityAttributes.ToBytes(writer);
				writer.Write(blockEntityClass);
			}
			writer.Write(DoRemoveBlock);
		}

		public override void FromBytes(BinaryReader reader, bool forClient)
		{
			base.FromBytes(reader, forClient);
			initialPos = new BlockPos();
			initialPos.X = reader.ReadInt32();
			initialPos.Y = reader.ReadInt32();
			initialPos.Z = reader.ReadInt32();
			blockCode = new AssetLocation(reader.ReadString());
			if (!reader.ReadBoolean())
			{
				blockEntityAttributes = new TreeAttribute();
				blockEntityAttributes.FromBytes(reader);
				blockEntityClass = reader.ReadString();
			}
			if (WatchedAttributes.HasAttribute("fallSound"))
			{
				fallSound = new AssetLocation(WatchedAttributes.GetString("fallSound"));
			}
			canFallSideways = WatchedAttributes.GetBool("canFallSideways");
			dustIntensity = WatchedAttributes.GetFloat("dustIntensity");
			maxSpawnHeightForParticles = WatchedAttributes.GetFloat("maxSpawnHeightForParticles");
			DoRemoveBlock = reader.ReadBoolean();
		}

		public override bool ShouldReceiveDamage(DamageSource damageSource, float damage)
		{
			return false;
		}
	}
