	public class ErrorReporter : ModSystem
	{
		private ICoreAPI api;

		private bool clientEnabled;

		private int readyFlags;

		private ICoreClientAPI capi;

		private GuiDialog dialog;

		private IServerNetworkChannel serverChannel;

		private const int maxLogEntries = 180;

		private object logEntiresLock = new object();

		private LimitedList<string> logEntries = new LimitedList<string>(180);

		public override double ExecuteOrder()
		{
			return 0.0;
		}

		public override bool ShouldLoad(EnumAppSide side)
		{
			return true;
		}

		public override void StartPre(ICoreAPI api)
		{
			this.api = api;
			api.World.Logger.EntryAdded += Logger_EntryAdded;
		}

		public override void StartServerSide(ICoreServerAPI api)
		{
			api.ChatCommands.Create("errorreporter").WithDescription("Toggles on/off the error reporting dialog on startup").RequiresPrivilege(Privilege.controlserver)
				.RequiresPlayer()
				.WithArgs(api.ChatCommands.Parsers.Bool("activate"))
				.HandleWith(OnCmdErrRep);
			serverChannel = api.Network.RegisterChannel("errorreporter").RegisterMessageType(typeof(ServerLogEntries));
			api.Event.PlayerJoin += OnPlrJoin;
		}

		public override void StartClientSide(ICoreClientAPI api)
		{
			capi = api;
			api.ChatCommands.Create("errorreporter").WithDescription("Reopens the error reporting dialog").HandleWith(ClientCmdErrorRep);
			api.Event.LevelFinalize += OnClientReady;
			api.Network.RegisterChannel("errorreporter").RegisterMessageType(typeof(ServerLogEntries)).SetMessageHandler<ServerLogEntries>(OnServerLogEntriesReceived);
		}

		private TextCommandResult ClientCmdErrorRep(TextCommandCallingArgs textCommandCallingArgs)
		{
			if (dialog != null && dialog.IsOpened())
			{
				dialog.TryClose();
			}
			else
			{
				ShowDialog();
			}
			return TextCommandResult.Success();
		}

		private void OnClientReady()
		{
			readyFlags++;
			if (readyFlags == 2 && logEntries.Count > 0)
			{
				ShowDialog();
			}
		}

		private void OnServerLogEntriesReceived(ServerLogEntries msg)
		{
			clientEnabled = true;
			readyFlags++;
			lock (logEntiresLock)
			{
				string[] array = msg.LogEntries;
				foreach (string key in array)
				{
					logEntries.Add(key);
				}
			}
			if (readyFlags == 2 && logEntries.Count > 0)
			{
				ShowDialog();
			}
		}

		private void ShowDialog()
		{
			lock (logEntiresLock)
			{
				if (!clientEnabled)
				{
					logEntries.Clear();
					return;
				}
				List<string> list = logEntries.ToList();
				if (logEntries.Count > 180)
				{
					list = logEntries.Take(180).ToList();
					list.Add($"...{logEntries.Count} more");
				}
				dialog = new GuiDialogLogViewer(string.Join("\n", list), capi);
			}
			dialog.TryOpen();
		}

		private void OnPlrJoin(IServerPlayer byPlayer)
		{
			byPlayer.ServerData.CustomPlayerData.TryGetValue("errorReporting", out var value);
			if (value == "1" && logEntries.Count > 0)
			{
				lock (logEntiresLock)
				{
					serverChannel.SendPacket(new ServerLogEntries
					{
						LogEntries = logEntries.ToArray()
					}, byPlayer);
				}
			}
		}

		private TextCommandResult OnCmdErrRep(TextCommandCallingArgs args)
		{
			bool flag = (bool)args.Parsers[0].GetValue();
			(args.Caller.Player as IServerPlayer).ServerData.CustomPlayerData["errorReporting"] = (flag ? "1" : "0");
			return TextCommandResult.Success(Lang.Get("Error reporting now {0}", flag ? "on" : "off"));
		}

		private void Logger_EntryAdded(EnumLogType logType, string message, params object[] args)
		{
			if (logType == EnumLogType.Error || logType == EnumLogType.Fatal || logType == EnumLogType.Warning)
			{
				string key;
				try
				{
					key = $"[{api.Side} {logType}] {string.Format(message, args)}";
				}
				catch (Exception)
				{
					key = string.Format("[{0} {1}] {2}", api.Side, logType, "Error reporter failed formatting for \"" + message + "\"");
				}
				lock (logEntiresLock)
				{
					logEntries.Add(key);
				}
			}
		}
	}
	public class LeafBlockDecay : ModSystem
	{
		private class CheckDecayThread : IAsyncServerSystem
		{
			public static int leafDecayCheckTickInterval = 10;

			private HashSet<BlockPos> checkDecay;

			private HashSet<BlockPos> performDecay;

			private ICoreServerAPI sapi;

			public bool Stopping { get; set; }

			public CheckDecayThread(ICoreServerAPI sapi)
			{
				this.sapi = sapi;
			}

			public void Start(HashSet<BlockPos> checkDecay, HashSet<BlockPos> performDecay)
			{
				this.checkDecay = checkDecay;
				this.performDecay = performDecay;
				sapi.Server.AddServerThread("CheckLeafDecay", this);
			}

			public int OffThreadInterval()
			{
				return leafDecayCheckTickInterval;
			}

			public void OnSeparateThreadTick()
			{
				for (int i = 0; i < 100; i++)
				{
					if (checkDecay.Count == 0)
					{
						break;
					}
					BlockPos blockPos = null;
					lock (checkDecayLock)
					{
						blockPos = checkDecay.First();
						checkDecay.Remove(blockPos);
					}
					if (shouldDecay(blockPos))
					{
						lock (performDecayLock)
						{
							performDecay.Add(blockPos);
						}
					}
				}
			}

			public void ThreadDispose()
			{
				lock (checkDecayLock)
				{
					checkDecay.Clear();
				}
				lock (performDecayLock)
				{
					performDecay.Clear();
				}
			}

			private bool shouldDecay(BlockPos startPos)
			{
				Queue<Vec4i> queue = new Queue<Vec4i>();
				HashSet<BlockPos> hashSet = new HashSet<BlockPos>();
				IBlockAccessor blockAccessor = sapi.World.BlockAccessor;
				Block block = blockAccessor.GetBlock(startPos);
				if (canDecay(block))
				{
					queue.Enqueue(new Vec4i(startPos, 2));
					hashSet.Add(startPos);
					while (queue.Count > 0)
					{
						if (hashSet.Count > 600)
						{
							return false;
						}
						Vec4i vec4i = queue.Dequeue();
						for (int i = 0; i < Vec3i.DirectAndIndirectNeighbours.Length; i++)
						{
							Vec3i vec3i = Vec3i.DirectAndIndirectNeighbours[i];
							BlockPos blockPos = new BlockPos(vec4i.X + vec3i.X, vec4i.Y + vec3i.Y, vec4i.Z + vec3i.Z);
							if (hashSet.Contains(blockPos))
							{
								continue;
							}
							hashSet.Add(blockPos);
							block = blockAccessor.GetBlock(blockPos);
							if (preventsDecay(block))
							{
								return false;
							}
							int value = blockPos.X - startPos.X;
							int value2 = blockPos.Y - startPos.Y;
							int value3 = blockPos.Z - startPos.Z;
							if (Math.Abs(value) > 4 || Math.Abs(value2) > 4 || Math.Abs(value3) > 4)
							{
								if (block.Id != 0)
								{
									return false;
								}
							}
							else if (canDecay(block))
							{
								queue.Enqueue(new Vec4i(blockPos, 0));
							}
						}
					}
					return true;
				}
				return false;
			}
		}

		private ICoreServerAPI sapi;

		private HashSet<BlockPos> checkDecayQueue = new HashSet<BlockPos>();

		public static object checkDecayLock = new object();

		private HashSet<BlockPos> performDecayQueue = new HashSet<BlockPos>();

		public static object performDecayLock = new object();

		private CheckDecayThread checkDecayThread;

		public static int leafRemovalInterval = 1000;

		public override bool ShouldLoad(EnumAppSide side)
		{
			return side == EnumAppSide.Server;
		}

		public override void StartServerSide(ICoreServerAPI api)
		{
			sapi = api;
			api.Event.SaveGameLoaded += onSaveGameLoaded;
			api.Event.GameWorldSave += onGameGettingSaved;
			api.Event.RegisterEventBusListener(onLeafDecayEventReceived, 0.5, "testForDecay");
			api.Event.RegisterGameTickListener(processReadyToDecayQueue, leafRemovalInterval);
			sapi.ChatCommands.GetOrCreate("debug").BeginSubCommand("leafdecaydebug").WithDescription("Shows leaf decay stats")
				.RequiresPrivilege(Privilege.controlserver)
				.HandleWith((TextCommandCallingArgs _) => TextCommandResult.Success("Queue sizes: pdq: " + performDecayQueue.Count + " / cdq: " + checkDecayQueue.Count))
				.EndSubCommand();
		}

		private void processReadyToDecayQueue(float dt)
		{
			if (performDecayQueue.Count != 0)
			{
				BlockPos blockPos = null;
				lock (performDecayLock)
				{
					blockPos = performDecayQueue.First();
					performDecayQueue.Remove(blockPos);
				}
				doDecay(blockPos);
			}
		}

		private void onLeafDecayEventReceived(string eventName, ref EnumHandling handling, IAttribute data)
		{
			if (checkDecayThread != null)
			{
				TreeAttribute treeAttribute = data as TreeAttribute;
				BlockPos pos = new BlockPos(treeAttribute.GetInt("x"), treeAttribute.GetInt("y"), treeAttribute.GetInt("z"));
				queueNeighborsForCheckDecay(pos);
			}
		}

		private void queueNeighborsForCheckDecay(BlockPos pos)
		{
			lock (checkDecayLock)
			{
				for (int i = 0; i < Vec3i.DirectAndIndirectNeighbours.Length; i++)
				{
					Vec3i vec3i = Vec3i.DirectAndIndirectNeighbours[i];
					Block blockRaw = sapi.World.BlockAccessor.GetBlockRaw(pos.X + vec3i.X, pos.InternalY + vec3i.Y, pos.Z + vec3i.Z);
					if (blockRaw.Id != 0 && canDecay(blockRaw))
					{
						checkDecayQueue.Add(pos.AddCopy(vec3i));
					}
				}
			}
		}

		private void doDecay(BlockPos pos)
		{
			if (canDecay(sapi.World.BlockAccessor.GetBlock(pos)))
			{
				sapi.World.BlockAccessor.SetBlock(0, pos);
				for (int i = 0; i < 6; i++)
				{
					sapi.World.BlockAccessor.MarkBlockDirty(pos.AddCopy(BlockFacing.ALLFACES[i]));
				}
				queueNeighborsForCheckDecay(pos);
			}
		}

		private void onGameGettingSaved()
		{
			using FastMemoryStream ms = new FastMemoryStream();
			lock (checkDecayLock)
			{
				sapi.WorldManager.SaveGame.StoreData("checkDecayQueue", SerializerUtil.Serialize(checkDecayQueue, ms));
				sapi.WorldManager.SaveGame.StoreData("performDecayQueue", SerializerUtil.Serialize(performDecayQueue, ms));
			}
		}

		private void onSaveGameLoaded()
		{
			sapi.Logger.Debug("Loading leaf block decay system");
			checkDecayQueue = deserializeQueue("checkDecayQueue");
			performDecayQueue = deserializeQueue("performDecayQueue");
			checkDecayThread = new CheckDecayThread(sapi);
			checkDecayThread.Start(checkDecayQueue, performDecayQueue);
			sapi.Logger.Debug("Finished loading leaf block decay system");
		}

		private HashSet<BlockPos> deserializeQueue(string name)
		{
			try
			{
				byte[] data = sapi.WorldManager.SaveGame.GetData(name);
				if (data != null)
				{
					return SerializerUtil.Deserialize<HashSet<BlockPos>>(data);
				}
			}
			catch (Exception e)
			{
				sapi.World.Logger.Error("Failed loading LeafBlockDecay.{0}. Resetting. Exception:", name);
				sapi.World.Logger.Error(e);
			}
			return new HashSet<BlockPos>();
		}

		public static bool canDecay(Block block)
		{
			if (block.BlockMaterial == EnumBlockMaterial.Leaves)
			{
				return block.Attributes?.IsTrue("canDecay") ?? false;
			}
			return false;
		}

		public static bool preventsDecay(Block block)
		{
			if (block.Id != 0)
			{
				return block.Attributes?.IsTrue("preventsDecay") ?? false;
			}
			return false;
		}
	}
	public class ModSystemAmbientParticles : ModSystem
	{
		private SimpleParticleProperties liquidParticles;

		private SimpleParticleProperties summerAirParticles;

		private SimpleParticleProperties fireflyParticles;

		private ClampedSimplexNoise fireflyLocationNoise;

		private ClampedSimplexNoise fireflyrateNoise;

		private ICoreClientAPI capi;

		private ClimateCondition climate = new ClimateCondition();

		private bool spawnParticles;

		private Vec3d position = new Vec3d();

		private BlockPos blockPos = new BlockPos();

		public event ActionBoolReturn ShouldSpawnAmbientParticles;

		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Client;
		}

		public override void StartClientSide(ICoreClientAPI api)
		{
			capi = api;
			capi.Event.RegisterGameTickListener(OnSlowTick, 1000);
			capi.Event.RegisterAsyncParticleSpawner(AsyncParticleSpawnTick);
			liquidParticles = new SimpleParticleProperties
			{
				MinSize = 0.1f,
				MaxSize = 0.1f,
				MinQuantity = 1f,
				GravityEffect = 0f,
				LifeLength = 2f,
				ParticleModel = EnumParticleModel.Quad,
				ShouldDieInAir = true,
				VertexFlags = 512
			};
			liquidParticles.OpacityEvolve = new EvolvingNatFloat(EnumTransformFunction.QUADRATIC, -9f);
			summerAirParticles = new SimpleParticleProperties
			{
				Color = ColorUtil.ToRgba(35, 230, 230, 150),
				ParticleModel = EnumParticleModel.Quad,
				MinSize = 0.05f,
				MaxSize = 0.1f,
				GravityEffect = 0f,
				LifeLength = 2f,
				WithTerrainCollision = false,
				ShouldDieInLiquid = true,
				MinVelocity = new Vec3f(-0.125f, -0.125f, -0.125f),
				MinQuantity = 1f,
				AddQuantity = 0f
			};
			summerAirParticles.AddVelocity = new Vec3f(0.25f, 0.25f, 0.25f);
			summerAirParticles.OpacityEvolve = EvolvingNatFloat.create(EnumTransformFunction.CLAMPEDPOSITIVESINUS, (float)Math.PI);
			summerAirParticles.MinPos = new Vec3d();
			fireflyParticles = new SimpleParticleProperties
			{
				Color = ColorUtil.ToRgba(150, 150, 250, 139),
				ParticleModel = EnumParticleModel.Quad,
				MinSize = 0.1f,
				MaxSize = 0.1f,
				GravityEffect = 0f,
				LifeLength = 2f,
				ShouldDieInLiquid = true,
				MinVelocity = new Vec3f(-0.25f, -0.0625f, -0.25f),
				MinQuantity = 2f,
				AddQuantity = 0f,
				LightEmission = ColorUtil.ToRgba(255, 77, 250, 139)
			};
			fireflyParticles.AddVelocity = new Vec3f(0.5f, 0.125f, 0.5f);
			fireflyParticles.VertexFlags = 255;
			fireflyParticles.AddPos.Set(1.0, 1.0, 1.0);
			fireflyParticles.AddQuantity = 8f;
			fireflyParticles.addLifeLength = 1f;
			fireflyParticles.OpacityEvolve = EvolvingNatFloat.create(EnumTransformFunction.CLAMPEDPOSITIVESINUS, (float)Math.PI);
			fireflyParticles.RandomVelocityChange = true;
			fireflyLocationNoise = new ClampedSimplexNoise(new double[1] { 1.0 }, new double[1] { 5.0 }, capi.World.Rand.Next());
			fireflyrateNoise = new ClampedSimplexNoise(new double[1] { 1.0 }, new double[1] { 5.0 }, capi.World.Rand.Next());
		}

		private void OnSlowTick(float dt)
		{
			climate = capi.World.BlockAccessor.GetClimateAt(capi.World.Player.Entity.Pos.AsBlockPos);
			if (climate == null)
			{
				climate = new ClimateCondition();
			}
			spawnParticles = capi.Settings.Bool["ambientParticles"];
		}

		private bool AsyncParticleSpawnTick(float dt, IAsyncParticleManager manager)
		{
			if (!spawnParticles)
			{
				return true;
			}
			if (this.ShouldSpawnAmbientParticles != null && !this.ShouldSpawnAmbientParticles())
			{
				return true;
			}
			int num = capi.Settings.Int["particleLevel"];
			IClientWorldAccessor world = capi.World;
			EntityPlayer entity = world.Player.Entity;
			ClimateCondition climateAt = world.BlockAccessor.GetClimateAt(blockPos.Set((int)entity.Pos.X, (int)entity.Pos.Y, (int)entity.Pos.Z));
			float num2 = 0.5f * (float)num;
			while (num2-- > 0f)
			{
				double x = world.Rand.NextDouble() * 32.0 - 16.0;
				double y = world.Rand.NextDouble() * 20.0 - 10.0;
				double z = world.Rand.NextDouble() * 32.0 - 16.0;
				position.Set(entity.Pos.X, entity.Pos.Y, entity.Pos.Z).Add(x, y, z);
				blockPos.Set(position);
				if (!world.BlockAccessor.IsValidPos(blockPos))
				{
					continue;
				}
				double num3 = 0.05 + (double)Math.Max(0f, world.Calendar.DayLightStrength) * 0.4;
				if ((double)climateAt.Rainfall <= 0.01 && GlobalConstants.CurrentWindSpeedClient.X < 0.2f && world.Rand.NextDouble() < num3 && climate.Temperature >= 14f && climate.WorldgenRainfall >= 0.4f && blockPos.Y > world.SeaLevel && manager.BlockAccess.GetBlock(blockPos).Id == 0)
				{
					IMapChunk mapChunk = manager.BlockAccess.GetMapChunk(blockPos.X / 32, blockPos.Z / 32);
					if (mapChunk != null && blockPos.Y > mapChunk.RainHeightMap[blockPos.Z % 32 * 32 + blockPos.X % 32])
					{
						summerAirParticles.MinPos.Set(position);
						summerAirParticles.RandomVelocityChange = true;
						manager.Spawn(summerAirParticles);
					}
					continue;
				}
				Block block = manager.BlockAccess.GetBlock(blockPos, 2);
				if (block.IsLiquid() && block.LiquidLevel >= 7)
				{
					liquidParticles.MinVelocity = new Vec3f((float)world.Rand.NextDouble() / 16f - 1f / 32f, (float)world.Rand.NextDouble() / 16f - 1f / 32f, (float)world.Rand.NextDouble() / 16f - 1f / 32f);
					liquidParticles.MinPos = position;
					if (world.Rand.Next(3) > 0)
					{
						liquidParticles.RandomVelocityChange = false;
						liquidParticles.Color = ColorUtil.HsvToRgba(110, 40 + world.Rand.Next(50), 200 + world.Rand.Next(30), 50 + world.Rand.Next(40));
					}
					else
					{
						liquidParticles.RandomVelocityChange = true;
						liquidParticles.Color = ColorUtil.HsvToRgba(110, 20 + world.Rand.Next(25), 100 + world.Rand.Next(15), 100 + world.Rand.Next(40));
					}
					manager.Spawn(liquidParticles);
				}
			}
			if ((double)climateAt.Rainfall < 0.15 && climateAt.Temperature > 5f)
			{
				double num4 = (fireflyrateNoise.Noise(world.Calendar.TotalDays / 3.0, 0.0) - 0.4000000059604645) * 4.0;
				float num5 = Math.Max(0f, (float)(num4 - (double)(Math.Abs(GlobalConstants.CurrentWindSpeedClient.X) * 2f)));
				int num6 = GameMath.RoundRandom(world.Rand, num5 * 0.01f * (float)num);
				while (num6-- > 0)
				{
					double x2 = world.Rand.NextDouble() * 80.0 - 40.0;
					double y2 = world.Rand.NextDouble() * 80.0 - 40.0;
					double z2 = world.Rand.NextDouble() * 80.0 - 40.0;
					position.Set(entity.Pos.X, entity.Pos.Y, entity.Pos.Z).Add(x2, y2, z2);
					blockPos.Set(position);
					if (!world.BlockAccessor.IsValidPos(blockPos))
					{
						continue;
					}
					double num7 = Math.Max(0.0, fireflyLocationNoise.Noise((double)blockPos.X / 60.0, (double)blockPos.Z / 60.0, world.Calendar.TotalDays / 5.0 - 0.800000011920929) - 0.5) * 2.0;
					double num8 = (double)Math.Max(0f, 1f - world.Calendar.DayLightStrength * 2f) * num7;
					int y3 = blockPos.Y;
					blockPos.Y = manager.BlockAccess.GetTerrainMapheightAt(blockPos);
					Block block2 = manager.BlockAccess.GetBlock(blockPos);
					if (world.Rand.NextDouble() <= num8 && climate.Temperature >= 8f && climate.Temperature <= 29f && climate.WorldgenRainfall >= 0.4f && block2.Fertility > 30 && blockPos.Y > world.SeaLevel)
					{
						blockPos.Y += world.Rand.Next(4);
						position.Y += blockPos.Y - y3;
						block2 = manager.BlockAccess.GetBlock(blockPos);
						Cuboidf[] collisionBoxes = block2.GetCollisionBoxes(manager.BlockAccess, blockPos);
						if (collisionBoxes == null || collisionBoxes.Length == 0)
						{
							fireflyParticles.AddVelocity.X = 0.5f + GlobalConstants.CurrentWindSpeedClient.X;
							fireflyParticles.MinPos = position;
							manager.Spawn(fireflyParticles);
						}
					}
				}
			}
			return true;
		}
	}
	public abstract class EntityParticle : ParticleBase
	{
		protected float dirNormalizedX;

		protected float dirNormalizedY;

		protected float dirNormalizedZ;

		protected bool SwimOnLiquid;

		public abstract string Type { get; }

		protected float Size
		{
			set
			{
				float num = (SizeZ = value);
				float sizeX = (SizeY = num);
				SizeX = sizeX;
			}
		}

		protected float SizeX { get; set; } = 1f;

		protected float SizeY { get; set; } = 1f;

		protected float SizeZ { get; set; } = 1f;

		protected float GravityStrength { get; set; } = 1f;

		public void OnSpawned(ParticlePhysics physicsSim)
		{
			lightrgbs = physicsSim.BlockAccess.GetLightRGBsAsInt((int)Position.X, (int)Position.Y, (int)Position.Z);
		}

		public override void TickNow(float dt, float physicsdt, ICoreClientAPI api, ParticlePhysics physicsSim)
		{
			motion.Set(Velocity.X * dt, Velocity.Y * dt, Velocity.Z * dt);
			float height = SizeY / 4f;
			updatePositionWithCollision(dt, api, physicsSim, height);
			Velocity.Y -= GravityStrength * dt;
			physicsSim.HandleBoyancy(Position, Velocity, SwimOnLiquid, GravityStrength, dt, height);
			tickCount++;
			if (tickCount > 2)
			{
				doSlowTick(physicsSim, dt * 3f);
			}
			if ((double)Velocity.Length() > 0.05)
			{
				dirNormalizedX = Velocity.X;
				dirNormalizedY = Velocity.Y;
				dirNormalizedZ = Velocity.Z;
			}
		}

		protected virtual void doSlowTick(ParticlePhysics physicsSim, float dt)
		{
			lightrgbs = physicsSim.BlockAccess.GetLightRGBsAsInt((int)Position.X, (int)Position.Y, (int)Position.Z);
			tickCount = 0;
		}

		public override void UpdateBuffers(MeshData buffer, Vec3d cameraPos, ref int posPosition, ref int rgbaPosition, ref int flagPosition)
		{
			float num = 1f - prevPosAdvance;
			float[] values = buffer.CustomFloats.Values;
			values[posPosition++] = (float)(Position.X - (double)(prevPosDeltaX * num) - cameraPos.X);
			values[posPosition++] = (float)(Position.Y - (double)(prevPosDeltaY * num) - cameraPos.Y);
			values[posPosition++] = (float)(Position.Z - (double)(prevPosDeltaZ * num) - cameraPos.Z);
			values[posPosition++] = SizeX;
			values[posPosition++] = SizeY;
			values[posPosition++] = SizeZ;
			posPosition = UpdateAngles(values, posPosition);
			byte[] values2 = buffer.CustomBytes.Values;
			values2[rgbaPosition++] = (byte)lightrgbs;
			values2[rgbaPosition++] = (byte)(lightrgbs >> 8);
			values2[rgbaPosition++] = (byte)(lightrgbs >> 16);
			values2[rgbaPosition++] = (byte)(lightrgbs >> 24);
			values2[rgbaPosition++] = ColorBlue;
			values2[rgbaPosition++] = ColorGreen;
			values2[rgbaPosition++] = ColorRed;
			values2[rgbaPosition++] = ColorAlpha;
			buffer.Flags[flagPosition++] = VertexFlags;
		}

		public virtual int UpdateAngles(float[] customFloats, int posPosition)
		{
			customFloats[posPosition++] = dirNormalizedX;
			customFloats[posPosition++] = dirNormalizedY;
			customFloats[posPosition++] = dirNormalizedZ;
			customFloats[posPosition++] = 0f;
			return posPosition;
		}
	}
	public abstract class EntityParticleInsect : EntityParticle
	{
		protected ICoreClientAPI capi;

		protected float jumpCooldown;

		protected float dieAccum;

		protected float soundCoolDownLeft;

		protected static Random rand = new Random();

		protected float jumpHeight = 1.3f;

		protected AssetLocation sound;

		protected bool doubleJump = true;

		protected float soundCoolDown = 5f;

		protected virtual float soundRange => 16f;

		protected virtual float despawnDistanceSq => 400f;

		public EntityParticleInsect(ICoreClientAPI capi, double x, double y, double z)
		{
			this.capi = capi;
			Position.Set(x, y, z);
			ColorAlpha = byte.MaxValue;
			SwimOnLiquid = true;
			Alive = true;
			base.Size = 0.5f + (float)capi.World.Rand.NextDouble() * 0.5f;
		}

		protected override void doSlowTick(ParticlePhysics physicsSim, float dt)
		{
			base.doSlowTick(physicsSim, dt);
			if (capi.World.BlockAccessor.GetBlockRaw((int)Position.X, (int)Position.Y, (int)Position.Z, 2).IsLiquid())
			{
				dieAccum += dt;
				if (dieAccum > 10f)
				{
					Alive = false;
				}
				return;
			}
			if (jumpHeight > 0f && doubleJump && jumpCooldown < 1.5f && jumpCooldown > 0f && (flags & EnumCollideFlags.CollideY) > (EnumCollideFlags)0 && Velocity.Y <= 0f && rand.NextDouble() < 0.4)
			{
				jump((float)rand.NextDouble() - 0.5f, jumpHeight, (float)rand.NextDouble() - 0.5f);
			}
			if (jumpCooldown > 0f)
			{
				jumpCooldown = GameMath.Max(0f, jumpCooldown - dt);
				return;
			}
			soundCoolDownLeft = GameMath.Max(0f, soundCoolDownLeft - dt);
			if (jumpHeight > 0f && rand.NextDouble() < 0.005)
			{
				jump((float)rand.NextDouble() - 0.5f, jumpHeight, (float)rand.NextDouble() - 0.5f);
				return;
			}
			if (soundCoolDownLeft <= 0f && shouldPlaySound())
			{
				capi.Event.EnqueueMainThreadTask(playsound, "playginsectsound");
				soundCoolDownLeft = soundCoolDown;
				return;
			}
			EntityPlayer entity = capi.World.NearestPlayer(Position.X, Position.Y, Position.Z).Entity;
			double num = 2500.0;
			if (entity != null && (num = entity.Pos.SquareHorDistanceTo(Position)) < 9.0 && jumpHeight > 0f)
			{
				Vec3d vec3d = entity.Pos.XYZ.Sub(Position).Normalize();
				jump((float)(0.0 - vec3d.X), jumpHeight, (float)(0.0 - vec3d.Z));
			}
			if (entity == null || num > (double)despawnDistanceSq)
			{
				dieAccum += dt;
				if (dieAccum > 10f)
				{
					Alive = false;
				}
			}
			else
			{
				dieAccum = 0f;
			}
		}

		private void playsound()
		{
			EntityPos pos = capi.World.Player.Entity.Pos;
			float num = ((capi.ModLoader.GetModSystem<RoomRegistry>().GetRoomForPosition(pos.AsBlockPos).ExitCount < 2) ? 0.1f : 1f);
			float num2 = 1f * num;
			if (num2 > 0.05f)
			{
				capi.World.PlaySoundAt(sound, Position.X, Position.Y, Position.Z, null, RandomPitch(), soundRange, num2);
			}
		}

		protected virtual float RandomPitch()
		{
			return (float)capi.World.Rand.NextDouble() * 0.5f + 0.75f;
		}

		protected virtual bool shouldPlaySound()
		{
			return rand.NextDouble() < 0.01;
		}

		private void jump(float dirx, float diry, float dirz)
		{
			Velocity.Add(dirx, diry, dirz);
			jumpCooldown = 2f;
		}
	}
	public class EntityParticleSpawner : ModSystem
	{
		private ICoreClientAPI capi;

		private Random rand = new Random();

		private NormalizedSimplexNoise grasshopperNoise;

		private NormalizedSimplexNoise cicadaNoise;

		private NormalizedSimplexNoise matingGnatsSwarmNoise;

		private NormalizedSimplexNoise coquiNoise;

		private NormalizedSimplexNoise waterstriderNoise;

		private Queue<Action> SimTickExecQueue = new Queue<Action>();

		public HashSet<string> disabledInsects;

		private EntityParticleSystem sys;

		private float accum;

		public override bool ShouldLoad(EnumAppSide forSide)
		{
			return forSide == EnumAppSide.Client;
		}

		public override void StartClientSide(ICoreClientAPI api)
		{
			capi = api;
			grasshopperNoise = NormalizedSimplexNoise.FromDefaultOctaves(4, 0.01, 0.9, api.World.Seed * 100);
			coquiNoise = NormalizedSimplexNoise.FromDefaultOctaves(4, 0.0025, 0.9, api.World.Seed * 101);
			waterstriderNoise = NormalizedSimplexNoise.FromDefaultOctaves(4, 0.01, 0.9, api.World.Seed * 102);
			matingGnatsSwarmNoise = NormalizedSimplexNoise.FromDefaultOctaves(4, 0.01, 0.9, api.World.Seed * 103);
			cicadaNoise = NormalizedSimplexNoise.FromDefaultOctaves(4, 0.01, 0.9, api.World.Seed * 104);
			sys = api.ModLoader.GetModSystem<EntityParticleSystem>();
			sys.OnSimTick += Sys_OnSimTick;
			disabledInsects = new HashSet<string>();
			List<string> list = capi.Settings.Strings["disabledInsects"];
			if (list != null)
			{
				disabledInsects.AddRange(list);
			}
			api.ChatCommands.GetOrCreate("insectconfig").WithArgs(api.ChatCommands.Parsers.WordRange("type", "grasshopper", "cicada", "gnats", "coqui", "waterstrider"), api.ChatCommands.Parsers.OptionalBool("enable/disable")).HandleWith(onCmdInsectConfig);
			api.ChatCommands.GetOrCreate("debug").BeginSub("eps").WithDesc("eps")
				.BeginSub("testspawn")
				.WithDesc("testspawn")
				.WithArgs(api.ChatCommands.Parsers.WordRange("type", "gh", "ws", "coq", "mg", "cic", "fis"))
				.HandleWith(handleSpawn)
				.EndSub()
				.BeginSub("count")
				.WithDesc("count")
				.HandleWith(handleCount)
				.EndSub()
				.BeginSub("clear")
				.WithDesc("clear")
				.HandleWith(handleClear)
				.EndSub()
				.BeginSub("testnoise")
				.WithDesc("testnoise")
				.HandleWith(handleTestnoise)
				.WithArgs(api.ChatCommands.Parsers.OptionalWordRange("clear", "clear"))
				.EndSub()
				.EndSub();
		}

		private TextCommandResult onCmdInsectConfig(TextCommandCallingArgs args)
		{
			string text = (string)args[0];
			if (args.Parsers[1].IsMissing)
			{
				return TextCommandResult.Success(Lang.Get("{0} are currently {1}", text, disabledInsects.Contains(text) ? Lang.Get("disabled") : Lang.Get("enabled")));
			}
			bool flag = !(bool)args[1];
			if (flag)
			{
				disabledInsects.Add(text);
			}
			else
			{
				disabledInsects.Remove(text);
			}
			capi.Settings.Strings["disabledInsects"] = disabledInsects.ToList();
			return TextCommandResult.Success(Lang.Get("{0} are now {1}", text, flag ? Lang.Get("disabled") : Lang.Get("enabled")));
		}

		private TextCommandResult handleCount(TextCommandCallingArgs args)
		{
			StringBuilder stringBuilder = new StringBuilder();
			foreach (KeyValuePair<string, int> item in sys.Count.Dict)
			{
				stringBuilder.AppendLine($"{item.Key}: {item.Value}");
			}
			if (stringBuilder.Length == 0)
			{
				return TextCommandResult.Success("No entityparticle alive");
			}
			return TextCommandResult.Success(stringBuilder.ToString());
		}

		private TextCommandResult handleTestnoise(TextCommandCallingArgs args)
		{
			BlockPos asBlockPos = capi.World.Player.Entity.Pos.XYZ.AsBlockPos;
			Block block = capi.World.GetBlock(new AssetLocation("creativeblock-35"));
			bool flag = !args.Parsers[0].IsMissing;
			for (int i = -200; i <= 200; i++)
			{
				for (int j = -200; j <= 200; j++)
				{
					double num = matingGnatsSwarmNoise.Noise(asBlockPos.X + i, asBlockPos.Z + j);
					if (flag || num < 0.65)
					{
						capi.World.BlockAccessor.SetBlock(0, new BlockPos(asBlockPos.X + i, 160, asBlockPos.Z + j));
					}
					else
					{
						capi.World.BlockAccessor.SetBlock(block.Id, new BlockPos(asBlockPos.X + i, 160, asBlockPos.Z + j));
					}
				}
			}
			return TextCommandResult.Success("testnoise");
		}

		private TextCommandResult handleClear(TextCommandCallingArgs args)
		{
			sys.Clear();
			sys.SpawnedFish.Clear();
			return TextCommandResult.Success("cleared");
		}

		private TextCommandResult handleSpawn(TextCommandCallingArgs args)
		{
			string type = args[0] as string;
			SimTickExecQueue.Enqueue(delegate
			{
				EntityPos pos = capi.World.Player.Entity.Pos;
				ClimateCondition climateAt = capi.World.BlockAccessor.GetClimateAt(pos.AsBlockPos);
				float cohesion = (float)GameMath.Max(rand.NextDouble() * 1.1, 0.25);
				Vec3d vec3d = pos.XYZ.AddCopy(0f, 1.5f, 0f);
				for (int i = 0; i < 20; i++)
				{
					double num = pos.X + (rand.NextDouble() - 0.5) * 10.0;
					double num2 = pos.Z + (rand.NextDouble() - 0.5) * 10.0;
					double num3 = capi.World.BlockAccessor.GetRainMapHeightAt((int)num, (int)num2);
					if (type == "gh")
					{
						EntityParticleGrasshopper eparticle = new EntityParticleGrasshopper(capi, num, num3 + 1.0 + rand.NextDouble() * 0.25, num2);
						sys.SpawnParticle(eparticle);
					}
					if (type == "coq")
					{
						EntityParticleCoqui eparticle2 = new EntityParticleCoqui(capi, num, num3 + 1.0 + rand.NextDouble() * 0.25, num2);
						sys.SpawnParticle(eparticle2);
					}
					if (type == "ws")
					{
						Block blockRaw = capi.World.BlockAccessor.GetBlockRaw((int)num, (int)num3, (int)num2, 2);
						if (blockRaw.LiquidCode == "water" && blockRaw.PushVector == null)
						{
							EntityParticleWaterStrider eparticle3 = new EntityParticleWaterStrider(capi, num, num3 + (double)((float)blockRaw.LiquidLevel / 8f), num2);
							sys.SpawnParticle(eparticle3);
						}
					}
					if (type == "fis")
					{
						num = pos.X + (rand.NextDouble() - 0.5) * 2.0;
						num2 = pos.Z + (rand.NextDouble() - 0.5) * 2.0;
						Block blockRaw2 = capi.World.BlockAccessor.GetBlockRaw((int)num, (int)num3, (int)num2, 2);
						if (blockRaw2.LiquidCode == "saltwater" && blockRaw2.PushVector == null)
						{
							EntityParticleFish eparticle4 = new EntityParticleFish(capi, num, num3 - (double)blockRaw2.LiquidLevel, num2, new Vec3f(0.4f), 0, 0.3f);
							sys.SpawnParticle(eparticle4);
						}
					}
					if (type == "mg")
					{
						sys.SpawnParticle(new EntityParticleMatingGnats(capi, cohesion, vec3d.X, vec3d.Y, vec3d.Z));
					}
					if (type == "cic")
					{
						spawnCicadas(pos, climateAt);
					}
				}
			});
			return TextCommandResult.Success(type + " spawned.");
		}

		private void Sys_OnSimTick(float dt)
		{
			accum += dt;
			while (SimTickExecQueue.Count > 0)
			{
				SimTickExecQueue.Dequeue()();
			}
			if (!(accum > 0.5f))
			{
				return;
			}
			accum = 0f;
			EntityPos pos = capi.World.Player.Entity.Pos;
			if (pos.Dimension == 0)
			{
				ClimateCondition climateAt = capi.World.BlockAccessor.GetClimateAt(pos.AsBlockPos);
				if (!disabledInsects.Contains("grasshopper"))
				{
					spawnGrasshoppers(pos, climateAt);
				}
				if (!disabledInsects.Contains("cicada"))
				{
					spawnCicadas(pos, climateAt);
				}
				if (!disabledInsects.Contains("gnats"))
				{
					spawnMatingGnatsSwarm(pos, climateAt);
				}
				if (!disabledInsects.Contains("coqui"))
				{
					spawnCoquis(pos, climateAt);
				}
				if (!disabledInsects.Contains("waterstrider"))
				{
					spawnWaterStriders(pos, climateAt);
				}
				spawnFish(pos, climateAt);
			}
		}

		private void spawnWaterStriders(EntityPos pos, ClimateCondition climate)
		{
			if (climate.Temperature > 35f || climate.Temperature < 19f || climate.Rainfall > 0.1f || (double)climate.WorldgenRainfall < 0.5 || waterstriderNoise.Noise(pos.X, pos.Z) < 0.5 || sys.Count["waterStrider"] > 50)
			{
				return;
			}
			for (int i = 0; i < 100; i++)
			{
				double num = pos.X + (rand.NextDouble() - 0.5) * 60.0;
				double num2 = pos.Z + (rand.NextDouble() - 0.5) * 60.0;
				double num3 = capi.World.BlockAccessor.GetRainMapHeightAt((int)num, (int)num2);
				if (!(pos.HorDistanceTo(num, num2) < 3.0))
				{
					Block blockRaw = capi.World.BlockAccessor.GetBlockRaw((int)num, (int)num3, (int)num2, 2);
					Block blockRaw2 = capi.World.BlockAccessor.GetBlockRaw((int)num, (int)num3 - 1, (int)num2);
					Block blockRaw3 = capi.World.BlockAccessor.GetBlockRaw((int)num, (int)num3 + 1, (int)num2);
					if (blockRaw.LiquidCode == "water" && blockRaw.PushVector == null && blockRaw2.Replaceable < 6000 && blockRaw3.Id == 0)
					{
						EntityParticleWaterStrider eparticle = new EntityParticleWaterStrider(capi, num, num3 + (double)((float)blockRaw.LiquidLevel / 8f), num2);
						sys.SpawnParticle(eparticle);
					}
				}
			}
		}

		private void spawnFish(EntityPos pos, ClimateCondition climate)
		{
			if (climate.Temperature > 40f || climate.Temperature < 0f)
			{
				return;
			}
			BlockPos blockPos = new BlockPos(0);
			if (sys.Count["fish"] > 500)
			{
				return;
			}
			for (int i = 0; i < 100; i++)
			{
				int num = (int)(pos.X + (rand.NextDouble() - 0.5) * 60.0);
				int num2 = (int)(pos.Z + (rand.NextDouble() - 0.5) * 60.0);
				blockPos.Set(num, 0, num2);
				int terrainMapheightAt = capi.World.BlockAccessor.GetTerrainMapheightAt(blockPos);
				blockPos.Y = Math.Min(capi.World.SeaLevel - 1, terrainMapheightAt + 2);
				if (blockPos.HorDistanceSqTo(pos.X, pos.Z) < 16f)
				{
					continue;
				}
				FastVec3i fastVec3i = new FastVec3i(blockPos.X, blockPos.Y, blockPos.Z);
				if (sys.SpawnedFish.Contains(fastVec3i) || GameMath.MurmurHash3Mod(blockPos.X, blockPos.Y, blockPos.Z, 100) < 80)
				{
					continue;
				}
				Block block = capi.World.BlockAccessor.GetBlock(blockPos, 2);
				Block block2 = capi.World.BlockAccessor.GetBlock(blockPos.DownCopy());
				if (!(block.LiquidCode != "saltwater") && block2.Code.Path.StartsWithFast("coral"))
				{
					sys.SpawnedFish.Add(fastVec3i);
					int num3 = 5 + rand.Next(15);
					EntityParticleFish[] array = new EntityParticleFish[num3];
					Vec3f vec3f = new Vec3f(0.55f + (float)rand.NextDouble() * 0.65f, 0.3f, 0.3f);
					vec3f.Mul(1f + (float)rand.NextDouble() * 0.5f);
					float maxspeed = 0.15f + (float)rand.NextDouble() * 0.2f;
					int colorindex = rand.Next(EntityParticleFish.Colors.Length);
					for (int j = 0; j < num3; j++)
					{
						double num4 = rand.NextDouble() - 0.5;
						double num5 = rand.NextDouble() - 0.5;
						EntityParticleFish entityParticleFish = new EntityParticleFish(capi, (double)num + num4, blockPos.Y, (double)num2 + num5, vec3f, colorindex, maxspeed);
						entityParticleFish.StartPos = fastVec3i;
						array[j] = entityParticleFish;
						sys.SpawnParticle(entityParticleFish);
					}
					for (int k = 0; k < num3; k++)
					{
						array[k].FriendFishes = new EntityParticleFish[4]
						{
							array[GameMath.Mod(k - 2, num3)],
							array[GameMath.Mod(k - 1, num3)],
							array[GameMath.Mod(k + 1, num3)],
							array[GameMath.Mod(k + 2, num3)]
						};
					}
				}
			}
		}

