								float precipitation = modSystem.GetPrecipitation(pos.X + (double)((float)l * num4) - (double)num6, pos.Y, pos.Z + (double)((float)m * num4) - (double)num6, num5);
								int num8 = (int)GameMath.Clamp(255f * precipitation, 0f, 254f);
