		public override void Dispose()
		{
			if (loadedMapData != null)
			{
				foreach (MultiChunkMapComponent value in loadedMapData.Values)
				{
					value?.ActuallyDispose();
				}
			}
			MultiChunkMapComponent.DisposeStatic();
			base.Dispose();
		}

